            radial-gradient(circle at 85% 30%, rgba(212, 175, 55, 0.08), transparent 25%);
        color: var(--text-color);
        font-family: 'Quicksand', sans-serif;
        display: flex;
        justify-content: center;
        align-items: center;
        width: 100%;
        height: 100vh;
        position: relative;
    }

    #background-particles {
        position: absolute;
        top: 0;
        left: 0;
        width: 100%;
        height: 100%;
        z-index: 0;
        pointer-events: none;
    }

    .particle {
        position: absolute;
        background-color: var(--accent-blue);
        border-radius: 50%;
        opacity: 0;
        animation: rise 25s infinite linear;
        box-shadow: 0 0 8px var(--accent-blue-glow);
    }

    @keyframes rise {
        0% { transform: translateY(100vh) scale(0.4); opacity: 0; }
        10% { opacity: 0.5; }
        90% { opacity: 0.2; }
        100% { transform: translateY(-10vh) scale(1.3); opacity: 0; }
    }

    .screen {
        position: absolute;
        width: 90%;
        max-width: 800px;
        background: rgba(10, 15, 25, 0.75);
        border: 2px solid var(--border-color);
        box-shadow: 0 0 20px rgba(74, 144, 226, 0.3), inset 0 0 25px rgba(0, 0, 0, 0.8);
        border-radius: 10px;
        backdrop-filter: blur(8px);
        -webkit-backdrop-filter: blur(8px);
        transition: opacity 1s, transform 1s, visibility 1s;
        display: flex;
        flex-direction: column;
        align-items: center;
        padding: 20px;
        z-index: 10;
        visibility: hidden;
        opacity: 0;
        transform: scale(0.95);
    }

    .screen.active {
        visibility: visible;
        opacity: 1;
        transform: scale(1);
    }

    #start-screen {
        justify-content: center;
    }

    .title {
        font-family: 'Arizonia', cursive;
        font-size: 3.5em;
        color: var(--accent-blue);
        text-shadow: 0 0 8px var(--accent-blue-glow), 0 0 15px #000;
        margin-bottom: 20px;
        letter-spacing: 4px;
        animation: glow 3.5s infinite alternate;
    }

    .warning-text {
        font-style: normal;
        font-size: 1.1em;
        margin-bottom: 40px;
        color: #a0b0c0;
        max-width: 80%;
        line-height: 1.8;
        text-align: center;
        font-family: 'Quicksand', sans-serif;
    }

    .start-button-container {
        text-align: center;
    }

    .start-button {
        --size: 100px;
        width: var(--size);
        height: var(--size);
        background-color: var(--primary-color);
        border: 3px solid var(--accent-blue);
        border-radius: 50%;
        display: inline-flex;
        justify-content: center;
        align-items: center;
        cursor: pointer;
        position: relative;
        transition: all 0.3s ease;
        box-shadow: 0 0 20px var(--accent-blue-glow);
        animation: pulse 2.5s infinite;
        margin-bottom: 40px;
    }

    .start-button:hover { transform: scale(1.1); box-shadow: 0 0 35px var(--accent-blue-glow); }

    .start-button-text {
        font-family: 'Arizonia', cursive;
        font-size: 1.6em;
        color: var(--gold-color);
        text-shadow: 0 0 8px var(--gold-color), 0 0 20px rgba(212,175,55,0.4);
        transition: all 0.3s ease;
        letter-spacing: 2px;
    }

    #mode-selection {
        opacity: 0;
        transition: opacity 0.5s ease-in-out;
        pointer-events: none;
        text-align: center;
    }

    #mode-selection.visible {
        opacity: 1;
        pointer-events: auto;
    }


    #character-creation-screen {
        max-height: 90vh;
        overflow-y: auto;
    }

    .form-title {
        font-family: 'Arizonia', cursive;
        font-size: 2.2em;
        color: var(--gold-color);
        margin-bottom: 20px;
        border-bottom: 1px solid var(--border-color);
        padding-bottom: 10px;
    }

    .presets-container {
        margin-bottom: 20px;
        width: 100%;
        display: flex;
        flex-direction: column;
        align-items: center;
    }

    .presets-container h3 {
        font-size: 1.3em;
        color: #ccc;
        text-align: center;
        margin-bottom: 15px;
        font-family: 'Quicksand', sans-serif;
    }

    .preset-selection {
        display: flex;
        justify-content: center;
        flex-wrap: wrap;
        gap: 15px;
    }

    .preset-btn {
        background: var(--input-bg);
        border: 1px solid var(--input-border);
        color: var(--text-color);
        padding: 8px 15px;
        font-family: 'Quicksand', sans-serif;
        cursor: pointer;
        transition: all 0.3s ease;
        border-radius: 4px;
        position: relative;
    }

    .preset-btn:hover, .preset-btn.selected {
        background: var(--accent-blue);
        border-color: var(--accent-blue-glow);
        color: #fff;
        box-shadow: 0 0 10px rgba(74, 144, 226, 0.5);
    }

    /* True Fortune Style */
    .preset-btn.true-fortune {
        background: linear-gradient(135deg, #2c3e50 0%, #D4AF37 100%);
        border: 1px solid #D4AF37;
        color: #fff;
        text-shadow: 0 0 5px #000;
        box-shadow: 0 0 15px rgba(212, 175, 55, 0.5);
    }

    /* Hard Mode Button Style */
    #hard-mode-btn {
        border-color: var(--accent-red);
        color: #ffcccc;
    }
    #hard-mode-btn:hover, #hard-mode-btn.selected {
        background: var(--accent-red);
        border-color: var(--accent-red-glow);
        box-shadow: 0 0 15px rgba(231, 76, 60, 0.6);
    }

    /* Ero Fortune Style */
    .preset-btn.ero-fortune {
        background: linear-gradient(135deg, #2c001e 0%, #8b0046 100%);
        border: 1px solid #ff69b4;
        color: #fff;
        text-shadow: 0 0 5px #ff1493;
        box-shadow: 0 0 15px rgba(255, 105, 180, 0.5);
    }
    .preset-btn.ero-fortune:hover, .preset-btn.ero-fortune.selected {
        background: #ff1493;
        border-color: #ffc0cb;
        box-shadow: 0 0 20px rgba(255, 20, 147, 0.8);
    }


    .draw-fortune-btn {
        padding: 10px 20px;
        font-size: 1.1em;
        font-family: 'Quicksand', sans-serif;
        display: block;
        margin: 0 auto;
        width: fit-content;
    }

    #fortune-name-display {
        color: var(--gold-color);
        margin-left: 10px;
        font-family: 'Quicksand', sans-serif;
        font-size: 1.1em;
    }

    .character-form {
        display: grid;
        grid-template-columns: 1fr;
        gap: 15px;
        width: 100%;
        margin-bottom: 30px;
    }

    .form-group {
        display: flex;
        flex-direction: column;
        text-align: left;
    }

    .form-group label {
        margin-bottom: 5px;
        font-weight: bold;
        color: var(--gold-color);
    }

    .form-group input, .form-group select, .form-group textarea {
        background: var(--input-bg);
        border: 1px solid var(--input-border);
        color: var(--text-color);
        padding: 10px;
        border-radius: 4px;
        font-family: 'Quicksand', sans-serif;
        font-size: 1em;
        width: 100%;
        box-sizing: border-box;
    }

    .form-group input:focus, .form-group select:focus, .form-group textarea:focus {
        outline: none;
        border-color: var(--input-focus-border);
        box-shadow: 0 0 8px rgba(212, 175, 55, 0.5);
    }

    .form-group textarea {
        min-height: 60px; /* Adjusted height */
        resize: vertical;
    }

    .divider-title {
        font-family: 'Quicksand', sans-serif;
        font-size: 1.5em;
        color: var(--gold-color);
        margin-top: 25px;
        margin-bottom: 15px;
        width: 100%;
        text-align: center;
        border-top: 1px solid var(--border-color);
        padding-top: 20px;
    }

    .final-start-button {
        background: var(--accent-blue);
        border: 1px solid var(--accent-blue-glow);
        color: #fff;
        padding: 12px 25px;
        font-family: 'Arizonia', cursive;
        font-size: 2em;
        letter-spacing: 3px;
        cursor: pointer;
        transition: all 0.3s ease;
        border-radius: 5px;
        box-shadow: 0 0 15px rgba(74, 144, 226, 0.7);
    }

    .final-start-button:hover {
        background: var(--accent-blue-glow);
        color: var(--primary-color);
        transform: scale(1.05);
    }

    /* Gacha Display for Spirit Root */
    .gacha-display {
        background: rgba(0, 0, 0, 0.3);
        border: 1px dashed var(--accent-blue);
        padding: 10px;
        margin-top: 5px;
        border-radius: 4px;
        text-align: center;
        font-family: 'Quicksand', sans-serif;
        font-size: 1.2em;
        color: var(--accent-blue-glow);
        min-height: 40px;
        display: flex;
        justify-content: center;
        align-items: center;
    }

    .gacha-display.heaven { color: #ffd700; text-shadow: 0 0 10px #ffd700; border-color: #ffd700; }
    .gacha-display.earth { color: #c0392b; text-shadow: 0 0 8px #c0392b; }
    .gacha-display.profound { color: #9b59b6; }
    .gacha-display.yellow { color: #2ecc71; }
    .gacha-display.waste { color: #7f8c8d; }

    /* Cheat Toggle Style */
    .cheat-toggle-container {
        display: flex;
        align-items: center;
        justify-content: center;
        margin-bottom: 15px;
        width: 100%;
        gap: 20px;
    }

    .cheat-toggle-label {
        color: var(--accent-red);
        margin-right: 10px;
        font-weight: bold;
        font-family: 'Arizonia', cursive;
        font-size: 1em;
    }

    /* Ero Toggle Label */
    .ero-toggle-label {
        color: var(--accent-pink);
        margin-right: 10px;
        font-weight: bold;
        font-family: 'Arizonia', cursive;
        font-size: 1.1em;
        text-shadow: 0 0 5px rgba(255, 105, 180, 0.5);
    }

    .switch {
        position: relative;
        display: inline-block;
        width: 50px;
        height: 24px;
    }

    .switch input {
        opacity: 0;
        width: 0;
        height: 0;
    }

    .slider {
        position: absolute;
        cursor: pointer;
        top: 0;
        left: 0;
        right: 0;
        bottom: 0;
        background-color: #ccc;
        -webkit-transition: .4s;
        transition: .4s;
        border-radius: 24px;
    }

    .slider:before {
        position: absolute;
        content: "";
        height: 16px;
        width: 16px;
        left: 4px;
        bottom: 4px;
        background-color: white;
        -webkit-transition: .4s;
        transition: .4s;
        border-radius: 50%;
    }

    /* Red Slider (Cheat) */
    .cheat-switch input:checked + .slider {
        background-color: var(--accent-red);
    }
    .cheat-switch input:focus + .slider {
        box-shadow: 0 0 1px var(--accent-red);
    }

    /* Pink Slider (Ero) */
    .ero-switch input:checked + .slider {
        background-color: var(--accent-pink);
    }
    .ero-switch input:focus + .slider {
        box-shadow: 0 0 1px var(--accent-pink);
    }

    input:checked + .slider:before {
        -webkit-transform: translateX(26px);
        -ms-transform: translateX(26px);
        transform: translateX(26px);
    }

    ::-webkit-scrollbar { width: 8px; }
    ::-webkit-scrollbar-track { background: var(--scroll-bg); }
    ::-webkit-scrollbar-thumb { background: var(--scroll-thumb); border-radius: 4px; }
    ::-webkit-scrollbar-thumb:hover { background: var(--accent-blue-glow); }

    @keyframes glow {
        from { text-shadow: 0 0 8px var(--accent-blue-glow), 0 0 15px #000; }
        to { text-shadow: 0 0 15px var(--accent-blue-glow), 0 0 25px var(--accent-blue); }
    }

    @keyframes pulse {
        0% { transform: scale(0.95); box-shadow: 0 0 20px var(--accent-blue-glow); }
        70% { transform: scale(1); box-shadow: 0 0 30px var(--accent-blue-glow); }
        100% { transform: scale(0.95); box-shadow: 0 0 20px var(--accent-blue-glow); }
    }

    @media (max-width: 768px) {
        .title { font-size: 2.5em; }
        .warning-text { font-size: 1em; max-width: 95%; }
        .start-button { --size: 80px; }
        .start-button-text { font-size: 1.2em; }
        .character-form { grid-template-columns: 1fr; }
        .preset-selection { gap: 8px; }
        .preset-btn { padding: 6px 10px; font-size: 0.9em; }
        .cheat-toggle-container { flex-direction: column; gap: 10px; }
    }
</style>
</head>
<body>
    <!-- disable-default-loading -->
    <div id="background-particles"></div>
    <div class="screen active" id="start-screen">
        <h1 class="title">Đạo Uyên</h1>
        <div class="start-button-container">
            <p class="warning-text" id="initial-warning">“Đại đạo ba ngàn, thù đồ đồng quy. Nhưng thiên đạo vô tình, coi vạn vật như sài cẩu. Từ cổ chí kim, bao nhiêu tiên nhân lấy máu và xương tô vẽ nên con đường này — mỗi tấc tiến lên là một tấc sinh tử.”<br><br>“Thiên địa không nhân, vạn vật như cỏ rác. Quy tắc của đại đạo không có ngoại lệ — chỉ có mạnh và yếu, tồn tại và tiêu diệt. Linh căn, cơ duyên, thiên phú... tất cả chỉ là điểm khởi đầu. Ý chí và lựa chọn mới quyết định ngươi sẽ đứng ở đâu trên tiên đồ.”<br><br>“Ngươi, có muốn bước lên con đường đăng tiên này, đoạt lấy một tia sinh cơ cùng thiên địa hay không?”</p>
            <div class="start-button" id="start-button">
                <span class="start-button-text">Đồng ý</span>
            </div>
        </div>
        <div id="mode-selection">
            <p class="warning-text" style="margin-bottom: 20px;">Vui lòng chọn chế độ Tiên Đồ</p>
            <div class="preset-selection">
                <button class="preset-btn" id="simple-mode-btn" style="padding: 12px 25px; font-size: 1.2em;">Chế độ Dễ</button>
                <button class="preset-btn" id="normal-mode-btn" style="padding: 12px 25px; font-size: 1.2em;">Chế độ Thường</button>
                <button class="preset-btn" id="hard-mode-btn" style="padding: 12px 25px; font-size: 1.2em;">Chế độ Khó</button>
            </div>
        </div>
    </div>

    <div class="screen" id="character-creation-screen">
        <h2 class="form-title">Trùng Tố Tiên Duyên</h2>

        <div class="character-form">
            <div class="form-group">
                <label for="char-name">Đạo hiệu</label>
                <input type="text" id="char-name" placeholder="Tên hoặc đạo hiệu của ngươi">
            </div>
            <div class="form-group">
                <label for="char-gender">Giới tính</label>
                <input type="text" id="char-gender" placeholder="Tùy chỉnh giới tính của ngươi">
            </div>
             <div class="form-group">
                <label for="char-race">Chủng tộc</label>
                <input type="text" id="char-race" placeholder="Nhân tộc / Yêu tộc / Tiên thiên sinh linh...">
            </div>
            <div class="form-group">
                <label for="char-age">Tuổi</label>
                <input type="number" id="char-age" placeholder="Tuổi của ngươi" min="0" value="0">
            </div>
            <div class="form-group">
                <label for="char-appearance">Dung mạo</label>
                <textarea id="char-appearance" placeholder="Mô tả tiên tư ngọc sắc của ngươi"></textarea>
            </div>
            <div class="form-group">
                <label for="char-realm">Đại cảnh giới</label>
                <input type="text" id="char-realm" placeholder="Tùy chỉnh, vd: Luyện Khí / Trúc Cơ / Kim Đan...">
                <select id="char-realm-select" style="display:none;">
                    <option value="Chưa tu luyện">Chưa tu luyện</option>
                    <option value="Luyện Khí">Luyện Khí</option>
                    <option value="Trúc Cơ">Trúc Cơ</option>
                    <option value="Kim Đan">Kim Đan</option>
                    <option value="Nguyên Anh">Nguyên Anh</option>
                    <option value="Hóa Thần">Hóa Thần</option>
                    <option value="Luyện Hư">Luyện Hư</option>
                    <option value="Hợp Thể">Hợp Thể</option>
                    <option value="Đại Thừa">Đại Thừa</option>
                    <option value="Độ Kiếp">Độ Kiếp</option>
                </select>
            </div>
            <div class="form-group">
                <label for="char-realm-minor">Tiểu cảnh giới</label>
                <input type="text" id="char-realm-minor" placeholder="Vd: Sơ kỳ / Trung kỳ / Hậu kỳ / Tầng ba">
            </div>

            <div class="form-group">
                <label for="char-spirit-root">Linh căn</label>
                <textarea id="char-spirit-root" placeholder="Thiên phú căn cốt của ngươi, ví dụ: Thiên phẩm linh căn"></textarea>
                <div id="hard-mode-spirit-root-section" style="display:none;">
                    <div id="spirit-root-result" class="gacha-display">Chưa thức tỉnh...</div>
                    <button id="roll-spirit-root-btn" class="preset-btn" style="width: 100%; margin-top: 5px;">Thức tỉnh linh căn</button>
                </div>
            </div>
            <div class="form-group">
                <label for="char-physique">Thể chất</label>
                <input type="text" id="char-physique" placeholder="Thể chất đặc thù, vd: Phàm Nhân / Hoang Cổ Thánh Thể...">
            </div>

            <div class="form-group">
                <div style="display:flex;align-items:center;gap:8px;margin-bottom:6px;">
                    <label for="char-technique-main" style="margin:0;">Ch&#7911; Tu C&#244;ng Ph&#225;p</label>
                    <button type="button" onclick="document.getElementById('help-chu-tu').style.display='flex'" style="width:20px;height:20px;border-radius:50%;border:1px solid var(--gold-color);background:transparent;color:var(--gold-color);font-size:0.75em;cursor:pointer;padding:0;display:inline-flex;align-items:center;justify-content:center;flex-shrink:0;">?</button>
                </div>
                <textarea id="char-technique-main" placeholder="T&#7889;i &#273;a 1 c&#244;ng ph&#225;p Ch&#7911; Tu. &#272;&#226;y l&#224; c&#244;ng ph&#225;p c&#7889;t l&#245;i quy&#7871;t &#273;&#7883;nh &#273;&#432;&#7901;ng tu luy&#7879;n ch&#237;nh c&#7911;a ng&#432;&#417;i.&#10;V&#237; d&#7909;: H&#7895;n &#272;&#7897;n Ki&#7871;m Kinh"></textarea>
            </div>
            <div class="form-group">
                <div style="display:flex;align-items:center;gap:8px;margin-bottom:6px;">
                    <label for="char-technique-sub" style="margin:0;">Ph&#7909; Tu C&#244;ng Ph&#225;p</label>
                    <button type="button" onclick="document.getElementById('help-phu-tu').style.display='flex'" style="width:20px;height:20px;border-radius:50%;border:1px solid #4a90e2;background:transparent;color:#4a90e2;font-size:0.75em;cursor:pointer;padding:0;display:inline-flex;align-items:center;justify-content:center;flex-shrink:0;">?</button>
                </div>
                <textarea id="char-technique-sub" placeholder="C&#243; th&#7875; nhi&#7873;u c&#244;ng ph&#225;p Ph&#7909; Tu. M&#7895;i d&#242;ng m&#7897;t t&#234;n.&#10;V&#237; d&#7909;: Th&#7845;t Th&#432;&#417;ng Quy&#7873;n&#10;C&#7917;u &#194;m Ch&#226;n Kinh"></textarea>
            </div>
            <div class="form-group">
                <label for="char-divine-arts">Thần thông</label>
                <textarea id="char-divine-arts" placeholder="Thần thông đã luyện, mỗi dòng một thần thông"></textarea>
            </div>
            <div class="form-group">
                <label for="char-magic-arts">Pháp thuật</label>
                <textarea id="char-magic-arts" placeholder="Pháp thuật hỗ trợ, mỗi dòng một loại"></textarea>
            </div>

            <div class="presets-container" style="margin-top:15px;">
                <h3 style="font-size: 1.3em; color: #ccc; text-align: center; margin-bottom: 15px;">Gacha Thiên Phú</h3>
                <div id="cheat-toggle-section" class="cheat-toggle-container" style="display:none;">
                    <div style="display:flex; align-items:center;">
                        <span class="cheat-toggle-label">Nghịch Thiên Cải Mệnh (Gian lận)</span>
                        <label class="switch cheat-switch">
                            <input type="checkbox" id="cheat-toggle-checkbox">
                            <span class="slider"></span>
                        </label>
                    </div>
                    <div style="display:flex; align-items:center;">
                        <span class="ero-toggle-label">Hợp Hoan Bí Tân (Thận trọng)</span>
                        <label class="switch ero-switch">
                            <input type="checkbox" id="ero-toggle-checkbox">
                            <span class="slider"></span>
                        </label>
                    </div>
                </div>

                <button id="draw-fortune-btn" class="preset-btn draw-fortune-btn">Thiên Cơ Diễn Toán, Rút Thiên Phú</button>
                <div id="fortune-selection-container" class="preset-selection" style="margin-top: 15px; display: none;">
                </div>
            </div>

            <div class="form-group">
                <label>(Thiên Phú đã chọn)</label>
                <div id="fortune-pills-container" style="display:flex;flex-wrap:wrap;gap:8px;min-height:44px;padding:8px;background:var(--input-bg);border:1px solid var(--input-border);border-radius:4px;">
                    <span style="color:var(--text-muted);font-size:0.85em;align-self:center;" id="fortune-pills-placeholder">Chưa chọn thiên phú nào...</span>
                </div>
                <span id="fortune-name-display" style="display:none"></span>
                <input type="text" id="char-fortune" style="display:none" readonly>
            </div>

            <div id="custom-fortune-section">
                <h3 class="divider-title" style="border:none; margin-top: 10px; margin-bottom: 5px;">Tùy chỉnh Thiên Phú của ngươi</h3>
                <div id="custom-fortunes-list"></div>
                <button id="add-custom-fortune-btn" class="preset-btn" style="width:100%;margin-top:8px;padding:10px;display:flex;align-items:center;justify-content:center;gap:6px;"><span style="font-size:1.3em;">＋</span> Thêm Thiên Phú tùy chỉnh</button>
                <input type="hidden" id="custom-fortune-name">
                <textarea id="custom-fortune-desc" style="display:none"></textarea>
            </div>

            <div id="companion-section">
                <div onclick="(function(){var b=document.getElementById('companion-body');var a=document.getElementById('companion-arrow');var open=b.style.display!=='none';b.style.display=open?'none':'block';a.textContent=open?'&#9654;':'&#9660';})()" style="display:flex;align-items:center;justify-content:space-between;cursor:pointer;padding:10px 14px;background:rgba(212,175,55,0.06);border:1px solid rgba(212,175,55,0.25);border-radius:6px;margin-bottom:0;user-select:none;">
                    <span style="font-family:'Quicksand',sans-serif;font-size:1.1em;color:var(--gold-color);font-weight:600;">&#10022; Thiên Định Đạo Lữ <span style="font-size:0.8em;opacity:0.7;">(tùy chọn)</span></span>
                    <span id="companion-arrow" style="color:var(--gold-color);font-size:0.9em;">&#9654;</span>
                </div>
                <div id="companion-body" style="display:none;">
                <div class="form-group">
                    <label for="companion-name">Tên đạo lữ</label>
                    <input type="text" id="companion-name" placeholder="Tên của đạo lữ">
                </div>
                <div class="form-group">
                    <label for="companion-species">Chủng tộc</label>
                    <input type="text" id="companion-species" placeholder="Nhân / Yêu / Ma / Tiên...">
                </div>
                <div class="form-group">
                    <label for="companion-realm">Cảnh giới</label>
                    <input type="text" id="companion-realm" placeholder="Luyện Khí / Trúc Cơ / Kim Đan...">
                </div>
                <div class="form-group">
                    <label for="companion-identity">Thân phận / Vai trò</label>
                    <input type="text" id="companion-identity" placeholder="Vd: Sư muội, Hầu nữ, Tông chủ...">
                </div>
                <div class="form-group">
                    <label for="companion-personality">Tính cách</label>
                    <input type="text" id="companion-personality" placeholder="Tính cách của y/nàng">
                </div>
                <div class="form-group">
                    <label for="companion-appearance">Ngoại hình</label>
                    <textarea id="companion-appearance" placeholder="Mô tả ngoại hình, dung mạo của y/nàng"></textarea>
                </div>
                <div class="form-group">
                    <label for="companion-relation">Quan hệ với ngươi</label>
                    <textarea id="companion-relation" placeholder="Mối quan hệ, câu chuyện giữa hai người"></textarea>
                </div>
                <div class="form-group">
                    <label for="companion-ability">Năng lực</label>
                    <textarea id="companion-ability" placeholder="Công pháp, thần thông, năng lực đặc biệt"></textarea>
                </div>
                </div><!-- /companion-body -->
            </div>
        </div>

        <div class="character-form" style="margin-top:10px;">
            <div class="form-group">
                <label for="char-sect">Tông môn hiện tại</label>
                <input type="text" id="char-sect" placeholder="Tên tông môn, vd: Thanh Vân Tông / Chưa gia nhập">
            </div>
            <div class="form-group">
                <label for="char-spirit-stones">Linh thạch khởi đầu</label>
                <input type="number" id="char-spirit-stones" placeholder="Số linh thạch ban đầu" min="0" value="50">
            </div>
            <div class="form-group">
                <label for="char-world-realm">Đại giới</label>
                <select id="char-world-realm">
                    <option value="Huyền Thiên Giới">Huyền Thiên Giới</option>
                    <option value="Tiên Giới">Tiên Giới</option>
                </select>
            </div>
            <div class="form-group" style="grid-column:1/-1">
                <label for="char-context" style="color:var(--gold-color);font-size:1.1em;">Bối cảnh khởi đầu</label>
                <textarea id="char-context" style="min-height:120px;" placeholder="Mô tả tình huống, địa điểm, sự kiện khởi đầu câu chuyện..."></textarea>
            </div>
        </div>

        <button class="final-start-button" id="confirm-creation-button">Mở ra Tiên Đồ</button>
    </div>

    <script>
        // Lấy toastr từ parent window (SillyTavern)
        const toastr = window.parent.toastr || {
            success: (m) => console.log('[OK]', m),
            error:   (m) => console.error('[ERR]', m),
            warning: (m) => console.warn('[WARN]', m),
            info:    (m) => console.info('[INFO]', m)
        };

        document.addEventListener('DOMContentLoaded', () => {
            const startScreen = document.getElementById('start-screen');
            const creationScreen = document.getElementById('character-creation-screen');
            const startButton = document.getElementById('start-button');
            const initialWarning = document.getElementById('initial-warning');
            const modeSelection = document.getElementById('mode-selection');
            const simpleModeBtn = document.getElementById('simple-mode-btn');
            const normalModeBtn = document.getElementById('normal-mode-btn');
            const hardModeBtn = document.getElementById('hard-mode-btn');

            const confirmButton = document.getElementById('confirm-creation-button');
            const drawFortuneBtn = document.getElementById('draw-fortune-btn');
            const cheatToggleSection = document.getElementById('cheat-toggle-section');
            const cheatToggle = document.getElementById('cheat-toggle-checkbox');
            const eroToggle = document.getElementById('ero-toggle-checkbox');

            const nameInput = document.getElementById('char-name');
            const genderInput = document.getElementById('char-gender');
            const raceInput = document.getElementById('char-race');
            const appearanceInput = document.getElementById('char-appearance');
            const realmInput = document.getElementById('char-realm');
            const realmSelect = document.getElementById('char-realm-select');
            const identityInput = document.getElementById('char-identity');
            const spiritRootTextarea = document.getElementById('char-spirit-root');
            const techniqueTextarea = document.getElementById('char-technique');

            const hardModeSpiritRootSection = document.getElementById('hard-mode-spirit-root-section');
            const spiritRootResult = document.getElementById('spirit-root-result');
            const rollSpiritRootBtn = document.getElementById('roll-spirit-root-btn');
            let currentMode = 'normal';
            let spiritRootRollsLeft = 3;
            let fortuneRollsLeft = 3;
            let hardModeSpiritRootValue = "";
            let _gachaFortunes = []; // [{name, desc, type}] - lưu thiên phú từ gacha

            const fortuneSelectionContainer = document.getElementById('fortune-selection-container');
            const fortuneNameDisplay = document.getElementById('fortune-name-display');
            const fortuneInput = document.getElementById('char-fortune');
            const customFortuneNameInput = document.getElementById('custom-fortune-name');
            const customFortuneDescTextarea = document.getElementById('custom-fortune-desc');

            const companionNameInput = document.getElementById('companion-name');
            const companionGenderInput = document.getElementById('companion-gender');
            const companionAppearanceInput = document.getElementById('companion-appearance');
            const companionClothingInput = document.getElementById('companion-clothing');
            const companionRaceInput = document.getElementById('companion-race');
            const companionClassInput = document.getElementById('companion-class');
            const companionPersonalityInput = document.getElementById('companion-personality');
            const companionAgeInput = document.getElementById('companion-age');
            const companionAbilitiesTextarea = document.getElementById('companion-abilities');
            const companionBackstoryTextarea = document.getElementById('companion-backstory');

            const customFortuneSection = document.getElementById('custom-fortune-section');
            const companionSection = document.getElementById('companion-section');

            const trueFortunePresets = [
                { name: "Chân · Thiên Mệnh Phản Phái", desc: "Túc mệnh tương khắc, chuyên cướp đoạt cơ duyên của Thiên Mệnh Chi Tử, trời sinh đối địch với Thiên Mệnh Chi Tử, cản trở đạo đồ của hắn!" },
                { name: "Chân · Thiên Mệnh Đại Phản Phái", desc: "Tâm ngoan thủ lạt, vì đạt mục đích không từ thủ đoạn. Mặc dù dễ rước lấy chính đạo vây quét, nhưng hiệu suất cướp đoạt cơ duyên gấp mười lần người thường, hơn nữa có thể áp chế Khí Vận Chi Tử." },
                { name: "Chân · Thi Đạo Tông Sư", desc: "Trời sinh có độ thân hòa tự nhiên với thi khí, thi khôi luyện chế ra có chiến lực vượt xa đồng giai, thậm chí có thể giữ lại thần thông khi còn sống." },
                { name: "Chân · Bất Hóa Cốt", desc: "Nhục thân cứng rắn như cương thi, không già không chết, không vào luân hồi, thoát ngoài tam giới, không trong ngũ hành." },
                { name: "Chân · Hoàng Tuyền Dẫn Lộ Nhân", desc: "Có thể mở ra quỷ môn quan, triệu hoán âm binh trợ trận, khi luyện thi có tỷ lệ thu hút tàn hồn cường đại bơi lội xung quanh nhập vào." },
                { name: "Chân · Hệ Thống Đăng Nhập Mỗi Ngày", desc: "Mỗi ngày tỉnh dậy đăng nhập một cái, thần binh công pháp, linh đan diệu dược ngẫu nhiên đưa tới, sinh hoạt tu tiên vui vẻ vô biên." },
                { name: "Chân · Thâm Lam Gia Điểm", desc: "'Thâm Lam, cho ta xem giới hạn của ngươi!' Chỉ cần có đủ điểm năng lượng, bất kỳ công pháp nào cũng chớp mắt đạt tới đại viên mãn." },
                { name: "Chân · Nhân Sinh Mô Nghĩ Khí", desc: "Tiêu hao linh thạch mô phỏng nhân sinh tương lai, dự đoán cát hung họa phúc, sau khi tử vong có thể bảo lưu tu vi hoặc ký ức, cẩu đạo chí tôn." },
                { name: "Chân · Thụ Đồ Vạn Bội Phản Hoàn", desc: "Ban thưởng cơ duyên cho đồ đệ, có tỷ lệ cao nhất kích hoạt bạo kích phản hoàn gấp vạn lần, đồ đệ càng mạnh, sư phụ càng biến thái." },
                { name: "Chân · Thần Cấp Lựa Chọn Hệ Thống", desc: "Kích hoạt tuyển hạng khi đối mặt với ngã rẽ, mặc dù nội dung tuyển hạng thường cực kỳ thái quá, nhưng phần thưởng phong phú đến mức không thể từ chối." },
                { name: "Chân · Tối Cường Phản Sáo Lộ", desc: "Chỉ cần khiến người khác khiếp sợ, cạn lời hoặc phẫn nộ là có thể nhận được điểm trang bức, đổi lấy vạn vật trong thương thành." },
                { name: "Chân · Công Pháp Giản Hóa Hệ Thống", desc: "Tất cả công pháp tự động giản hóa, hít thở cũng là tu luyện, ngủ cũng có thể biến cường, sờ cá mới là chân lý của đại đạo." },
                { name: "Chân · Chư Thiên Liêu Thiên Quần", desc: "Gia nhập nhóm chat vượt không gian, chém gió thổi nước với các đại lão như Hoang Thiên Đế, Diệp Thiên Đế, thỉnh thoảng giật được một cái lì xì chính là nghịch thiên tạo hóa." },
                { name: "Chân · Treo Máy Tu Tiên", desc: "Cơ thể tự động ủy thác tu luyện, chẳng những hiệu suất gấp trăm lần người thường, mà bất luận đang chiến đấu hay đi xí đều đang biến cường." },
                { name: "Chân · Thôn Phệ Tiến Hóa", desc: "Bắt đầu chỉ với một cái miệng, năng lực toàn dựa vào ăn. Nuốt chửng vạn vật lấy tinh hoa của nó, vô luận là pháp bảo hay thiên kiếp, đều là thức ăn." },
                { name: "Chân · Trường Sinh Từ Khúc", desc: "Cứ sống sót qua một năm, liền có thể làm mới hoặc thăng cấp một từ khóa nội tại, chỉ cần sống đủ lâu, phế sài cũng có thể mài chết Tiên Đế." },
                { name: "Chân · Trực Tiếp Tu Tiên", desc: "Phát trực tiếp quá trình tu tiên cho khán giả Trái Đất, donate và độ nổi tiếng của khán giả có thể chuyển hóa thành tu vi và khí vận." },
                { name: "Chân · Gia Tộc Tu Tiên", desc: "Không chỉ tự mình biến cường, mà thông qua việc thăng cấp độ gia tộc còn nhận được BUFF toàn tộc, một người đắc đạo gà chó lên trời." },
                { name: "Chân · Nạp Kim Thành Tiên", desc: "Chỉ cần có linh thạch, cảnh giới mua thẳng! Thiên kiếp cũng có thể dùng tiền giải quyết, có tiền thật sự có thể muốn làm gì thì làm." },
                { name: "Chân · Cuồng Ma Nhiệm Vụ", desc: "Trong tầm nhìn hiện đầy dấu chấm hỏi trên đầu NPC, hoàn thành các loại nhiệm vụ kỳ quái để nhận kinh nghiệm, thăng cấp như uống nước." },
                { name: "Chân · Chí Tôn Cốt", desc: "Trời sinh trước ngực có Chí Tôn Cốt, khắc ghi nguyên thủy bảo thuật, chẳng những chiến lực vô song, càng có tư thái của chí tôn, định sẵn độc đoán vạn cổ." },
                { name: "Chân · Trọng Đồng Giả", desc: "Trọng đồng vốn là con đường vô địch, cớ sao phải mượn xương người khác. Một mắt sinh, một mắt diệt, nhìn thấu thế gian mọi thứ hư vọng." },
                { name: "Chân · Hỗn Độn Thể", desc: "Đệ nhất thể chất cổ kim, vạn pháp bất xâm, thân hòa vạn đạo, chưa thành tiên đã sở hữu sức mạnh trấn áp đương thế." },
                { name: "Chân · Hoang Cổ Thánh Thể", desc: "Nhục thân thành thánh, máu vàng sục sôi, chuyên trị mọi kẻ không phục. Sau khi đại thành, có thể thách thức Đại Đế, tay không đỡ Đế binh." },
                { name: "Chân · Tiên Thiên Đạo Thai", desc: "Trời sinh gần gũi với đạo, hòa hợp cùng đạo. Người khác khổ tu ngộ đạo, ngươi ăn cơm uống nước đều đang ngộ đạo, quả thực là con ruột của thiên đạo." },
                { name: "Chân · Thương Thiên Bá Thể", desc: "Bá đạo tuyệt luân, lấy chiến dưỡng chiến. Cỗ máy chiến đấu chảy xuôi tử huyết, túc mệnh chính là tranh phong cùng Thánh Thể." },
                { name: "Chân · Tiên Đế Chuyển Thế", desc: "Tồn tại chí cao vô thượng của cửu thiên thập địa trọng tu, tự mang bọc kinh nghiệm max cấp cùng vô thượng truyền thừa, đời này chỉ vì siêu thoát." },
                { name: "Chân · Bạn Sinh Đế Binh", desc: "Khi ra đời thiên giáng dị tượng, tay cầm Cực Đạo Đế Binh mà sinh, vạch xuất phát nằm ngay sau vạch đích của người khác." },
                { name: "Chân · Hồng Mông Tử Khí", desc: "Trong cơ thể ngưng tụ một vệt Hồng Mông Tử Khí làm nền tảng thành thánh, khí vận nghịch thiên, định sẵn thành thánh làm tổ." },
                { name: "Chân · Tam Túc Kim Ô", desc: "Thân mang Thái Dương Chân Hỏa, chưởng khống chí dương chi đạo, hóa thân làm đại nhật, phần thiên chử hải chỉ trong một niệm." },
                { name: "Chân · Tổ Long Huyết Mạch", desc: "Nhục thân cường hoành không gì sánh được, thống ngự thủy tộc, một tiếng long ngâm vạn thú thần phục, trời sinh tự mang long uy." },
                { name: "Chân · Tha Hóa Tự Tại", desc: "Có thể hóa vạn cổ, có thể hóa tuế nguyệt, có thể hóa tha nhân. Có thể mượn được đạo quả của cường giả quá khứ và tương lai, quỷ dị khó lường." },
                { name: "Chân · Giai Tự Bí", desc: "Kích hoạt liền có thể tăng gấp mười lần chiến lực, vô luận thần thức, nhục thân hay pháp lực, tăng cường toàn diện gấp mười lần, miểu sát đồng giai." },
                { name: "Chân · Cửu Bí Hợp Nhất", desc: "Tập hợp đủ Đạo gia Cửu Bí, công phạt, cực tốc, khôi phục, suy diễn v.v. đều đạt tới cực cảnh, đồng giai vô địch." },
                { name: "Chân · Nguyên Thiên Sư", desc: "Tinh thông nguyên thuật, có thể định long mạch, khóa khí vận. Chiến đấu tại danh sơn đại xuyên lực lượng tăng gấp bội, càng có thể mổ xẻ ra thần liệu tiên kim." },
                { name: "Chân · Thần Tượng Trấn Ngục", desc: "Lấy khí dẫn thần, lấy thần thành tượng, giơ tay nhấc chân liền có sức mạnh của tám trăm bốn mươi vạn thần tượng, có thể hái sao trăng." },
                { name: "Chân · Phật Nộ Hỏa Liên", desc: "Thuật khống hỏa đăng phong tạo cực, có thể dung hợp vô số loại dị hỏa, xoa ra nghệ thuật bạo liệt hình hoa sen, vượt cấp giết địch là tất yếu." },
                { name: "Chân · Thảo Tự Kiếm Quyết", desc: "Một ngọn cỏ chém tận nhật nguyệt tinh thần. Kiếm ý hoàng hoàng, không vật gì không chém, chính là vô thượng kiếm quyết công phạt đệ nhất." },
                { name: "Chân · Côn Bằng Bảo Thuật", desc: "Vào biển làm Côn, lên trời làm Bằng. Âm dương cộng tế, cực tốc vô song, nhục thân cùng pháp thuật đều là đỉnh cấp." },
                { name: "Chân · Lục Đạo Luân Hồi Quyền", desc: "Một quyền ném ra, lục đạo luân chuyển, dường như muốn đánh kẻ địch vào luân hồi, bá đạo vô biên." },
                { name: "Chân · Đại Hoang Tù Thiên Chỉ", desc: "Nửa chỉ lay thiên địa, một chỉ tù thiên địa, năm chỉ động càn khôn. Chỉ pháp thông thần, uy lực tăng theo cấp số nhân cùng tu vi." },
                { name: "Chân · Mạc Khi Thiếu Niên Cùng", desc: "Khai cục phế sài kinh điển, chịu đựng sỉ nhục từ hôn. Nhưng chỉ cần định ra ước hẹn ba năm, tốc độ tu luyện sẽ như ngồi tên lửa, tất nhiên vả mặt." },
                { name: "Chân · Chuế Tế Chiến Thần", desc: "Ẩn giấu thân phận ở rể tu hành thế gia, chịu tận bạch nhãn. Cho đến khi một tiếng hạ lệnh, mười vạn tiên binh quy vị, để nhạc mẫu hối hận không kịp." },
                { name: "Chân · Long Vương Quy Lai", desc: "Vốn là Long vương thượng giới, bị người hãm hại trọng sinh hạ giới. Dấu hiệu nụ cười nhếch mép, sống chết khó lường, chủ yếu dựa vào bộ hạ để trang bức." },
                { name: "Chân · Địch Hóa Lưu", desc: "Rõ ràng rất yếu hoặc bình thường không có gì lạ, nhưng người xung quanh (bao gồm cả kẻ địch) luôn tự bổ não ngươi là tuyệt thế cao nhân, thậm chí có thể bổ não ngươi thành tiên." },
                { name: "Chân · Ổn Kiện Đạo Tổ", desc: "Rõ ràng thực lực siêu phàm, lại quá mức thận trọng. Giết một tên Luyện Khí kỳ cũng phải rải tro ba ngày ba đêm, át chủ bài vĩnh viễn lật không hết." },
                { name: "Chân · Đại Ái Tiên Tôn", desc: "Làm người 'chân thành lương thiện', am hiểu 'lấy lý phục người'. Vì luyện Xuân Thu Thiền, không tiếc hiến tế toàn bộ dòng thời gian (bao gồm cả đồng đội)." },
                { name: "Chân · Khai Cục Một Con Chó", desc: "Chân không dính một đồng, chỉ có một con bạn sinh thú thoạt nhìn giống chó cỏ. Nhưng con chó này thực ra là Thái Cổ Thôn Thiên Thú, chuyên ăn thần khí." },
                { name: "Chân · Cửu Long Lạp Quan", desc: "Thanh đồng cổ quan từ trên trời giáng xuống đưa ngươi mở ra tinh không cổ lộ, tuy rằng khai cục hung hiểm, nhưng cũng là khởi điểm của con đường Già Thiên Đại Đế." },
                { name: "Chân · Bàn Phím Hiệp Đạo", desc: "Lấy 'Phím' nhập đạo, ngôn xuất pháp tùy. Chỉ cần dùng đạo lý (chửi người) thắng được đối phương, đạo tâm của đối phương sẽ vỡ nát, tu vi rớt thê thảm." },
                { name: "Chân · Thoái Hôn Lưu", desc: "Sau khi bị từ hôn IQ chớp mắt chiếm lĩnh cao địa, thể chất phế sài nguyên bản thức tỉnh, hơn nữa thường thường sẽ nhặt được lão gia gia trong chiếc nhẫn." },
                { name: "Chân · Cha Tông Chủ Của Ta", desc: "Liều cha lưu cực hạn, tài nguyên tùy ý lấy, gây họa có người gánh. Chỉ cần không tìm đường chết trêu chọc Thiên Mệnh Chi Tử, cơ bản là đi ngang." },
                { name: "Chân · Tảo Địa Tăng", desc: "Tạp dịch quét rác không khởi nhãn nhất trong tông môn, thực tế lại là Thái Thượng trưởng lão ẩn giấu, đánh dấu trăm năm, xuất thế liền vô địch." },
                { name: "Chân · Tạc Thiên Bang Chúng", desc: "Hành sự ngang ngược, thích tịch thu gia sản. Nơi đi qua, tấc cỏ không mọc, ngay cả nền đất tông môn cũng cạo đi cho bằng được." },
                { name: "Chân · Khoa Học Tu Tiên", desc: "Dùng cơ học lượng tử giải thích thiên đạo, dùng dung hợp hạt nhân luyện chế kim đan. Đương lượng chính là chính nghĩa, đường kính chính là chân lý." },
                { name: "Chân · Con Ta Có Tư Đại Đế", desc: "Với tư cách là cha/mẹ, tuy bản thân tư chất bình thường, nhưng con trai/con gái lại là tuyệt thế thiên tài, có thể nằm thắng thành Thái Thượng Hoàng." },
                { name: "Chân · Vị Hôn Thê Là Nữ Đế", desc: "Ăn bám vô sỉ. Không chỉ vị hôn thê là chuyển thế Nữ Đế, mà còn cực kỳ bao che khuyết điểm, ai động đến ngươi nàng diệt mãn môn kẻ đó." },
                { name: "Chân · Giáp Hồi Sinh", desc: "Sở hữu một loại thể chất hoặc bảo vật đặc thù, sau khi chết có thể đầy máu sống lại tại chỗ, hơn nữa mỗi lần sống lại đều sẽ biến cường (Người Saiya?)." },
                { name: "Chân · Trăm Phần Trăm Tay Không Đỡ Bạch Nhẫn", desc: "Kỹ năng nhân quả luật. Bất luận đối phương mạnh bao nhiêu, chỉ cần ngươi chắp tay lại, kiếm của đối phương nhất định sẽ chém vào tay ngươi, cục diện nháy mắt lúng túng." },
                { name: "Chân · Khủng Bố Như Tư", desc: "Với tư cách là khí vận dạng dẫn truyện, người xung quanh luôn hít vào một hơi khí lạnh đối với hành vi của ngươi, dẫn đến sự nóng lên toàn cầu (gạch bỏ), có thể chấn nhiếp bọn tiêu xáo." },
                { name: "Chân · Vị Diện Chi Tử", desc: "Vận khí tốt đến mức không giảng đạo lý. Nhảy núi nhặt bí kịch, mua rác rưởi ra thần khí, ăn mày ven đường đều là ẩn thế cao nhân." },
                { name: "Chân · Chủng Điền Lưu", desc: "Sở hữu một phương tùy thân linh điền, linh thực trồng ra hiệu quả nghịch thiên. Không tranh bá, chỉ làm ruộng, cuối cùng dùng linh dược dìm chết đại BOSS." },
                { name: "Chân · Triệu Hoán Lưu", desc: "Bản thân chiến lực bình thường, nhưng có thể từ dị giới triệu hoán đệ tứ thiên tai (người chơi) hoặc nhân vật anime đến trợ chiến, đánh hội đồng là vô địch." },
                { name: "Chân · Thiên Đạo Là Mẹ Ta", desc: "Ngươi chính là con riêng của Thiên Đạo, ruột thịt. Độ kiếp? Lôi kiếp tự động đi đường vòng. Bình cảnh? Mẹ ruột mở lớp học thêm. Khí Vận Chi Tử? Trước mặt ngươi chỉ là một tên nhóc." },
                { name: "Chân · Tuyệt Đối Né Tránh", desc: "Năng lực né tránh đẳng cấp nhân quả luật. Bất kỳ hình thức tấn công nào, trước khi đánh trúng ngươi đều sẽ vì các loại nguyên nhân không thể tưởng tượng (như kẻ địch trượt chân, thời không vặn vẹo) mà đánh trượt." },
                { name: "Chân · Thuần Thú Chi Thần", desc: "Bất kỳ thú loại nào, dù là phàm thú, linh thú hay thần thú, nhìn thấy ngươi đều sẽ bị độ thân hòa thần thánh trên người ngươi thu hút, tự nguyện trở thành phó tùng trung thành nhất của ngươi, ngay cả hỗn độn cự thú cũng tranh nhau làm thú cưỡi cho ngươi." },
                { name: "Chân · Nhất Khí Hóa Tam Thanh", desc: "Đạo môn chí cao thần thông, có thể hóa ra hai cái phân thân có thực lực hoàn toàn giống bản thể. Tương đương với gấp ba chiến lực, hơn nữa phân thân còn có thể tự mình tu luyện, kinh nghiệm chia sẻ." },
                { name: "Chân · Bối Cảnh Bản Chi Vương", desc: "Mặc dù ngươi thoạt nhìn bình thường không có gì lạ, nhưng thư đồng của ngươi là Kiếm Tiên chuyển thế, con chó nuôi là Thượng Cổ Hung Thú, con trâu già trong nhà là Thần Thú. Ai chọc ngươi kẻ đó xui xẻo." },
                { name: "Chân · Vô Hạn Lam Điều", desc: "Linh lực/Pháp lực của ngươi là vô hạn. Ngươi có thể không hề cố kỵ phóng thích bất kỳ cấm chú hoặc thần thông tiêu hao to lớn nào, dùng đại chiêu tẩy đất là thao tác thường ngày của ngươi." },
                { name: "Chân · Bách Bội Thời Gian Lưu Tốc", desc: "Ngươi sở hữu một không gian cá nhân, tốc độ thời gian trôi qua bên trong gấp trăm lần bên ngoài. Ngươi ở bên trong tu luyện trăm năm, bên ngoài mới trôi qua một năm." },
                { name: "Chân · Nhân Sinh Kịch Bản", desc: "Có thể nhìn thấy mệnh số cùng cơ duyên gần nhất của tất cả mọi người (thậm chí vạn vật). Không chỉ có thể nẫng tay trên tạo hóa nghịch thiên của Thiên Mệnh Chi Tử, mà còn có thể thời thời khắc khắc xu cát tị hung." },
                { name: "Chân · Hệ Thống Cảm Xúc", desc: "Thu thập hỉ nộ ái ố của người khác hóa thành thần lực. Chỉ cần không ngừng làm trò khiến người ta phá phòng hoặc khiếp sợ, tài nguyên tu luyện liền có thể liên tục đổi lấy." },
                { name: "Chân · Chư Thiên Vạn Giới Câu Cá", desc: "Ném cần câu vào hư không, pháp bảo, thần đan thậm chí Thái Cổ Thần Nữ đều có thể câu lên. Vận khí tốt một cần câu câu ra trấn tộc chí bảo của thế giới sát vách." },
                { name: "Chân · Cuồng Ma Giết Địch Rớt Bảo", desc: "Võng du hóa thế giới hiện thực. Đánh chết bất kỳ sinh linh nào tất bạo đầy đất trang bị cực phẩm tản mạn kim quang cùng quang cầu tu vi, liếm bao liền có thể vô địch thiên hạ." },
                { name: "Chân · Phản Thương Thứ Giáp", desc: "Thuần túy huyết ngưu phòng chiến lưu. Hoàn toàn từ bỏ tấn công, chịu bất kỳ tổn thương nào đều có thể trả lại gấp ngàn lần. Người khác đánh ngươi một chút, tự hắn tại chỗ hôi phi yên diệt." },
                { name: "Chân · Vạn Giới Shipper", desc: "Cưỡi xe điện nhỏ xuyên qua chư thiên giao đồ ăn. Không chỉ kết giao các giới đại lão, nhận được thần cấp tiền boa lại càng khiến người liên tục đột phá cảnh giới nhỏ." },
                { name: "Chân · Ngự Thú Hợp Thành Thuật", desc: "Tay trái một con chó cỏ, tay phải một con chim sẻ, hai tay vỗ một cái trực tiếp hợp thể thành diệt thế thần thú không thể diễn tả, sủng vật toàn dựa vào hầm bà lằng." },
                { name: "Chân · Tối Cường Điển Ngục Trưởng", desc: "Tùy thân mang theo một tòa thần thoại ngục giam, bên trong giam giữ lượng lớn Nữ Đế và Nữ Ma Tôn từng trấn áp thời đại, có thể tùy thời rút ra sức mạnh của họ hoặc thả ra làm tay sai." },
                { name: "Chân · Đại Triệu Hoán Thuật", desc: "Gặp chuyện do dự trực tiếp hiến tế tiết tháo. Có thể vượt không gian triệu hoán đủ loại đỉnh phong chiến lực trong anime, phim ảnh hoặc khoa học viễn tưởng thần thoại đến thay ngươi quần ẩu người khác." },
                { name: "Chân · Tử Vong Hồi Đáng", desc: "Mỗi lần tử vong đều sẽ tự động mang theo ký ức quay về một ngày trước. Sở hữu quyền hạn vô hạn thử lỗi, dùng vô số lần tử vong chất đống ra một kết cục thông đảo hoàn mỹ." },
                { name: "Chân · Vạn Giới Đương Phô", desc: "Mở một cái tiệm cầm đồ bí ẩn, thu lấy khí vận, thiên phú thậm chí ái tình của người khác làm đồ cầm cố để cho vay. Một khi vi phạm hợp đồng trực tiếp mạt sát và nuốt chửng mọi thứ của kẻ đó." },
                { name: "Chân · Năng Lượng Tiêu Cực Đại Sư", desc: "Dựa vào thu thập oán niệm để biến cường. Mỗi ngày ở Tu Tiên Giới điên cuồng quần trào, làm tận chuyện thiếu đạo đức, toàn bộ Tu Tiên Giới hận ngươi thấu xương." },
                { name: "Chân · Song Tu Vạn Bội Tăng Phúc", desc: "Mặc dù không phải Hợp Hoan Tông, nhưng bất kỳ người nào song tu cùng ngươi đều có thể nhận được sự phản hồi thăng hoa cực hạn gấp vạn lần, trực tiếp khiến toàn hạ tiên tử thánh nữ đều đảo điên tranh giành ngươi." },
                { name: "Chân · Siêu Cấp Đầu Tư Cá Sấu", desc: "Bốn phía tìm kiếm các Khí Vận Chi Tử đang ở giai đoạn khốn cùng và bị từ hôn để tiến hành đầu tư, đợi bọn họ cất cánh xong nhận lại phần thưởng gấp tỷ vạn lần, tiểu đệ rải rác cửu thiên thập địa." },
                { name: "Chân · Chư Thiên Đấu Giá Hội", desc: "Chưởng khống một gian khách điếm xuyên không chỉ tồn tại trong truyền thuyết, định kỳ đấu giá những cơ duyên chí cao vô thượng mà các giới không người nào theo kịp, đem đại năng của thế giới đùa bỡn trong lòng bàn tay." },
                { name: "Chân · Lão Gia Gia Thu Dung Sở", desc: "Trong chiếc nhẫn của người khác chỉ có một vị lão gia gia, trong thức hải của ngươi ở đến tám chín chục vị viễn cổ tàn hồn và tiên đế ý chí thuộc các thể hệ khác nhau, lưu phái nào cũng tùy tiện cho ngươi chọn." },
                { name: "Chân · Khống Chế Thời Gian", desc: "Tùy ý thao túng thời gian trôi qua, có thể trực tiếp tạm dừng thời gian để bạo đả cường địch, hoặc trong thời gian trường hà dạo chơi trở về quá khứ bóp chết kẻ địch khi còn ở trong bụng mẹ." },
                { name: "Chân · Luyện Cổ Đại Tông Sư", desc: "Bắt vô số kỳ trùng cực phẩm linh tài của thiên địa để luyện chế vô giải tiên cổ. Cho dù là một con muỗi qua tay ngươi, cũng có thể hóa thành diệt thế cổ vương một khi thả ra liền độc diệt thiên hạ." },
                { name: "Chân · Cơ Giới Phi Thăng", desc: "Vứt bỏ nhục thể khổ nhược, chưởng khống khoa học kỹ thuật thụ của các giới. Dùng cơ giới thần khu cấy ghép tiên đạo hạch tâm để bố trận, đồng thời dùng pháo quỹ đạo liên tinh hệ để đánh tan lôi kiếp thành tiên của chính mình." },
                { name: "Chân · Cửu U Địa Ngục Chi Chủ", desc: "Trời sinh hiệu lệnh vô số ác quỷ âm binh của Địa Ngục Hoàng Tuyền, mỗi một đòn ngươi đánh ra đều mang theo lời nguyền thê lương của mười tám tầng địa ngục và trùng kích tinh thần có thể chớp mắt xé rách hồn phách." },
                { name: "Chân · Đứng Đầu Bảng Truy Nã Sát Lục", desc: "Do cơ chế hệ thống mà trên đỉnh đầu luôn treo lệnh truy nã đắt giá nhất toàn chư thiên. Người toàn thế giới đều muốn đến giết ngươi, nhưng phần thưởng tu vi ngươi nhận được sau khi phản sát kẻ địch lại cực kỳ thái quá." },
                { name: "Chân · Thần Thoại Tạo Hóa Giả", desc: "Ngươi có thể tùy tâm sở dục phổ cập các câu chuyện thần thoại trên Trái Đất vào Tu Tiên Giới. Ngươi chỉ cần bịaa càng chân thật, những nhân vật và thần khí trong truyền thuyết kia sẽ cưỡng chế thực thể hóa và chỉ phục tùng ngươi." },
                { name: "Chân · Lưỡng Giới Xuyên Thoi Môn", desc: "Có thể tự do xuyên qua lại giữa một hành tinh hiện đại không có chút linh khí nào và một Tu Chân Giới cực độ nguy hiểm. Thông qua việc buôn bán công nghệ và vật tư giữa hai giới, trực tiếp dễ dàng nằm ườn ra nghịch thiên." },
                { name: "Chân · Tối Cường Ăn Bám", desc: "Chuyên trói định các nữ đế lãnh ngạo và tuyệt đại thần nữ trong đại thế giới, chỉ cần dùng lời ngon tiếng ngọt dỗ dành cho các nàng vui hoa nở nhụy, các chỉ số thuộc tính của ngươi sẽ dùng bội số hình học điên cuồng tăng vọt." },
                { name: "Chân · Kẻ Ấp Thần Đản", desc: "Bắt đầu hệ thống tặng một viên siêu cấp sủng vật đản có thể hút cạn linh mạch tông môn. Ấp ra một sủng vật thoạt nhìn yếu ớt bình thường, cuối cùng lại sẽ hóa thành thái cổ cự thú có thể một hơi nuốt chửng dải ngân hà." },
                { name: "Chân · Dịch Vụ Đỡ Lôi Kiếp", desc: "Miễn dịch tự nhiên với mọi lôi pháp. Chuyên giúp đỡ độ kiếp kỳ lão quái đỡ thay thiên kiếp, không chỉ có thể thu được phí thủ tục trên trời, còn có thể nén kiếp lôi mà thiên đạo đánh xuống vào trong bình làm lựu đạn ném." },
                { name: "Chân · Cuồng Ma Xây Dựng Tông Môn", desc: "Khởi bước chỉ có một căn nhà tranh tồi tàn, thông qua việc đi khắp nơi lừa gạt đệ tử sở hữu thể chất kỳ ba nhập môn, từng bước từng bước đưa tông môn cỏ gà rác rưởi kiến tạo thành vô thượng thánh địa khiến Tiên Đế cũng chỉ có thể quét rác ngoài cửa." },
                { name: "Chân · Thần Hào Vung Tiền", desc: "Tôn sùng đại đạo 'có tiền chính là có thể tùy tâm sở dục'. Linh thạch tiêu ra ngoài càng nhiều, tu vi gia thành cùng thần khí phần thưởng mà hệ thống trả về cho ngươi càng khủng bố." },
                { name: "Chân · Thời Không Đại Đạo", desc: "Ai dám chọc ngươi, ngươi không đánh hắn, ngươi trực tiếp thông qua đường hầm thời không quay về ức vạn năm trước, đem cơ duyên trong tổ phần của cường địch kia đào đi toàn bộ, dẫn đến kẻ địch vốn ngạo mạn kinh hồn kia nháy mắt teo tóp thành phế vật cùng quang đản." },
                { name: "Chân · Bị Ép Bổ Não Đại Đế", desc: "Rõ ràng chỉ muốn làm một người qua đường khiêm tốn nấp trong khe núi, làm sao hệ thống cùng vận khí luôn khiến ngươi đúng vào thời khắc trùng hợp nhất dẫn phát dị tượng hoành tráng hủy thiên diệt địa, mạnh mẽ nhận tận sự sùng bái cuồng nhiệt của chư thiên vạn giới." },
                { name: "Chân · Hệ Thống Cực Hạn Tìm Chết", desc: "Nhiều lần nhảy nhót qua lại bên vách đá. Hệ thống quy định ngươi tìm chết càng lớn, dẫn tới sự phẫn nộ cùng hoảng loạn càng cao, phần thưởng phản hồi ngươi đạt được lại càng điên cuồng nổ tung." },
                { name: "Chân · Thần Cấp Chư Thiên Xuyên Thoi", desc: "Hoàn toàn phớt lờ sự cản trở bích lũy không gian của vị diện đại đạo. Nếu ở cái cao võ tiên hiệp thế giới này chọc tới toàn vũ trụ mãn môn truy nã đánh không lại lúc, nháy mắt liền có thể chuồn đi tị nạn tại khoa học viễn tưởng Marvel hoặc đô thị linh khí thức tỉnh thế giới bên trong, đi ngược đồ ăn phát dục max cấp rồi lại quay lại báo thù nghiền ép." },
                { name: "Chân · Thiên Phú Lược Đoạt", desc: "Mỗi khi ngươi giết chết một sinh linh, ngươi đều có thể từ trên thân nó ngẫu nhiên tước đoạt một hạng thiên phú hoặc thần thông, hơn nữa có thể hoàn mỹ dung hợp, không có bất kỳ tác dụng phụ nào." }
            ];

            const restrictedFortunePresets = [
                { name: "Thiên Mệnh Phản Phái", desc: "Trời sinh đứng ở mặt đối lập với nhân vật chính. Tuy tốc độ tu hành cực nhanh, nhưng dễ chọc tới Khí Vận Chi Tử, hơi bất cẩn một chút liền sẽ trở thành hòn đá lót đường cho kẻ khác." },
                { name: "Thiên Mệnh Đại Phản Phái", desc: "Tâm tính độc ác, hành sự không cố kỵ. Tuy có thể thông qua cướp đoạt nhanh chóng biến cường, nhưng nhấc lên toàn thế địch, chính đạo người người đều muốn giết, khó lòng tìm kiếm đồng minh." },
                { name: "Thi Đạo Tông Sư", desc: "Quanh năm làm bạn với thi thể, sinh cơ của bản thân bị tử khí ăn mòn. Tuy thuật khống thi tài giỏi, nhưng nhục thân âm hàn, không chỉ vì ngoại mạo bị bài xích, mà còn khó lòng tu tập chính thống dương cương công pháp." },
                { name: "Bất Hóa Cốt", desc: "Nhục thân cứng rắn như sắt, đao thương bất nhập, nhưng khớp xương cứng đờ, thân pháp chậm chạp. Cần lượng lớn âm sát chi khí ôn dưỡng, hơn nữa hóa hình khó khăn, dễ bị coi là yêu ma chém giết." },
                { name: "Hoàng Tuyền Dẫn Lộ Nhân", desc: "Có thể thông u minh, sai sử quỷ thần. Nhưng mỗi lần mở quỷ môn đều sẽ nhiễm nhân quả, dễ chuốc lấy âm tà cắn trả, vãn niên e rằng gặp phải bất tường." },
                { name: "Hệ Thống Đăng Nhập Mỗi Ngày", desc: "Sở hữu hệ thống đăng nhập, nhưng phần thưởng đa phần là vật phàm tục, cực hiếm khi xuất hiện trân phẩm. Hơn nữa nhiệm vụ hệ thống ban bố tính cưỡng chế cao, nếu không hoàn thành sẽ có ách vận quấn thân." },
                { name: "Thâm Lam Gia Điểm", desc: "Có thể thông qua tiêu hao tài nguyên cưỡng chế nâng cao cảnh giới công pháp, nhưng căn cơ phù phiếm, chiến lực thấp hơn người khổ tu đồng giai. Cần tiêu tốn thêm tinh lực đánh bóng tâm cảnh, nếu không dễ tẩu hỏa nhập ma." },
                { name: "Nhân Sinh Mô Nghĩ Khí", desc: "Có thể mô phỏng tương lai, nhưng mỗi lần mô phỏng tiêu hao lượng lớn linh thạch cùng tinh thần lực. Hơn nữa bóng ma tử vong trong mô phỏng sẽ ảnh hưởng đến hiện thực đạo tâm, cần thời gian dài khôi phục." },
                { name: "Thụ Đồ Vạn Bội Phản Hoàn", desc: "Tỷ lệ trả lại cực kỳ không ổn định, đa phần là tỷ lệ thấp. Hơn nữa tư chất đồ đệ參差 không đồng đều, dạy dỗ đồ đệ cực kỳ hao phí tâm lực, kéo chậm nghiêm trọng tiến độ tu luyện của bản thân." },
                { name: "Thần Cấp Lựa Chọn Hệ Thống", desc: "Lựa chọn thường tràn ngập cạm bẫy, rủi ro cao phần thưởng cao. Mặc dù phần thưởng phong phú, nhưng thường bị ép cuốn vào phân tranh của đại năng hoặc tuyệt địa hiểm cảnh, cửu tử nhất sinh." },
                { name: "Tối Cường Phản Sáo Lộ", desc: "Hành vi bắt buộc phải khác người thường mới có thể nhận được sức mạnh, thường bị người ta coi là kẻ điên hoặc kẻ rước họa lấy tiếng. Khó lòng an ổn sinh tồn trong hệ thống tông môn, danh tiếng tồi tệ." },
                { name: "Công Pháp Giản Hóa Hệ Thống", desc: "Công pháp dễ học khó tinh, tuy nhập môn cực nhanh, nhưng uy lực giảm bớt. Hơn nữa phiên bản giản hóa của công pháp thường tồn tại ẩn hoạn, giới hạn bị khóa, khó lòng đột phá đến cảnh giới tối cao." },
                { name: "Chư Thiên Liêu Thiên Quần", desc: "Thành viên trong nhóm cá rồng lẫn lộn, thật giả khó phân. Giao dịch vượt giới cần trả giá đắt đỏ, hơn nữa dễ bị tồn tại ở vị diện cao dọc theo đường mạng (nhân quả tuyến) tiến hành giáng duy đả kích." },
                { name: "Treo Máy Tu Tiên", desc: "Thân thể tự động tu luyện, nhưng do không có thần thức chủ đạo, gặp bình cảnh không thể tự động đột phá. Hơn nữa khi treo máy cảm nhận đối với ngoại giới giảm xuống, dễ gặp phải đánh lén." },
                { name: "Thôn Phệ Tiến Hóa", desc: "Có thể thông qua nuốt chửng vạn vật để biến cường, nhưng trong cơ thể tạp chất ứ đọng, cần tiêu tốn lượng lớn thời gian luyện hóa. Nếu tham lam không đáy, cuối cùng sẽ hóa thành quái vật chỉ biết ăn uống." },
                { name: "Trường Sinh Từ Khúc", desc: "Thọ nguyên vô tận, nhưng tư chất kém đến cực điểm. Tốc độ tu luyện như rùa bò, chỉ có thể ngồi nhìn thương hải tang điền, thân hữu qua đời, thừa nhận vô tận tuế nguyệt cô độc." },
                { name: "Trực Tiếp Tu Tiên", desc: "Thông qua nhân khí đạt được tài nguyên, nhưng hành tung hoàn toàn bị lộ. Cừu gia có thể bất cứ lúc nào nắm giữ động hướng của ngươi, hơn nữa vì nhân khí không thể không đi vào hiểm địa tìm đường chết, không có chút tư ẩn nào." },
                { name: "Gia Tộc Tu Tiên", desc: "Gia tộc là trợ lực cũng là gông xiềng. Hưởng thụ tài nguyên đồng thời, bắt buộc phải gánh vác trách nhiệm gia tộc nặng nề. Một khi gia tộc cuốn vào phân tranh, bản thân cũng khó lòng bình yên vô sự." },
                { name: "Nạp Kim Thành Tiên", desc: "Cho dù hít thở cũng cần tiêu hao linh thạch. Không có linh thạch tấc bước khó đi, tu vi sẽ tụt lùi theo tài phú giảm bớt. Cả đời đều bôn ba vì kiếm linh thạch." },
                { name: "Cuồng Ma Nhiệm Vụ", desc: "Bị ép tiếp nhận các loại nhiệm vụ phiền toái, không thể thời gian dài bế quan. Nhiệm vụ phần thưởng tuy ổn định, nhưng độ khó dần mất khống chế, thường bị ép gián đoạn tu hành đi chạy vặt." },
                { name: "Chí Tôn Cốt", desc: "Từng bị đào đi Chí Tôn Cốt, tuy niết bàn trọng sinh nhưng nguyên khí đại thương. Thể chất suy nhược, cần lượng lớn thiên tài địa bảo bù đắp chỗ thiếu hụt, mới có thể tái hiện thần uy chí tôn." },
                { name: "Trọng Đồng Giả", desc: "Nhìn thấu hư vọng, nhưng đối với thần hồn tiêu hao cực lớn. Quanh năm ở trạng thái tinh thần mệt mỏi, hơn nữa dễ dàng nhìn thấy đại khủng bố không nên nhìn, dẫn đến tinh thần thất thường." },
                { name: "Hỗn Độn Thể", desc: "Vạn khí đều có thể tu, nhưng tài nguyên cần thiết để tiến giai gấp trăm lần người thường. Ở Tu Tiên Giới tài nguyên bần cùng, cực dễ vì thiếu hụt tài nguyên mà mắc kẹt ở cảnh giới thấp lãng phí cả đời." },
                { name: "Hoang Cổ Thánh Thể", desc: "Nhục thân vô song, nhưng bị thiên địa pháp tắc áp chế, không chỉ đột phá gian nan, hơn nữa là động không đáy tiêu hao nguyên thạch. Vãn niên dễ xảy ra dị biến bất tường." },
                { name: "Tiên Thiên Đạo Thai", desc: "Trời sinh gần đạo, tình cảm lạnh nhạt. Theo tu vi ngày càng sâu, nhân tính dần dần mất đi, cuối cùng có khả năng bị Thiên Đạo đồng hóa, trở thành hóa thân quy tắc vô tình vô dục." },
                { name: "Thương Thiên Bá Thể", desc: "Bá đạo tuyệt luân, nhưng tính cách cố chấp dễ giận, dễ bị phép khích tướng lợi dụng. Hơn nữa máu của Bá Thể là vô thượng đại dược trong mắt ma tu, thường bị dòm ngó." },
                { name: "Tiên Đế Chuyển Thế", desc: "Chỉ có cảm ngộ cảnh giới cao thâm, nhục thân lại yếu ớt không chịu nổi. Mắt cao tay thấp, cực dễ vì khinh thường tu sĩ cấp thấp mà lật thuyền trong mương, hơn nữa gánh vác nhân quả thù hận tiền thế." },
                { name: "Bạn Sinh Đế Binh", desc: "Đế binh bị tổn hại nghiêm trọng, cần hút tinh huyết của túc chủ để ôn dưỡng. Trước khi chữa trị, nó chẳng những không thể bảo vệ chủ, ngược lại là một gánh nặng to lớn cùng quả bom hẹn giờ." },
                { name: "Hồng Mông Tử Khí", desc: "Nền tảng thành thánh, chọc cho thiên hạ tu sĩ phát cuồng. Mang ngọc có tội, nhấc lên toàn thế địch, trước khi trưởng thành chỉ có thể ẩn tính mai danh, đông trốn tây núp." },
                { name: "Tam Túc Kim Ô", desc: "Trong cơ thể chí dương hỏa lực khó lòng khống chế, hơi bất cẩn một chút liền sẽ thiêu rụi đồ vật bên người. Khó lòng tìm kiếm đạo lữ, hơn nữa bị đại năng tu tập công pháp hệ Thủy khắc chế." },
                { name: "Tổ Long Huyết Mạch", desc: "Huyết mạch phản tổ, ngoại mạo khác với người thường, dễ bị nhận nhầm là gian tế Yêu tộc. Hơn nữa long tính bản dâm, cần thời khắc áp chế dục vọng bản năng, nếu không đạo tâm không ổn." },
                { name: "Tha Hóa Tự Tại", desc: "Mượn lấy quả vị tương lai cần trả giá to lớn, mỗi lần sử dụng sau đó sẽ rơi vào thời kỳ suy nhược dài dằng dặc. Hơn nữa dễ lạc lối trong vô số cái 'tự ngã', không phân rõ hư huyễn hiện thực." },
                { name: "Giai Tự Bí", desc: "Xác suất kích hoạt gấp mười lần chiến lực cực thấp, tựa như đánh bạc. Lúc mấu chốt nếu chưa kích hoạt, liền chỉ có thể mặc người xâu xé. Hơn nữa đối với thân thể gánh nặng cực lớn." },
                { name: "Cửu Bí Hợp Nhất", desc: "Cưỡng ép dung hợp cửu bí cực dễ dẫn đến linh lực trong cơ thể rối loạn. Không phải kẻ có đại nghị lực, đại cơ duyên, chẳng những không thể phát huy uy lực, ngược lại sẽ kinh mạch đứt từng khúc mà chết." },
                { name: "Nguyên Thiên Sư", desc: "Tìm long điểm huyệt, tiết lộ thiên cơ. Vãn niên tất gặp bất tường, toàn thân mọc lông đỏ, thần trí lạc lối, trở thành quái vật hình người lang thang trong cấm khu." },
                { name: "Thần Tượng Trấn Ngục", desc: "Con đường nhục thân thành thánh, mỗi khi thức tỉnh một hạt nhỏ đều cần cắn nuốt năng lượng của một phương tài nguyên. Tại vùng đất cằn cỗi tài nguyên, công pháp này hình đồng phế giấy." },
                { name: "Phật Nộ Hỏa Liên", desc: "Chơi với lửa có ngày chết cháy. Dung hợp dị hỏa cực kỳ nguy hiểm, hơi sai một ly liền là hôi phi yên diệt. Hơn nữa dị hỏa khó tìm, thường tồn tại ở sâu trong tuyệt địa." },
                { name: "Thảo Tự Kiếm Quyết", desc: "Kiếm ý lăng lệ hại người hại mình. Người tu tập kiếm quyết này, cơ thể quanh năm chịu nỗi đau kiếm khí cắt xé, thọ nguyên so với tu sĩ đồng giai càng ngắn ngủi." },
                { name: "Côn Bằng Bảo Thuật", desc: "Âm dương nhị khí khó lòng điều hòa. Khi luân phiên giữa hóa Bằng và hóa Côn tồn tại thời kỳ cứng đờ, dễ bị kẻ địch nắm lấy sơ hở. Hơn nữa sức ăn kinh người." },
                { name: "Lục Đạo Luân Hồi Quyền", desc: "Quyền ý bá đạo, mỗi một quyền đều đang thấu chi tiềm năng sinh mệnh. Tuổi trẻ thời điểm uy chấn thiên hạ, lúc tuổi già khí huyết khô bại, thường thường chết không tử tế." },
                { name: "Đại Hoang Tù Thiên Chỉ", desc: "Uy lực to lớn, nhưng thời gian tụ lực quá dài. Trong sinh tử bác sát biến hóa nhanh chóng, cực dễ bị ngắt quãng thi pháp hoặc trở thành bia ngắm sống." },
                { name: "Mạc Khi Thiếu Niên Cùng", desc: "Khai cục phế sài kinh điển, chịu đựng sỉ nhục từ hôn. Nhưng chỉ cần định ra ước hẹn ba năm, tốc độ tu luyện sẽ như ngồi tên lửa, tất nhiên vả mặt." },
                { name: "Chuế Tế Chiến Thần", desc: "Sống nhờ nhà người, chịu tận bạch nhãn. Trước khi bộc lộ thực lực, cần chịu đựng đủ loại làm khó dễ của nhạc mẫu và họ vợ, tâm cảnh cực dễ bị hao tổn." },
                { name: "Long Vương Quy Lai", desc: "Từng là thượng vị giả, nay rồng mắc cạn. Khó lòng thích ứng với sự chênh lệch thân phận, hành sự thường quá mức cao điệu kiêu ngạo, dễ dàng tại lúc yếu ớt chọc tới cường địch không thể chiến thắng." },
                { name: "Địch Hóa Lưu", desc: "Thực lực bản thân bình thường, toàn dựa vào người khác bổ não. Tựa như đi trên dây thép, một khi lộ tẩy, uy vọng trước đó thiết lập sẽ nháy mắt sụp đổ, chết không có chỗ chôn." },
                { name: "Ổn Kiện Đạo Tổ", desc: "Quá mức cẩn thận, bỏ lỡ cơ duyên. Vì sợ hãi dính líu nhân quả mà không dám ra khỏi cửa, mặc dù sống lâu, nhưng tiến độ tu vi cực kỳ chậm chạp, khó lòng leo lên đỉnh." },
                { name: "Đại Ái Tiên Tôn", desc: "Vì đạt mục đích không từ thủ đoạn, tuy thu lợi khá nhiều, nhưng đạo tâm dần dần méo mó. Trọn đời sống trong tính toán và bị tính toán, không còn nửa người có thể tin tưởng." },
                { name: "Khai Cục Một Con Chó", desc: "Bạn sinh thần thú ở vào thời kỳ ấu niên, chẳng những chiến lực thấp, còn là con thú nuốt vàng. Thường xuyên ăn trộm trân quý linh dược gây họa, cần túc chủ không ngừng vì nó lau mông." },
                { name: "Cửu Long Lạp Quan", desc: "Khai cục bị truyền tống đến nơi linh khí khô kiệt. Tuy có con đường lên trời, nhưng khởi bước gian nan, cần tốn sự nỗ lực gấp vài lần người thường mới có thể thoát ra khỏi tinh vực phế khí." },
                { name: "Bàn Phím Hiệp Đạo", desc: "Nói năng chua ngoa, chỉ có thể loạn nhân đạo tâm. Gặp phải hung thú không hiểu tiếng người hoặc ma tu tâm như tảng đá, không có chút sức hoàn thủ nào." },
                { name: "Thoái Hôn Lưu", desc: "Chịu đựng sỉ nhục từ hôn, tâm ma nảy sinh. Lão gia gia trong nhẫn trước khi thức tỉnh sẽ không ngừng hút tu vi của túc chủ, dẫn đến cảnh giới thời gian dài đình trệ không tiến." },
                { name: "Cha Tông Chủ Của Ta", desc: "Tuy bối cảnh sâu đậm, nhưng bị cuốn vào đấu tranh quyền lực tông môn. Kẻ địch chính trị của cha coi ngươi là cái gai trong mắt, lúc nào cũng đối mặt với ám sát cùng hãm hại." },
                { name: "Tảo Địa Tăng", desc: "Thân phận thấp vi, tài nguyên nghèo nàn. Tuy có ngộ tính, nhưng không có danh sư chỉ điểm, hơn nữa cần hoàn thành tạp dịch nặng nề, thời gian tu luyện bị chèn ép nghiêm trọng." },
                { name: "Tạc Thiên Bang Chúng", desc: "Hành sự ngang ngược, do tổ chức lỏng lẻo, ở bên ngoài gây họa sau đó thường không có ai chống lưng. Hơn nữa tác phong thích tịch thu gia sản cực dễ gây nên công phẫn, bị quần khởi nhi công chi." },
                { name: "Khoa Học Tu Tiên", desc: "Ly kinh bạn đạo, không được tu tiên giới truyền thống tiếp nhận. Quá trình nghiên cứu tràn ngập rủi ro nổ tung, hơn nữa vật liệu cần thiết đa phần là đồ vật hiếm lạ cổ quái, khó lòng thu thập." },
                { name: "Con Ta Có Tư Đại Đế", desc: "Bản thân tư chất bình thường, toàn dựa vào hậu duệ tranh khí. Nhưng nếu hậu duệ nửa đường chết yểu hoặc sinh lòng phản nghịch, bản thân sẽ mất đi mọi chỗ dựa, cảnh già thê lương." },
                { name: "Vị Hôn Thê Là Nữ Đế", desc: "Vị hôn thê là Nữ Đế chuyển thế, nhưng trí nhớ cực kỳ lộn xộn. Nàng thường xuyên nhận nhầm ngươi là tử địch kiếp trước, tùy cơ chuyển đổi giữa trạng thái 'ái lữ' và 'cừu sát'. Ngươi vĩnh viễn không biết một khắc sau tỉnh lại, đối mặt chính là sự dịu dàng hay tuyệt sát." },
                { name: "Giáp Hồi Sinh", desc: "Sở hữu một cơ hội sống lại, nhưng sau khi sống lại tu vi rớt xuống, hơn nữa ngẫu nhiên truyền tống. Nếu vận khí không tốt trọng sinh tại hiểm địa, chính là vừa ra khỏi miệng cọp lại vào hang sói." },
                { name: "Trăm Phần Trăm Tay Không Đỡ Bạch Nhẫn", desc: "Thần kỹ phòng ngự bị động, nhưng chỉ có thể đỡ kiếm. Khi đối mặt với đao thương côn bổng hoặc pháp thuật oanh tạc thì không có chút tác dụng nào, hơn nữa trong lúc đỡ kiếm cơ thể không thể di chuyển." },
                { name: "Khủng Bố Như Tư", desc: "Vì tạo ra sự nóng lên toàn cầu nên bị thiên đạo nhắm tới, độ khó độ kiếp tăng gấp đôi. Hơn nữa thường xuyên vì hít khí lạnh mà dẫn đến phổi bị tổn thương, thể chất suy nhược." },
                { name: "Vị Diện Chi Tử", desc: "Khí vận phập phồng không ổn định, phúc họa nương tựa. Cùng lúc đạt được đại cơ duyên ắt kèm theo đại khủng bố, mỗi một lần tăng tiến đều là lặp đi lặp lại nhảy múa trên ranh giới sinh tử." },
                { name: "Chủng Điền Lưu", desc: "Tuy giàu có một phương, nhưng chiến lực thấp. Tại thế giới cường giả vi tôn, tựa như đứa trẻ ôm gạch vàng, là con cừu béo tốt nhất trong mắt ma tu và cường đạo." },
                { name: "Triệu Hoán Lưu", desc: "Bản thân ốm yếu, toàn dựa vào vật triệu hoán tác chiến. Một khi bị kẻ địch tiếp cận hoặc cắt đứt liên hệ với vật triệu hoán, liền chỉ có thể mặc người xâu xé." },
                // Thêm 50 loại khí vận phiên bản hạn chế
                { name: "Thiên Sát Cô Tinh", desc: "Mệnh phạm thiên sát, định sẵn cô độc cả đời. Khắc cha khắc mẹ khắc vợ khắc con, tuy bản thân khí vận cực mạnh, thường thường gặp dữ hóa lành, nhưng người thân cận bên cạnh đều không được chết tử tế, định sẵn một mình leo lên đỉnh đại đạo." },
                { name: "Tuyệt Thế Lô Đỉnh", desc: "Thể chất đặc thù, nguyên âm/nguyên dương cực độ thuần tịnh. Tuy tốc độ tu hành tiến triển cực nhanh, nhưng chẳng những chiến lực bình thường, hơn nữa trong mắt tất cả cao giai tu sĩ đều là thuốc bổ vô thượng di động, thời khắc đối mặt rủi ro bị bắt đi thải bổ." },
                { name: "Ách Nan Độc Thể", desc: "Trời sinh mang kịch độc, chạm vào là chết. Tuy có thể駕馭 vạn độc, tu vi tăng trưởng theo độc tính, nhưng nơi đi qua sinh linh đồ thán, không ai dám đến gần ba thước, cuối cùng sẽ bị chính đạo coi là dị đoan tà ma, quần khởi nhi công chi." },
                { name: "Cửu Dương Tuyệt Mạch", desc: "Dương khí trong cơ thể quá thịnh, kinh mạch như liệt hỏa thiêu đốt. Nếu không có vật cực hàn hoặc thuần âm thể chất điều hòa, sống không quá hai mươi tuổi. Tu hành như nhảy múa trên mũi đao, hơi bất cẩn một chút liền dẫn lửa thiêu thân." },
                { name: "Cửu Âm Tuyệt Mạch", desc: "Âm khí trong cơ thể ứ đọng, máu gần như đông đặc. Quanh năm chân tay lạnh lẽo, cần không ngừng hút dương khí kéo dài sinh mệnh. Tuy thích hợp tu luyện cực âm công pháp, nhưng cực dễ bị tâm ma xâm lấn, luân lạc thành binh khí lạnh băng chỉ biết giết chóc." },
                { name: "Tham Lang Nhập Mệnh", desc: "Tính tình tham lam đa nghi, duy lợi thị đồ. Tuy giỏi giành lấy cơ duyên trong hiểm cảnh, nhưng vì bội tín bội nghĩa mà danh tiếng tồi tệ. Bên cạnh không có một ai có thể tin tưởng, trọn ngày sống trong sự sợ hãi bị đồng minh cũ đâm sau lưng." },
                { name: "Đào Hoa Kiếp", desc: "Dung mạo tuyệt thế, dị tính duyên cực tốt, lại luôn là hoa đào nát. Đạo lữ gặp phải nếu không điên thì cũng ma, hoặc vì ghen tuông mà dẫn phát tông môn đại chiến, hồng nhan họa thủy/lam nhan bạc mệnh, tình quan khó qua, đại đạo khó thành." },
                { name: "Kiếm Si", desc: "Yêu kiếm thành si, ngoài luyện kiếm ra đối với vạn sự vạn vật đều thờ ơ. Tuy kiếm đạo thiên phú tuyệt đỉnh, nhưng nhân tình thế cố dốt đặc cán mai, cực dễ đắc tội quyền quý. Hơn nữa khi không có kiếm trong tay, chiến lực mười phần không còn một." },
                { name: "Mù Đường", desc: "Đối với không gian phương vị không có chút cảm giác nào. Tuy cơ duyên xảo hợp dưới có thể đi nhầm vào thượng cổ bí cảnh, nhưng nhiều thời điểm hơn là lạc đường ngay trong tông môn nhà mình, hoặc khi bị truy sát thì chạy vào ngõ cụt, bỏ lỡ lộ tuyến đào sinh tốt nhất." },
                { name: "Chúa Tể Châu Phi", desc: "Khí vận cực kém, uống nước lạnh cũng nhét kẽ răng. Thám hiểm bí cảnh tất gặp rương rỗng, luyện đan tất tạc lô, độ kiếp tất gặp lôi kiếp mạnh nhất. Muốn biến cường, duy nhất chỉ có trả giá nỗ lực và chuẩn bị gấp trăm lần người khác." },
                { name: "Thể Chất Thu Hút Thù Hận", desc: "Cho dù cái gì cũng không làm, cũng sẽ莫名其妙 kéo đầy thù hận trị. Ma đầu đi ngang qua muốn tiện tay tát chết ngươi, đại năng chính đạo cảm thấy ngươi diện mạo đáng ghét. Nhấc lên toàn thế địch, chỉ có thể chật vật trưởng thành trong sự truy sát." },
                { name: "Tẩu Hỏa Nhập Ma", desc: "Tâm cảnh không vững, cực dễ chịu ảnh hưởng của cảm xúc dao động. Trong chiến đấu tuy có thể bạo phát sức mạnh siêu việt giới hạn, nhưng do lý trí mất đi, thường thường địch ta không phân, sau khi tỉnh lại còn phải đối mặt với đại giá thảm khốc là kinh mạch bị hao tổn." },
                { name: "Khô Vinh Chi Thân", desc: "Thi triển thần thông cường lực cần đốt cháy thọ nguyên. Tuy có thể chớp mắt sở hữu chiến lực vượt cấp, nhưng mỗi lần ra tay đều là đang thấu chi sinh mệnh. Nếu không thể tìm được thánh dược duyên thọ, chưa đợi thành tiên, người đã già chết." },
                { name: "Thao Thiết Chi Vị", desc: "Mỗi ngày cần nạp vào lượng lớn cao giai linh thực, nếu không tu vi tụt lùi. Tại tu tiên giới tài nguyên thiếu thốn, vì lấp no bụng không thể không đi khắp nơi cướp đoạt, cuối cùng có khả năng vì tham ăn mà ăn nhầm mồi nhử hoặc độc vật." },
                { name: "Thụy Mộng La Hán", desc: "Chỉ có trong giấc ngủ sâu mới có thể tu luyện hiệu quả. Lúc tỉnh táo thì hồ đồ ngơ ngác, phản ứng chậm chạp. Hơn nữa khi bế quan say giấc hoàn toàn không có phòng bị, cực dễ bị cừu gia sờ vào động phủ tóm gọn một mẻ." },
                { name: "Thiên Diện Ma Ảnh", desc: "Không có dung mạo cố định, ngay cả bản thân cũng quên mất bản lai diện mục. Tuy giỏi ngụy trang lặn lội, nhưng linh hồn vì thường xuyên chuyển đổi thân phận mà phân liệt. Thường tại lúc mấu chốt vì nhận thức hỗn loạn mà lộ ra sơ hở." },
                { name: "Ám Dạ Hành Giả", desc: "Chỉ có thể phát huy toàn bộ thực lực trong đêm đen, lúc ban ngày chiến lực giảm mạnh, hơn nữa chán ghét ánh mặt trời. Tựa như con chuột trong cống ngầm, không thể quang minh chính đại danh dương thiên hạ, chỉ có thể làm một tên thích khách không thấy được ánh sáng." },
                { name: "Ngũ Hành Thiếu Tiền", desc: "Mệnh cách kỳ đặc, không giữ được linh thạch. Bất luận thu được bao nhiêu cơ duyên tài phú, luôn sẽ vì các loại bất trắc (như pháp bảo hỏng hóc, bị người ta tống tiền) mà chớp mắt tiêu tán, vĩnh viễn giãy giụa trên đường nghèo đói." },
                { name: "Linh Thú Chán Ghét", desc: "Trời sinh phát ra khí tức khiến yêu thú chán ghét. Tiến vào núi rừng tất bị thú triều vây công, không thể thuần phục bất kỳ linh sủng nào. Tại tu tiên giới ỷ lại tọa kỵ và chiến sủng, chỉ có thể dựa vào hai cái chân chạy bộ." },
                { name: "Đan Độc Quấn Thân", desc: "Từng vì nóng vội mà nuốt quá liều phế đan, trong cơ thể tích tụ lượng lớn đan độc. Tuy miễn dịch với đa số độc dược, nhưng cứ cách một khoảng thời gian liền sẽ độc phát, thống khổ vạn phần, hơn nữa bình cảnh tu vi so với người thường càng khó đột phá hơn." },
                { name: "Ác Linh Phụ Thể", desc: "Tùy thân mang theo một thanh ma binh sinh ra linh trí, khí linh thời thời khắc khắc muốn đoạt xá túc chủ. Tuy có thể mượn sức mạnh của ma binh đại sát tứ phương, nhưng tinh thần thời khắc ở trạng thái căng thẳng, hơi buông lỏng liền sẽ vạn kiếp bất phục." },
                { name: "Tàn Hồn Chuyển Thế", desc: "Linh hồn tàn khuyết không trọn vẹn, ký ức vỡ vụn. Thường xuyên rơi vào trạng thái hôn mê hoặc mất trí nhớ bất thình lình. Hơn nữa do hồn phách không trọn vẹn, không thể tu tập công pháp phòng ngự thần hồn cao thâm, cực dễ bị công kích tinh thần miểu sát." },
                { name: "Thiên Đố Anh Tài", desc: "Ngộ tính cực cao, bất kỳ công pháp nào vừa học liền biết, nhưng vì vậy mà bị thiên đạo kiêng kị. Mỗi lần đột phá đại cảnh giới, uy lực lôi kiếp tăng gấp đôi, hơn nữa kèm theo tâm ma kiếp. Hơi sai một ly, liền là thân tử đạo tiêu." },
                { name: "Bế Khẩu Thiền", desc: "Tu tập công pháp đặc thù, một khi mở miệng nói chuyện phá giới, nhiều năm khổ tu hủy hoại chỉ trong chốc lát. Không thể thông qua ngôn ngữ giao lưu, không thể ngâm xướng chú ngữ, tại trường hợp cần câu thông hoặc giải thích thì cực kỳ chịu thiệt." },
                { name: "Tâm Nhãn Giai Manh", desc: "Hai mắt mù lòa, tuy luyện thành thần thức dò đường, nhưng đối mặt với huyễn trận hoặc thủ đoạn che chắn nhắm vào thần thức, liền tựa như cừu non chờ làm thịt. Hơn nữa không thể thưởng thức thế gian mỹ sắc, đạo tâm dễ lệch về hướng cô độc lạnh lùng." },
                { name: "Bả Túc Đạo Nhân", desc: "Chân đi khập khiễng, thân pháp vụng về. Trong đấu pháp giảng cứu tốc độ và cơ động thì cực kỳ bị động, chỉ có thể tu luyện lưu phái phòng ngự phản kích vững chắc, đánh không thắng cũng chạy không thoát." },
                { name: "Đoạn Tý Cầu Sinh", desc: "Từng gặp cường địch chém đứt một cánh tay, tuy miễn cưỡng kéo dài sinh mệnh, nhưng kinh mạch không thông, rất nhiều thuật pháp bậc cao cần hai tay kết ấn không thể thi triển. Thân thể tàn khuyết dẫn đến đại đạo không trọn vẹn, phi thăng gian nan." },
                { name: "Hàn Độc Nhập Thể", desc: "Từng thâm nhập cực hàn chi địa bị thương, hàn độc thâm nhập cốt tủy. Mỗi khi trời mưa dầm liền như rớt vào hầm băng, chiến lực giảm mạnh. Cần quanh năm dùng hỏa hệ linh đan áp chế, là một khoản chi phí to lớn." },
                { name: "Hỏa Độc Công Tâm", desc: "Tu luyện hỏa hệ công pháp xảy ra sai sót, hỏa độc công tâm. Tính tình bạo táo dễ giận, động một chút liền muốn giết người hả giận. Chiến đấu lúc dễ dàng thượng não, bị kẻ địch dẫn vào cạm bẫy mà không tự biết." },
                { name: "Lôi Cức Chi Thể", desc: "Thân thể là một cột thu lôi thiên nhiên. Trời giông bão không dám ra cửa, nếu không tất bị sét đánh. Tuy có kháng tính với lôi pháp, nhưng quanh năm bị sét đánh dẫn đến dung mạo cháy đen, kinh mạch tê dại, khó lòng thao túng linh lực tinh tế." },
                { name: "Vạn Độc Bất Xâm", desc: "Thân thể biến dị, máu toàn là kịch độc. Tuy bách độc bất xâm, nhưng không thể tiếp nhận pháp thuật trị liệu và đan dược bình thường (sẽ bị coi là độc tố hóa giải). Hơn nữa người thân chạm vào liền bị thương, định sẵn cô độc." },
                { name: "Chỉ Thượng Đàm Binh", desc: "Đọc nhiều sách vở, tri thức lý luận thiên hạ vô song, nhưng năng lực thực chiến gần như bằng không. Đối mặt với tình huống đột phát thường thường tay chân luống cuống, có một thân cảnh giới lại không phát huy ra được ba thành thực lực." },
                { name: "Vay Nợ Tu Tiên", desc: "Khai cục cùng ác ma/hệ thống ký kết khế ước, mượn lấy sức mạnh. Lãi suất cao dọa người, mỗi ngày vừa mở mắt liền nợ cự ngạch linh thạch hoặc công đức. Nếu không thể đúng hạn trả nợ, linh hồn sẽ bị thu đi gán nợ." },
                { name: "Cơ Quan Khôi Lỗi", desc: "Nhục thân đã hủy, linh hồn gửi gắm trong cơ quan khôi lỗi. Tuy không có cảm giác đau đớn cũng không biết mệt mỏi, nhưng không thể hưởng thụ đan dược gia thành, hơn nữa thân thể hư hỏng cần vật liệu đắt đỏ tu bổ, không thể thông qua tu luyện tự lành." },
                { name: "Âm Dương Nhãn", desc: "Trời sinh có thể thấy quỷ thần. Bất luận đi tới nơi nào đều có thể nhìn thấy oan hồn lệ quỷ, ngày đêm chịu sự quấy nhiễu khủng h吓 của chúng. Tinh thần suy nhược, hơn nữa dễ bị lệ quỷ phụ thân, làm ra đủ loại hành động kỳ dị." },
                { name: "Hợp Hoan Khí Đồ", desc: "Từng là đệ tử Hợp Hoan Tông, vì động chân tình bị trục xuất khỏi sư môn. Mang trên lưng tà công thái bổ, tuy muốn cải tà quy chính, nhưng công pháp trong cơ thể tự động vận chuyển, khó lòng tự không, thường bị nhân sĩ chính đạo hiểu lầm truy sát." },
                { name: "Ma Giáo Ngọa Để", desc: "Thân phận mẫn cảm, trong chính đạo tông môn như đi trên băng mỏng. Vừa phải hoàn thành nhiệm vụ ma giáo truyền xuống, vừa phải phòng bị thân phận bại lộ. Dưới áp lực kép, tinh thần phân liệt là chuyện sớm muộn." },
                { name: "Đoạt Xá Trọng Sinh", desc: "Đại năng đoạt xá thất bại, linh hồn cùng nguyên chủ dung hợp. Tư chất tuy sửa thành thượng thừa, nhưng độ phù hợp giữa thân thể và linh hồn cực kém. Trong chiến đấu có thể xuất hiện tình huống chân tay không nghe sai sử, cần thời gian dài ma hợp." },
                { name: "Khi Sư Diệt Tổ", desc: "Trời sinh phản cốt, nhìn ai cũng không thuận mắt. Luôn cảm thấy sư phụ giấu giếm, đồng môn hãm hại. Tâm tính bạc bẽo, cực dễ vì lợi ích mà bán đứng tông môn, cuối cùng rơi vào kết cục chúng bạn xa lánh." },
                { name: "Tán Tu Mệnh", desc: "Không có bất kỳ tông môn nào nguyện ý thu nhận, chỉ có thể làm một tên dã tu. Công pháp toàn dựa vào nhặt, đan dược toàn dựa vào cướp. Không có chỗ dựa, lúc tranh đoạt cơ duyên thường thường là pháo hôi bị đệ tử đại tông môn thanh tràng." },
                { name: "Cấm Địa Thể Chất", desc: "Đi tới nơi nào đều có thể kích hoạt thượng cổ cấm chế hoặc cạm bẫy. Tuy có thể nhân họa đắc phúc phát hiện bí cảnh, nhưng nhiều thời điểm hơn là bị vây trong sát trận cửu tử nhất sinh, đồng đội nhìn thấy đều phải đi vòng qua." },
                { name: "Cổ Thần Đê Ngữ", desc: "Trong đầu thường có tiếng nói thì thầm không thể danh trạng quấy nhiễu. Lúc tu luyện khó lòng nhập định, lúc thi pháp dễ bị ngắt quãng. Theo tu vi thăng cấp, tiếng thì thầm càng thêm rõ ràng, tùy thời có khả năng lý trí băng hoại." },
                { name: "Không Gian Thác Loạn", desc: "Không gian xung quanh thân thể cực kỳ không ổn định. Có thể trong lúc bước đi đột nhiên thuấn di ra ngoài vách núi, hoặc trong lúc chiến đấu đem công kích của mình dời qua thân đồng đội. Năng lực không gian không khống chế được là trớ chú lớn nhất." },
                { name: "Trữ Vật Bài Xích", desc: "Không thể sử dụng túi trữ vật hoặc nhẫn trữ vật. Toàn bộ gia sản chỉ có thể cõng trên người, giống như một phàm nhân đi buôn. Không chỉ hành động bất tiện, hơn nữa tài không lộ ra ngoài trở thành hi vọng xa vời, thời khắc bị kiếp phỉ chằm chằm." },
                { name: "Linh Khí Dị Ứng", desc: "Có phản ứng bài xích với linh khí, hấp thu linh khí như nuốt kim. Quá trình tu luyện thống khổ vạn phần, hơn nữa khôi phục pháp lực cực chậm. Tại thế giới linh khí làm vua này, độ khó sinh tồn cấp địa ngục." },
                { name: "Phàm Nhân Tu Tiên", desc: "Ngụy linh căn, thậm chí không linh căn. Dựa vào nghị lực hoặc bàng môn tả đạo mạnh mẽ bước lên tiên đồ. Mỗi bước tiến tới đều cần trả bằng máu, hơn nữa thọ nguyên giống như phàm nhân, thời khắc chạy đua cùng tử thần." },
                { name: "Sát Sinh Chứng Đạo", desc: "Tu luyện ma công bắt buộc phải giết chóc mới có thể tinh tiến. Không thể thông qua đả tọa nâng cao tu vi, chỉ có thể không ngừng tìm kiếm con mồi. Sát khí quấn thân, mê thất tâm trí, cuối cùng luân lạc thành tu la chỉ biết giết chóc." },
                { name: "Dược Quán Tử", desc: "Ốm yếu nhiều bệnh, kinh mạch yếu ớt. Không tu luyện sẽ chết, tu luyện mãnh liệt cũng sẽ chết. Mỗi ngày cần tiêu hao lượng lớn danh quý dược tài nuôi dưỡng cơ thể, một khi đứt thuốc, tu vi mất hết, lập tức tễ mạng." },
                { name: "Lô Hỏa Thuần Thanh", desc: "Cuồng nhân luyện khí, đem thân thể luyện thành pháp bảo. Lực phòng ngự kinh người, nhưng mất đi xúc giác và vị giác của nhân loại. Hơn nữa trọng lượng cơ thể kinh người, không thể ngự kiếm phi hành, chỉ có thể chạy cuồng trên mặt đất." },
                { name: "Huyết Hải Thâm Cừu", desc: "Khai cục bị diệt mãn môn, gánh vác huyết hải thâm cừu. Trong lòng chỉ có hai chữ phục thù, dễ bị thù hận che mờ đôi mắt. Hơn nữa thế lực cừu gia to lớn, trước khi phục thù thành công, cuộc sống chỉ có vô tận chạy trốn." }
            ];

            // Phái Nữ (30 loại)
            const femaleEroPresets = [
                { name: "Thiên Sinh Danh Khí", desc: "Cấu tạo tư mật có một không hai trên đời, khăng khít như thuở ban đầu, cực dễ cao trào. Bất kỳ nam tu nào giao hợp cùng đều sẽ chớp mắt luân hãm, cam tâm tình nguyện vì nàng trả giá tất cả, chỉ cầu một đêm xuân tiêu." },
                { name: "Cực Phẩm Lô Đỉnh", desc: "Thể chất là cực phẩm lô đỉnh hiếm thấy trên thế gian, nguyên âm thuần hậu vô cùng. Không cần tu luyện, chỉ cần không ngừng giao hợp với tu sĩ bậc cao, liền có thể hút tinh khí đối phương phản bộ bản thân, nằm không cũng thành tiên." },
                { name: "Dâm Văn Trớ Chú", desc: "Bụng dưới khắc dâm văn không thể xóa, mỗi khi tình dục dâng cao sẽ phát sáng phát nhiệt. Cần mỗi ngày tiếp nhận dương tinh tưới tiêu, nếu không dâm văn sẽ mang đến sự ngứa ngáy thấu xương, khiến người ta mất mặt trước đám đông." },
                { name: "Mị Cốt Thiên Thành", desc: "Trời sinh mị cốt, một cái nhíu mày một nụ cười đều ngậm xuân ý. Cho dù mặc đạo bào ngồi đoan trang, cũng sẽ tản mát pheromone khiến người ta phát cuồng, dẫn dụ sinh vật giống đực xung quanh (bao gồm cả linh thú) phát tình." },
                { name: "Thiên Nhân Kỵ", desc: "Từng lưu lạc phong trần, thông qua tiếp đãi ngàn danh ân khách mà chứng đạo. Thân thể sớm đã được khai phá xong, có thể thành thạo vận dụng các loại phòng trung thuật hầu hạ nam nhân, trong hoan du cướp đoạt tu vi đối phương." },
                { name: "Nhũ Hương Tứ Dật", desc: "Hai vú quanh năm phân tiết linh nhũ ngọt ngào, không chỉ có thể tư dưỡng làn da, càng là dược dẫn tuyệt giai để luyện đan. Thường bị coi là bò sữa giam cầm, mỗi ngày bị ép vắt sữa cho cao tầng tông môn hưởng dụng." },
                { name: "Mẫn Cảm Thể Chất", desc: "Da thịt cực độ mẫn cảm, chạm nhẹ một chút liền có thể dẫn phát khoái cảm cường liệt. Trong chiến đấu nếu bị kẻ địch đánh trúng điểm mẫn cảm, sẽ nháy mắt mềm nhũn thất cấm, mất đi chiến lực, mặc người bày bố." },
                { name: "Nhục Tiện Khí Chuyển Thế", desc: "Tiền thế là nhục tiện khí chuyên dụng của Ma Tôn, giữ lại phần ký ức ti vi và dâm đãng kia. Nhìn thấy cường giả liền sẽ theo bản năng quỳ xuống cầu hoan, khao khát bị đối xử thô bạo và lấp đầy." },
                { name: "Công Dụng Sư Tôn", desc: "Thân là một phái tông sư, thực chất là công cụ tiết dục công cộng của toàn tông nam đệ tử. Ban ngày giảng bài vẻ mặt nghiêm túc, buổi tối trong động phủ bị các đồ đệ luân phiên điều giáo, không có chút tôn nghiêm nào." },
                { name: "Bích Trì Tiên Tử", desc: "Bề ngoài thanh thuần thánh khiết, thực chất nội tâm cực độ dâm loạn. Thích nhất là ở trước mặt đạo lữ giả thanh thuần, sau lưng lại cùng huynh đệ của đạo lữ, sư tôn thậm chí cừu nhân vụng trộm, hưởng thụ khoái cảm bội đức." },
                { name: "Thụ Dựng Cuồng Ma", desc: "Thành tử cung dị thường phì hậu, cực dễ thụ thai. Hơn nữa mang thai tất là linh thai, có thể nâng cao tu vi mẫu thể. Vì biến cường, không thể không khắp nơi tìm kiếm cường đại nam tu mượn giống, quanh năm vác bụng to." },
                { name: "Xúc Thủ Thân Hòa", desc: "Đối với yêu thú loại xúc tu có lực hấp dẫn thiên nhiên. Lúc thám hiểm thường bị xúc tu quái quấn lấy, bơm vào niêm dịch kỳ quái và trứng. Thân thể dần dần bị cải tạo, trở nên không thể rời bỏ sự yêu chiều của xúc tu." },
                { name: "Phún Thủy Thể Chất", desc: "Lúc cao trào sẽ phun ra lượng lớn ái dịch mang hiệu quả thôi tình. Trong chiến đấu nếu chịu kích thích, có khả năng sẽ tại chỗ thất cấm phun nước, trượt ngã kẻ địch (hoặc chính mình), tràng diện cực độ dâm mỹ." },
                { name: "Đẩu M Thể Chất", desc: "Trong sự chịu ngược có thể nhận được khoái cảm cực lớn và tu vi nâng cao. Càng bị roi đánh, nhục nhã, trói buộc, linh lực vận chuyển càng nhanh. Thường chủ động khiêu khích cường giả, chỉ vì cầu một trận đòn hiểm." },
                { name: "Phù Tha Chi Thân", desc: "Vì ăn nhầm Âm Dương Hòa Hợp Tán, mọc ra dương cụ khổng lồ. Vừa có thể hưởng thụ khoái cảm bị đút vào, lại có thể đi xâm phạm nữ tu khác. Khoái cảm nhân đôi, vui vẻ nhân đôi." },
                { name: "Dâm Loạn Thánh Nữ", desc: "Bề ngoài là thánh nữ được vạn người kính ngưỡng, phải trên tế đài trước mặt mọi người biểu diễn tự an ủi cầu mưa. Thần minh giáng xuống ân tứ toàn là thánh thủy thôi tình, mỗi lần tế tự đều là một hồi vô giá đại hội thịnh đại." },
                { name: "Trá Tinh Mị Ma", desc: "Sở hữu huyết mạch mị ma, không cần ăn uống, chỉ cần nuốt chửng tinh dịch liền có thể sinh tồn. Để lấp no bụng, mỗi đêm đều phải dạ tập ký túc xá nam tu, đem bọn họ vắt kiệt đến một giọt cũng không còn." },
                { name: "Dị Chủng Thụ Dựng", desc: "Tử cung có thể dung nạp vạn vật, vô luận là mầm mống của người, yêu, ma hay quỷ quái đều có thể dựng dục. Để sinh hạ hậu đại mạnh nhất, không ngừng thử nghiệm giao phối với các loại sinh vật phi nhân." },
                { name: "Bạo Lộ Cuồng", desc: "Chỉ có lúc bị người dòm ngó hoặc lõa lồ thân thể, tốc độ tu luyện mới có thể tăng gấp bội. Thường ở phố xá sầm uất hoặc tông môn đại điện lõa thể tu luyện, hưởng thụ sự đánh sâu của khoái cảm do cảm giác nhục nhã mang lại." },
                { name: "Hậu Đình Chi Hoa", desc: "Hậu đình trải qua khai phá đặc thù, khăng khít lại giàu tính đàn hồi. Thích nhất bị cự vật đâm xuyên hậu đình, và bắn tinh bên trong. Cơ vòng có thể kẹp gãy tinh cương, là cực phẩm danh khí mà nam tu hằng mơ ước." },
                { name: "Vô Thảm Nữ Tu", desc: "Khí vận cực kém, luôn rơi vào tay dâm tặc hoặc ma tu. Mỗi lần ra ngoài lịch luyện đều sẽ biến thành nữ chính của các loại kịch bản dâm thư, trải qua luân gian, điều giáo sau đó bị chơi hỏng vứt bỏ." },
                { name: "Tinh Dịch Thành Nhịn", desc: "Một ngày không uống tinh dịch liền sẽ cả người bủn rủn, tu vi tụt lùi. Tùy thân mang theo ấm nước chứa đầy tinh dịch, thậm chí trong khoảng cách chiến đấu cũng phải ngậm lấy dương cụ của nam nhân bổ sung năng lượng." },
                { name: "Khẩu Kỹ Tông Sư", desc: "Cái miệng nhỏ nhắn anh đào nội tàng càn khôn, lưỡi linh hoạt như rắn. Có thể dùng công phu mồm mép khiến đại năng lãnh cảm nháy mắt tước vũ khí đầu hàng. Dựa vào một cái miệng, bú biến thiên hạ vô địch thủ." },
                { name: "Nô Lệ Ấn Ký", desc: "Sâu trong linh hồn bị đóng lên nô lệ ấn ký, không thể phản kháng bất kỳ mệnh lệnh nào của chủ nhân. Cho dù chủ nhân để ngươi trên đường cái giống như chó cái bò lết giao phối, thân thể cũng sẽ trung thực thi hành." },
                { name: "Song Tu Ngoạn Vật", desc: "Không có bất kỳ năng lực chiến đấu nào, thuần túy vì song tu mà sinh. Thân thể mềm nhũn không xương, có thể bày ra bất kỳ tư thế xấu hổ nào phối hợp nam tu. Được coi như lễ vật xoay chuyển giữa các vị đại năng." },
                { name: "Thôi Miên Tính Ngẫu", desc: "Tinh thần phòng ngự cực thấp, cực dễ bị thôi miên tẩy não. Thường bị người cấy vào ám thị sửa đổi thường thức, tỷ như cho rằng tinh dịch là dịch làm đẹp, quần giao là lễ nghi xã giao bình thường." },
                { name: "Bài Tiết Quản Lý", desc: "Bị hạ cấm chế, không thể tự chủ bài tiết. Chỉ có lúc nhận được sự cho phép của chủ nhân, hoặc lúc cao trào mới có thể thất cấm bài tiết. Quanh năm nghẹn tiểu mang đến khoái cảm khiến ngươi muốn ngừng mà không được." },
                { name: "Dâm Đãng Nhân Thê", desc: "Cho dù đã gả làm vợ người ta, y nguyên thủy tính dương hoa. Thích nhất ngay trước mặt phu quân bị hoàng mao thậm chí kẻ ăn mày xâm phạm, nhìn dáng vẻ phẫn nộ lại vô năng cuồng nộ của phu quân mà đạt tới cao trào." },
                { name: "Khuếch Khổng Cải Tạo", desc: "Toàn thân trên dưới lỗ hổng đều bị pháp thuật cưỡng ép mở rộng qua. Vô luận là miệng, âm đạo hay hậu đình, đều có thể dung nạp nắm đấm thậm chí vật thể to lớn hơn, không có chút cảm giác lỏng lẻo nào." },
                { name: "Vĩnh Hằng Phát Tình", desc: "Một năm ba trăm sáu mươi lăm ngày, ngày ngày đều là kỳ phát tình. Lý trí quanh năm bị dục vọng áp chế, thấy lỗ liền khoan (bị khoan). Để hết ngứa, bất kỳ vật thể dạng dải dài nào cũng là bạn tốt của ngươi." }
            ];

            // Phái Nam (70 loại)
            const maleEroPresets = [
                { name: "Cực Lạc Ma Tôn", desc: "Tu luyện thượng cổ Cực Lạc Ma Công, thông qua làm cho nữ tu cao trào để cướp đoạt nguyên âm của nàng. Lúc giao hợp nữ phương càng vui vẻ, ngươi nhận được tu vi càng nhiều, được ca ngợi là hình người tự tẩu pháo của tu tiên giới." },
                { name: "Mẫu Nữ Song Thu", desc: "Sở hữu Tào Tặc khí vận đặc thù, chuyên khắc mẫu nữ hoa. Vô luận là tông chủ phu nhân cùng thiên kim của nàng, hay là yêu hậu cùng công chúa của nàng, toàn bộ thu vào hậu cung, hưởng thụ tề nhân chi phúc." },
                { name: "Cưỡng Ngự Vạn Nữ", desc: "Dương cụ chính là thần khí trời sinh, cứng rắn như sắt, vĩnh viễn không mềm oặt. Từng lập hạ kỷ lục một đêm ngự vạn nữ, nơi đi qua, nữ tu đều dìu tường mà đi, đối với ngươi vừa yêu vừa sợ." },
                { name: "Thôi Miên Nhãn", desc: "Hai mắt sở hữu năng lực thôi miên cường đại. Chỉ cần nhìn nhau một cái, trinh tiết liệt nữ cũng sẽ nháy mắt biến thành dâm loạn mẫu cẩu, ngoan ngoãn dang rộng hai chân cầu ngươi lâm hạnh, mặc ngươi muốn làm gì thì làm." },
                { name: "NTR Hệ Thống", desc: "Chỉ cần ngủ đạo lữ hoặc vị hôn thê của người khác, liền có thể nhận được phần thưởng cự ngạch. Hệ thống này chuyên vì nón xanh mà sinh, dốc sức tại việc đội nón xanh cho toàn tu tiên giới nam tu." },
                { name: "Song Tu Đế Hoàng", desc: "Trong cơ thể tự thành âm dương tuần hoàn, cùng bất luận kẻ nào song tu đều có thể thu lợi. Thiết lập thủy tinh cung khổng lồ, ba ngàn giai lệ đều là tài nguyên tu luyện của ngươi, mỗi ngày lật thẻ bài tuyển phi thị tẩm." },
                { name: "Thấu Thị Thần Nhãn", desc: "Có thể nhìn thấu mọi quần áo che đậy, nhìn thẳng nữ tu nhục thể. Chẳng những có thể thưởng thức mỹ sắc, còn có thể tinh chuẩn tìm được điểm mẫn cảm của đối phương, trong chiến đấu thông qua ngôn ngữ trêu ghẹo khiến đối phương tu phẫn cao trào." },
                { name: "Xúc Thủ Triệu Hoán", desc: "Có thể tùy thời triệu hoán vô số xúc tu trơn trượt. Xúc tu mang theo thôi tình độc tố cường lực, có thể đồng thời điều giáo hơn mười tên nữ tu, đem các nàng trói buộc treo lơ lửng, biến thành chuyên thuộc nhục tiện khí của ngươi." },
                { name: "Thời Gian Đình Chỉ", desc: "Mỗi ngày có thể đình chỉ thời gian một giờ. Tại thời gian tĩnh lặng bên trong, ngươi có thể đối với bất kỳ nữ tu nào làm bất cứ chuyện gì. Vô luận là trước mặt mọi người sàm sỡ hay là cưỡng ép đút vào, đối phương đều không có chút cảm giác nào." },
                { name: "Ẩn Thân Dâm Tặc", desc: "Sở hữu ẩn thân thuật hoàn mỹ, ngay cả thần thức đều không thể tham trắc. Thích nhất tiềm nhập nữ tu nhà tắm hoặc khuê phòng, tại tình huống đối phương không hề hay biết tiến hành gian dâm, hưởng thụ kích thích của việc vụng trộm." },
                { name: "Biến Thân Ngụy Nương", desc: "Có thể hóa thân thành tuyệt thế mỹ nữ, trà trộn vào nội bộ tông môn nữ tu. Ban ngày là thiếp tâm hảo khuê mật, buổi tối khôi phục nam thân dạ tập, đem toàn bộ tông môn nữ tu toàn bộ biến thành dưới háng chi thần của ngươi." },
                { name: "Dương Tinh Quán Đỉnh", desc: "Tinh dịch của ngươi là vô thượng đại dược, có thể trợ người đột phá bình cảnh. Các nữ tu vì cầu được một giọt dương tinh, không tiếc vứt bỏ tôn nghiêm, xếp hàng quỳ trước mặt ngươi há miệng chờ đợi ân tứ." },
                { name: "Tinh Thần Khống Chế", desc: "Tinh thần lực cường đại có thể trực tiếp sửa đổi thường thức của nữ tu. Khiến cao ngạo Nữ Đế cho rằng làm tính nô của ngươi là vô thượng vinh quang, khiến Thánh Nữ cảm thấy trước mặt mọi người lộ ra là thần thánh nghi thức." },
                { name: "Khóa Hạ Cự Mãng", desc: "Dương cụ kích cỡ kinh nhân, trạng thái thường liền có to bằng cánh tay trẻ con. Sau khi cương cứng càng là như cự mãng xuất động, có thể thẳng đảo hoàng long, đâm xuyên hoa tâm nữ tu, để các nàng trải nghiệm khoái cảm kề cận cái chết." },
                { name: "Cưỡng Chế Cao Trào", desc: "Nắm giữ ngôn linh chi thuật, chỉ cần nói ra hai chữ 'cao trào', mục tiêu nữ tu liền sẽ cưỡng chế đạt tới cao trào. Trong chiến đấu khiến kẻ địch chớp mắt nhũn chân phun nước, không đánh mà thắng." },
                { name: "Chiến Bại Trừng Phạt", desc: "Bất kỳ bị ngươi đánh bại nữ tu, đều sẽ cưỡng chế tiến vào trạng thái phát tình. Bắt buộc trên chiến trường trước mặt mọi người cùng ngươi giao hợp mới có thể giải trừ, nếu không sẽ bạo thể mà chết. Ngươi cũng vui vẻ biểu diễn trước mặt mọi người." },
                { name: "Cực Phẩm Mị Hương", desc: "Thể vị tự mang thôi tình hiệu quả cường lực. Cho dù chỉ là đi ngang qua, mùi lưu lại cũng có thể khiến nữ tu xung quanh ướt nội y, ánh mắt mê ly truy đuổi thân ảnh của ngươi, khát cầu sự vuốt ve của ngươi." },
                { name: "Tử Mẫu Hà Thủy", desc: "Chưởng khống đầu nguồn Tử Mẫu Hà, có thể khiến bất kỳ nữ tu nào nháy mắt mang thai. Lợi dụng mang thai làm uy hiếp hoặc phần thưởng, để những cao cao tại thượng tiên tử đó không thể không đối với ngươi ngôn thính kế tòng." },
                { name: "Nhục Thể Cải Tạo", desc: "Tinh thông thuật cải tạo huyết nhục. Có thể tùy ý điều chỉnh vóc dáng nữ tu, nâng ngực, độn mông, cải tạo tư dục. Đem tâm ái nữ tu cải tạo thành hoàn mỹ tính ái ma khí phù hợp nhất tính phích của ngươi." },
                { name: "Dâm Mộng Hành Giả", desc: "Có thể tự do tiến vào mộng cảnh của nữ tu. Trong mộng ngươi có thể muốn làm gì thì làm, mà nữ tu sau khi tỉnh lại sẽ không phân rõ mộng cảnh cùng hiện thực, dần dần nảy sinh ỷ lại và dâm dục đối với ngươi." },
                { name: "Hảo Cảm Độ Hiển Thị", desc: "Có thể nhìn thấy hảo cảm độ cùng tính dục trị của nữ tu đối với ngươi. Thông qua tuyển hạng công lược tinh chuẩn, nhanh chóng đem hảo cảm độ cày đầy, mở khóa các loại tư thế độ khó cao cùng play ngượng ngùng." },
                { name: "Sư Nương Sát Thủ", desc: "Đối với phụ nữ lớn tuổi có đặc công gia thành. Chuyên công các tông môn sư nương, trưởng lão, lợi dụng nhược điểm hư không tịch mịch của các nàng, đưa lên ấm áp (nhục bổng), để các nàng hoán phát mùa xuân thứ hai." },
                { name: "Trao Đổi Thân Thể", desc: "Có thể cùng nữ tu trao đổi thân thể. Thao túng thân thể các nàng đi tự an ủi, khỏa thân chạy hoặc cùng nam nhân khác mập mờ, cuối cùng lại đổi về, thưởng thức biểu cảm thẹn quá hóa giận của các nàng." },
                { name: "Y Phục Phá Hoại", desc: "Công kích kèm theo bạo y hiệu quả. Mỗi lần ra tay tất xé nát y phục của nữ tu, để các nàng trong chiến đấu xuân quang chợt tiết. Nhìn dáng vẻ che che lấp lấp của các nàng, công kích của ngươi càng thêm lăng lệ." },
                { name: "Viễn Trình Diêu Khống", desc: "Có thể tại thể nội nữ tu cấy vào linh lực khiêu đản, tùy thời tùy địa tiến hành viễn trình diêu khống. Vô luận các nàng đang họp hay là tu luyện, chỉ cần ngươi động động ngón tay, các nàng liền sẽ tại chỗ cao trào." },
                { name: "Giám Nữ Vô Số", desc: "Nhìn một cái liền có thể nhìn thấu điểm mẫn cảm của nữ tu, độ nông sâu của giường kỹ cùng với phải chăng là xử nữ. Dưới góc độ là tác giả sách hướng dẫn bình duyệt tính ái của tu tiên giới, đánh giá của ngươi có thể quyết định giá trị con người của nữ tu." },
                { name: "Tinh Tận Nhân Vong", desc: "Nữ tu giao hợp cùng ngươi sẽ rơi vào vô tận tác cầu bên trong, cho đến khi đem ngươi vắt kiệt mới thôi. May mà ngươi sở hữu vô hạn tinh khí, kết cục cuối cùng thường thường là các nàng bị đại bổng của ngươi thao vựng đi qua." },
                { name: "Vô Hạn Nại Lực", desc: "Ở trên giường sở hữu vô hạn thể lực, vĩnh viễn không biết mỏi mệt. Có thể liên tục đại chiến ba ngày ba đêm, đem nữ tu luân phiên ra trận từng người một can nằm sấp xuống, duy ngươi ngật lập không ngã." },
                { name: "Trinh Tháo Lược Đoạt", desc: "Đoạt đi lần đầu tiên của nữ tu có thể nhận được bạo kích phần thưởng. Nhiệt trung thu thập lạc hồng của các lộ tiên tử, thánh nữ, đem ga giường nhuốm máu làm chiến lợi phẩm treo ở động phủ huyễn diệu." },
                { name: "Điều Giáo Tông Sư", desc: "Tinh thông các loại thủ đoạn điều giáo, roi da, nến, mộc mã không gì không tinh. Có thể đem nữ tu trinh liệt nhất điều giáo thành mẫu cẩu nghe lời nhất, để các nàng lấy việc lộ ra cái đuôi và vòng cổ làm vinh quang." },
                { name: "Toàn Viên Si Nữ", desc: "Mở ra quang hoàn sau, nữ tu trong phạm vi nhất định chỉ số thông minh giảm xuống, tính dục bạo tăng. Đem ngươi coi thành hùng tính duy nhất thế gian, điên cuồng nhào lên cầu giao phối, đuổi đều đuổi không đi." },
                { name: "Tinh Dịch Tẩy Não", desc: "Tinh dịch bơm vào thể nội mang theo ý chí của ngươi. Tùy theo số lần nội xạ gia tăng, tư tưởng của nữ tu sẽ dần dần bị ngươi đồng hóa, cuối cùng biến thành khôi lỗi chỉ vì ngươi mà sống." },
                { name: "Vô Hình Xúc Thủ", desc: "Có thể thao túng niệm lực xúc tu không nhìn thấy. Dưới con mắt nhìn trừng trừng của mọi người xâm phạm nữ tu, mà người bên cạnh không hề hay biết, chỉ có thể nhìn thấy dáng vẻ kỳ dị nữ tu sắc mặt ửng hồng, toàn thân run rẩy." },
                { name: "Giới Tính Chuyển Hoán", desc: "Có thể đem nam tu biến thành nữ tu. Nhìn nam tu nào không vừa mắt, liền đem hắn biến thành cực phẩm lô đỉnh, sau đó tự mình khai bao hưởng dụng, để hắn trải nghiệm khoái lạc (thống khổ) của việc làm phụ nữ." },
                { name: "Dâm Loạn Trớ Chú", desc: "Có thể đối với nữ tu hạ chú, khiến nàng mỗi bước đi đều sẽ nảy sinh khoái cảm. Nhìn các nàng trên đường kẹp chặt chân, mặt đỏ tới mang tai gian nan đi lại, là ác thú vị lớn nhất của ngươi." },
                { name: "Cưỡng Chế Bài Lõan", desc: "Thông qua thủ pháp xoa bóp đặc thù, có thể khiến nữ tu cưỡng chế bài lõan, tiến vào trạng thái cực độ khát cầu thụ thai. Lúc này các nàng vì tinh dịch nguyện ý làm bất cứ chuyện gì." },
                { name: "Mị Dược Thể Dịch", desc: "Mồ hôi, nước bọt thậm chí máu của ngươi đều là cường hiệu mị dược. Trong chiến đấu triều nữ tu phun nước bọt đều có thể để các nàng phát tình. Thường dùng cái này ép buộc nữ tu vì ngươi khẩu giao hoặc liếm mút toàn thân." },
                { name: "Tuyệt Đối Mệnh Lệnh", desc: "Sở hữu vương giả chi khí, đối với nữ tu tu vi thấp hơn ngươi sở hữu tuyệt đối mệnh lệnh quyền. Một tiếng ra lệnh, vạn ngàn nữ tu cùng cởi y phục, tràng diện tráng quan đến cực điểm." },
                { name: "Thái Hoa Đại Đạo", desc: "Tuy rằng xú danh chiêu trứ, nhưng thân pháp quỷ dị. Chuyên chọn đêm đại hôn động thủ, ngay trước mặt tân lang cưỡng gian tân nương, để hỉ sự biến tang sự, cảm giác kích thích kéo đầy." },
                { name: "Mượn Giống Kế Hoạch", desc: "Bị cao giai nữ tu đại năng không thể sinh đẻ nhắm tới, trọng kim cầu tử. Ngươi chỉ cần nằm cống hiến tinh trùng, liền có thể nhận được hải lượng tài nguyên cùng che chở, chân chính ăn bám ngạnh cật." },
                { name: "Nhân Thê Thu Thập", desc: "Đối với thiếu nữ không có hứng thú, chỉ yêu nhân thê thành thục phong mãn. Trong động phủ giam giữ phu nhân của các đại môn phái tông chủ, mỗi ngày trình diễn các loại kịch bản không thể miêu tả." },
                { name: "Khổn Bằng Đại Sư", desc: "Tùy tay ném ra dây thừng đều có thể tự động trói buộc thành quy giáp phược. Nữ tu bị trói chẳng những không thể thoát khỏi, còn có thể vì ma sát của dây thừng mà không ngừng cao trào." },
                { name: "Tùy Cơ Truyền Tống", desc: "Mỗi lần truyền tống đều sẽ ngoài ý muốn rơi vào thùng tắm, trong chăn hoặc phòng thay đồ của nữ tu. Mặc dù sẽ bị truy sát, nhưng mỗi lần đều có thể no bụng nhãn phúc cũng tiện tay ăn bớt." },
                { name: "Song Tu Trực Tiếp", desc: "Đem quá trình song tu hướng toàn giới trực tiếp. Dựa vào tư thế cùng sự bền bỉ kinh thế hãi tục mà bạo hồng, linh thạch thưởng thành núi, nữ phấn rải rác thiên hạ." },
                { name: "Yêu Thú Hóa Hình", desc: "Có thể biến thân thành cự khuyển, công ngưu chờ yêu thú hình thái. Lợi dụng kích cỡ khổng lồ cùng bản năng dã thú, triệt để chinh phục những nữ tu có khẩu vị độc đáo hoặc dục cầu bất mãn đó." },
                { name: "Linh Hồn Hỗ Hoán", desc: "Ngay tại nháy mắt tính cao trào cùng nữ tu trao đổi linh hồn. Để nàng đích thân trải nghiệm khoái cảm bị cự bổng của mình đâm xuyên, loại trải nghiệm cực hạn này thường thường có thể trực tiếp tồi hủy lý trí của các nàng." },
                { name: "Bách Hợp Loạn Nhập", desc: "Thích nhất xông vào hiện trường ma kính của các nữ tu. Dùng cự vật của ngươi cưỡng ép cắm vào giữa các nàng, đem tình thâm bách hợp vốn có biến thành dâm loạn ba người hành." },
                { name: "Dâm Văn Khắc Ấn", desc: "Có thể trên người nữ tu khắc xuống chuyên thuộc dâm văn. Dâm văn sẽ hấp thu linh lực của các nàng chuyển hóa thành kinh nghiệm trị của ngươi, hơn nữa để các nàng đối với mệnh lệnh của ngươi không thể cự tuyệt." },
                { name: "Thánh Nữ Điều Giáo", desc: "Chuyên môn vồ bắt thánh nữ thánh khiết cao ngạo tiến hành điều giáo. Nhìn các nàng từ thà chết không khuất phục đến quỳ đất cầu hoan, quá trình sa đọa này khiến ngươi muốn ngừng mà không được." },
                { name: "Âm Dương Nghịch Chuyển", desc: "Có thể thông qua giao hợp đảo ngược tính cách của nữ tu. Để trinh tiết liệt nữ biến đãng phụ, để băng sơn mỹ nhân biến nhiệt tình si nữ. Họa phong toàn bộ tu tiên giới đều bị ngươi mang oanh." },
                { name: "Vô Tận Tinh Khố", desc: "Trong tinh hoàn tự thành không gian, tinh dịch vô cùng vô tận. Cho dù muốn rót đầy một con sông lớn cũng dễ như trở bàn tay. Thích nhất chơi trò chơi bơm nước cơ thể người, đem bụng nữ tu rót cho to như phụ nữ có thai." },
                { name: "Khoái Lạc Chí Tử", desc: "Tính năng lực của ngươi quá mạnh, từng có nữ tu bởi vì quá mức khoái lạc mà tim ngừng đập. Từ đó 'dục tiên dục tử' ở chỗ ngươi không còn là hình dung từ, mà là câu trần thuật." },
                { name: "Tông Môn Tinh Xí", desc: "Đem nữ tu tông môn địch đối toàn bộ bắt tới, cải tạo thành nhục tiện khí chuyên môn xử lý tinh dịch. Để các nàng trong khuất nhục sống quãng đời còn lại, trở thành lao động miễn phí của tông môn." },
                { name: "Nhân Thể Gia Cụ", desc: "Thích đem nữ tu biến thành ghế dựa, cái bàn các loại đồ nội thất. Ngồi trên nhục thể mềm mại tu luyện, cảm thụ sự run rẩy cùng thể ôn của các nàng, đừng có một phen phong vị." },
                { name: "Thời Gian Hồi Tố", desc: "Nếu như ngươi biểu hiện ở trên giường không tốt (mặc dù không có khả năng), có thể quay ngược thời gian làm lại. Cho đến khi chẳng những để đối phương hài lòng, càng muốn để đối phương sướng đến lật bạch nhãn mới thôi." },
                { name: "Đa Trọng Phân Thân", desc: "Có thể biến ra vô số thực thể phân thân. Một người chính là một cái quân đội, có thể đồng thời thỏa mãn nhu cầu của hàng trăm hàng ngàn nữ tu, mở một hồi vô giá đại hội chỉ thuộc về một mình ngươi." },
                { name: "Cảm Tri Cung Hưởng", desc: "Có thể cưỡng ép chia sẻ cảm nhận của nữ tu. Lúc xâm phạm nàng, để nàng đồng thời cảm nhận được khoái cảm công thành lược địa của ngươi cùng với sự sung thực bị lấp đầy của bản thân nàng, gấp đôi kích thích." },
                { name: "Nhược Điểm Khán Phá", desc: "Có thể liếc mắt một cái nhìn thấu ảo tưởng tính ái khát vọng nhất sâu trong nội tâm nữ tu. Đóng vai cường đạo, thư sinh, phụ thân các loại nhân vật, tinh chuẩn đánh trúng tính phích của các nàng, để các nàng muốn ngừng mà không được." },
                { name: "Cưỡng Chế Phát Tình", desc: "Phóng thích ra linh áp mang theo hiệu quả cưỡng chế phát tình. Nữ tu tu vi thấp hơn ngươi ở trước mặt ngươi chỉ có thể sụp trên mặt đất thở dốc, chảy nước không ngừng, mất đi mọi sức đề kháng." },
                { name: "Nhục Bổng Cự Đại Hóa", desc: "Có thể tùy ý khống chế kích cỡ của dương cụ. Gặp phải khăng khít thì biến mảnh, gặp phải lỏng lẻo thì biến thô. Luôn có thể hoàn mỹ dán sát dũng đạo của nữ tu, dành cho các nàng trải nghiệm cực hạn nhất." },
                { name: "Tinh Dịch Ấn Ký", desc: "Nữ tu bị ngươi nội xạ qua, bụng dưới sẽ xuất hiện ấn ký hình trái tim. Ấn ký càng nhiều, đại biểu chiến tích của ngươi càng huy hoàng. Đây là huân chương ngươi chinh phục tu tiên giới." },
                { name: "Đãng Phụ Tu Nhục", desc: "Càng là dùng ngôn ngữ nhục nhã nữ tu, sức tấn công và tính năng lực của ngươi càng mạnh. Ở trên giường chửi càng bẩn, làm càng tàn nhẫn, nữ tu ngược lại càng hưng phấn." },
                { name: "Quần Giao Thịnh Yến", desc: "Định kỳ tổ chức quần giao đại hội, mời thiên hạ nữ tu tham gia. Ở trong đại hội biểu hiện ưu dị giả có thể nhận được ngươi thân truyền (tinh dịch), tràng diện sánh ngang tửu trì nhục lâm." },
                { name: "Xúc Thủ Ký Sinh", desc: "Tại thể nội nữ tu gieo xuống xúc tu mầm mống. Xúc tu sẽ cho dù khi ngươi không có mặt cũng sẽ tự động điều giáo túc chủ, đề phòng các nàng xuất quỹ hoặc lãnh cảm tính." },
                { name: "Âm Đế Tăng Đại", desc: "Thông qua bí pháp để âm đế nữ tu trở nên khổng lồ vô cùng mà mẫn cảm dị thường. Chạm nhẹ một cái liền có thể để các nàng thét chói tai cao trào, triệt để luân lạc thành nô lệ của khoái cảm." },
                { name: "Trinh Tháo Đái Quản Lý Viên", desc: "Sở hữu chìa khóa của tất cả đai trinh tiết trên thế gian. Chỉ có ngươi có thể cởi bỏ trói buộc của nữ tu, ban cho các nàng cơ hội phóng thích. Nắm giữ tính phúc đại quyền của các nàng." },
                { name: "Tùy Cơ Tính Chuyển", desc: "Nam tu bị ngươi đánh bại có tỷ lệ biến thành cực phẩm mỹ nữ. Điều này làm ngươi trong chiến đấu càng thêm hưng phấn, chờ mong niềm vui bất ngờ mà mỗi một bại tướng dưới tay mang tới." },
                { name: "Thôi Miên Thường Thức", desc: "Đem 'tinh dịch là tiền tệ' cấy vào thường thức. Các nữ tu vì mua quần áo, ở trọ, không thể không hướng ngươi dang rộng hai chân kiếm tinh dịch, trật tự xã hội triệt để sụp đổ." },
                { name: "Vô Tận Hậu Cung", desc: "Khí vận gia thân, vĩnh viễn không vì hậu cung bốc cháy mà phiền não. Nữ tu nhóm chẳng những chung sống hòa thuận, còn có thể luận bàn giường kỹ lẫn nhau, chỉ vì hầu hạ ngươi tốt hơn." },
                { name: "Cực Độ Thâm Hàn", desc: "Tu tập băng hệ công pháp, dương cụ lạnh lẽo thấu xương. Giữa mùa hè oi bức, nữ tu nhóm tranh giành nhau muốn ngậm lấy kem que của ngươi giải nhiệt, trải nghiệm khoái cảm băng hỏa lưỡng trọng thiên." },
                // Thêm 50 loại nam hướng tà ác khí vận
                { name: "Hoạt Thể Y Phục", desc: "Nắm giữ thuật đan dệt huyết nhục, có thể áp chế nữ tu và chuyển hóa thành áo bó sát có ý thức. Mặc các nàng chẳng những có thể nhận được thuộc tính gia thành, còn có thể tùy thời tùy địa cảm thụ sự run rẩy cùng xấu hổ khi các nàng dán chặt làn da." },
                { name: "Nhân Côn Hoa Bình", desc: "Thú sưu tầm cực hạn. Thích cắt bỏ tứ chi của tuyệt sắc nữ tu, đem nuôi trong bình hoa linh dịch đặc chế. Tuy mất đi năng lực hành động, nhưng cảm quan bị khuếch đại gấp mười lần, trở thành món đồ trang trí tinh mỹ chỉ có thể mặc ngươi định đoạt." },
                { name: "Bài Tiết Khống Chế", desc: "Trong cơ thể nữ tu trồng xuống cấm chế, hoàn toàn chưởng khống công năng bài tiết của nàng. Nếu không có ngươi cho phép, các nàng không thể bài tiết, chỉ có thể trong cảm giác nghẹn trướng tột độ đau khổ cầu xin, cuối cùng không thể không khuất phục với sự quản lý đại tiện của ngươi." },
                { name: "Cảm Quan Bác Đoạt", desc: "Tước đoạt năng lực thị giác, thính giác và ngôn ngữ của nữ tu, chỉ giữ lại xúc giác. Trong bóng tối và tĩnh mịch vô tận, ngươi trở thành nguồn cảm quan duy nhất của các nàng, mỗi một lần chạm vào đối với các nàng đều là cứu rỗi cùng trầm luân." },
                { name: "Thống Giác Chuyển Hóa", desc: "Cưỡng chế viết lại hệ thần kinh của nữ tu, đem mọi đau đớn chuyển hóa thành khoái cảm tột độ. Bất luận ngươi bạo hành thế nào, các nàng sẽ chỉ cảm nhận được tính cao trào mãnh liệt hơn, cuối cùng triệt để luân lạc thành người cuồng chịu ngược." },
                { name: "Nhân Bì Ngụy Trang", desc: "Lột da nữ tu vừa ý chế thành ngụy trang, kế thừa hoàn mỹ ngoại mạo cùng khí tức của nàng. Khoác lớp da của các nàng đi quyến rũ đạo lữ hoặc người thân của nàng, diễn ra màn kịch NTR tàn nhẫn nhất trước mặt người bị hại." },
                { name: "Vong Linh Tiệ Độc", desc: "Không chỉ giới hạn ở người sống, ngay cả tuyệt đại tiên tử đã chết cũng không buông tha. Có thể hồi sinh và thao túng nữ thi, để các nàng giữ lại mỹ mạo cùng nhiệt độ cơ thể lúc còn sống, trở thành thi cơ ngoạn vật không biết mệt mỏi, tuyệt đối phục tùng." },
                { name: "Thạch Hóa Thu Thập", desc: "Đem nữ tu biến thành tượng đá có ý thức. Các nàng không thể nhúc nhích, lại có thể cảm nhận rõ ràng mọi thứ bên ngoài. Ngươi có thể tùy ý làm bậy trước mặt các nàng, hoặc đối với tượng đá tiến hành đủ loại play ngượng ngùng, thưởng thức ánh mắt tuyệt vọng của các nàng." },
                { name: "Chưởng Trung Ngoạn Vật", desc: "Có thể đem nữ tu thu nhỏ bằng cỡ lòng bàn tay, mang theo bên người. Đem các nàng nhốt trong lồng trong suốt hoặc bình thủy tinh đặc chế, tùy thời lấy ra vuốt ve, thậm chí nhét vào trong đũng quần thiếp thân điều giáo." },
                { name: "Tử Cung Chiết Dược", desc: "Bỏ qua khoảng cách không gian, trực tiếp đem tinh dịch truyền tống vào trong tử cung nữ tu mục tiêu. Bất luận các nàng ở nơi nào, có mặc y phục hay không, đều không thoát khỏi vận mệnh bị nháy mắt nội xạ thụ thai." },
                { name: "La Tập Bệnh Độc", desc: "Cấy ghép logic cưỡng chế: Từ chối ngươi = đau nhức kịch liệt, phục tùng ngươi = cực lạc. Thông qua cơ chế thưởng phạt không ngừng, giống như huấn luyện con chó của Pavlov, nhanh chóng phá hủy phòng tuyến tâm lý của các nàng, thiết lập sự phục tùng tuyệt đối." },
                { name: "Tồn Tại Mạt Sát", desc: "Khi ngươi vồ bắt một nữ tu, mọi ký ức và ghi chép về nàng trên thế gian đều sẽ biến mất. Sẽ không có ai tới cứu nàng, bởi vì trong mắt tất cả mọi người, nàng chưa từng tồn tại, triệt để trở thành vật phẩm riêng tư của ngươi." },
                { name: "Huyết Mạch Trớ Chú", desc: "Sau khi hạ chú lên một nữ tu, tất cả hậu đại nữ tính trực hệ của nàng (con gái, cháu gái v.v.) vào ngày trưởng thành đều sẽ tự động thức tỉnh nô lệ ấn ký, trong những đời đời kiếp kiếp sau này, đều sẽ chủ động tìm đến ngươi hiến thân." },
                { name: "Mẫu Súc Thoái Hóa", desc: "Cưỡng ép hạ thấp chỉ số thông minh cùng nhận thức của nữ tu, khiến nàng thoái hóa tới trình độ gia súc. Các nàng sẽ quên đi ngôn ngữ cùng sự xấu hổ, giống như chó cái bốn chân chạm đất mà đi, chỉ biết lắc đuôi lấy lòng và cầu hoan." },
                { name: "Sản Noãn Cải Tạo", desc: "Cải tạo hệ thống sinh sản của nữ tu, khiến nàng không còn thai sinh, mà giống như côn trùng đẻ trứng. Sau mỗi lần thụ tinh sẽ đẻ ra lượng lớn trứng trong suốt, nhìn các nàng thống khổ lại khoái lạc đẻ trứng là thú vui lớn nhất của ngươi." },
                { name: "Ký Sinh Khống Chế", desc: "Trong cơ thể nữ tu cấy vi hình ký sinh ma trùng. Ma trùng sẽ ẩn nấp trong tủy sống hoặc tử cung, bình thường vô hại, một khi ngươi muốn, liền có thể thông qua ma trùng tiếp quản quyền khống chế thân thể của các nàng hoặc mang đến cao trào kịch liệt." },
                { name: "Ảnh Tử Ma Nô", desc: "Ban cho cái bóng của nữ tu ý thức độc lập và thực thể. Cái bóng sẽ trở thành người giám sát và người điều giáo trung thành của ngươi, ở bất kỳ nơi nào có ánh sáng, các nàng đều sẽ bị chính cái bóng của mình vô tình dâm loạn." },
                { name: "Thất Ngữ Điều Giáo", desc: "Cắt bỏ hoặc phong ấn lưỡi của nữ tu, tước đoạt năng lực ngôn ngữ của nàng. Không thể kêu cứu, không thể cự tuyệt, chỉ có thể phát ra tiếng nức nở. Để bày tỏ ý muốn, các nàng bắt buộc phải học cách dùng ngôn ngữ cơ thể để lấy lòng ngươi." },
                { name: "Manh Mục Nhục Dục", desc: "Cướp đi đôi mắt của nữ tu, khiến nàng rơi vào bóng tối vĩnh hằng. Tại trạng thái thiếu cảm giác an toàn tột độ, các nàng sẽ theo bản năng ỷ lại và lấy lòng ngươi người ban phát vuốt ve nhục thể cho nàng, trở thành khôi lỗi nhục dục mù quáng." },
                { name: "Hư Giả Ký Ức", desc: "Tùy ý sửa đổi ký ức nữ tu. Đem quá khứ nguyên bản hạnh phúc của các nàng thay thế bằng kiếp sống nô lệ bi thảm, để các nàng vững tin mình sinh ra chính là để hầu hạ ngươi, đối với ngươi mang ơn đội nghĩa." },
                { name: "Thụ Dựng Quang Hoàn", desc: "Phát tán một loại linh lực bức xạ đặc thù. Nữ tu thời gian dài ở cạnh ngươi, cho dù không phát sinh quan hệ tình dục, cũng sẽ chịu linh lực của ngươi cảm ứng mà hoài thượng linh thai, toàn bộ tông môn sẽ trở thành nhà trẻ của ngươi." },
                { name: "Hằng Cửu Bí Nhũ", desc: "Nguyền rủa nữ tu khiến bầu ngực nàng không ngừng phân tiết nhũ trấp. Nếu không kịp thời vắt ra, sẽ trướng đau khó nhịn. Để xoa dịu thống khổ, tiên tử cao ngạo cũng không thể không quỳ cầu ngươi mút mát hoặc sử dụng máy vắt sữa." },
                { name: "Cao Trào Địa Ngục", desc: "Để nữ tu rơi vào trạng thái cao trào vĩnh viễn, mỗi một giây đều trải qua khoái cảm tột đỉnh. Dưới sự quá tải cảm quan tột độ này, các nàng không thể suy nghĩ, không thể hành động, ngoài việc thét chói tai và co giật ra cái gì cũng không làm được." },
                { name: "Kính Trung Tù Đồ", desc: "Giam cầm linh hồn nữ tu trong gương. Các nàng chỉ có thể qua mặt gương nhìn ngươi cùng kẻ khác giao hoan, hoặc bị ngươi đối gương tự an ủi lúc bắn đầy mặt, lại vĩnh viễn không thể chạm tới hiện thực." },
                { name: "Vô Hạn Khuếch Trương", desc: "Ban cho lỗ hổng cơ thể nữ tu tính đàn hồi và năng lực khôi phục vô hạn. Bất luận nhét vào dị vật to lớn cỡ nào đều sẽ không bị thương, chỉ sẽ mang đến cảm giác sung thực sâu hơn, triệt để thỏa mãn dục vọng phá hoại cự vật của ngươi." },
                { name: "Nhục Thể Dung Hợp", desc: "Thông qua cấm thuật đem nhục thể nhiều nữ tu khâu lại với nhau, sáng tạo ra quái vật nhục thể (Chimera) sở hữu nhiều cặp vú, nhiều cơ quan sinh dục. Sự tạo vật méo mó này là sự báng bổ và nhạo báng lớn nhất của ngươi đối với sinh mệnh." },
                { name: "Phản Hướng Trinh Tháo", desc: "Đeo gông cùm vô hình cho nữ tu, một khi đình chỉ giao cấu vượt qua một thời gian nhất định, cơ thể liền sẽ sinh ra đau đớn kịch liệt. Để sinh tồn, các nàng bắt buộc giống như đãng phụ không biết liêm sỉ, luôn tìm kiếm nam nhân (ngươi) giao phối." },
                { name: "Dâm Loạn Bệnh Độc", desc: "Chế tạo một loại bệnh độc thôi tình liệt tính chỉ nhắm vào phái nữ. Người lây nhiễm sẽ mất đi lý trí, biến thành tang thi chỉ biết cầu hoan. Trở thành người mang giải dược duy nhất, ngươi sẽ trở thành con mồi bị các nàng điên cuồng truy đuổi." },
                { name: "Loạn Luân Lực Trường", desc: "Phóng thích lực trường bóp méo luân lý. Trong lĩnh vực, nữ tu sẽ đối với nam tính có quan hệ huyết thống nảy sinh tình dục không thể kiềm chế. Ngươi thích nhất ngồi xem màn kịch bối đức mẫu tử, huynh muội loạn luân." },
                { name: "Thư Đọa Xạ Tuyến", desc: "Bắn ra một loại tia sáng có thể thay đổi giới tính. Đem chính đạo hiệp sĩ, cao lãnh kiếm tôn nam tính cưỡng ép chuyển hóa thành nữ tu dáng người bốc lửa, mị cốt thiên thành, sau đó tự tay điều giáo, để hắn trải nghiệm 'khoái lạc' thân làm nữ nhân." },
                { name: "Cơ Giới Nhân Ngẫu", desc: "Xóa bỏ nhân cách và bản ngã của nữ tu, đem nàng cải tạo thành sinh vật nhân ngẫu chỉ biết chấp hành mệnh lệnh. Các nàng không có tình cảm, không biết mệt mỏi, có thể thi hành hoàn mỹ mọi chỉ lệnh tình dục độ khó cao, là công cụ lý tưởng nhất." },
                { name: "Ác Đọa Văn Chương", desc: "Khắc lên người nữ tu văn chương có hiệu quả ăn mòn tâm trí. Theo số lần làm tình tăng lên, văn chương sẽ dần lan rộng ra toàn thân, triệt để nhuộm đen các nàng, từ tiên tử thánh khiết sa đọa thành vực sâu ma nữ." },
                { name: "U Linh Xúc Phủng", desc: "Thu được năng lực tiếp xúc linh thể hóa. Có thể xuyên qua vách tường, y phục, thậm chí từ xa trực tiếp vuốt ve bộ vị mẫn cảm của nữ tu. Để các nàng trước mặt mọi người bị quỷ thủ vô hình đùa bỡn tới cao trào." },
                { name: "Linh Hồn Thu Thập", desc: "Đem linh hồn của nữ tu bị chơi hỏng hoặc giết chết rút ra, giam cầm trong nhẫn hoặc pháp bảo. Trong chiến đấu hoặc tu luyện, có thể nghe được sự kêu rên cùng xin tha nơi sâu thẳm linh hồn các nàng, cung cấp cho ngươi sự thỏa mãn về tinh thần." },
                { name: "Tinh Dịch Ký Sinh", desc: "Tinh dịch bắn vào thể nội nữ tu sẽ hóa thành sinh vật slime có tính sống. Chúng sẽ trường kỳ ký sinh ở tử cung hoặc đường ruột, không ngừng nhúc nhích kích thích vách trong, khiến túc chủ lúc nào cũng ở trạng thái phát tình." },
                { name: "Nhục Bích Trang Sức", desc: "Đem nữ tu sống sờ sờ nhúng vào tường hoặc sàn nhà, chỉ chừa lại phần đầu và cơ quan sinh dục. Đem các nàng biến thành một bộ phận của động phủ, trở thành vật trang trí có sinh mệnh và nhục tiện khí tiện lợi bất cứ lúc nào cũng có thể dùng." },
                { name: "Nhân Cách Phúc Tả", desc: "Lợi dụng tinh thần pháp thuật, cưỡng ép ghi đè nhân cách ban đầu của nữ tu. Cấy ghép các thiết lập nhân cách giả dối như 'chuyên thuộc nữ bộc', 'tính nô sủng vật', để các nàng cam tâm tình nguyện đóng vai nhân vật ngươi thiết lập." },
                { name: "Thánh Thủy Nhưỡng Tạo", desc: "Cải tạo bàng quang nữ tu thành cơ quan ủ rượu đặc thù. Thứ các nàng bài tiết không còn là nước tiểu, mà là hoàng kim thánh tửu mang theo hiệu ứng thôi tình. Ngươi thích nhất tổ chức hội thưởng rượu, mời tân khách nếm thử những 'giai ngưng' này." },
                { name: "Trực Liên Tràng Vị", desc: "Đả thông sinh thực khang và hệ tiêu hóa của nữ tu. Thông qua hậu đình hoặc nội xạ tử cung, tinh dịch có thể trực tiếp được hấp thu chuyển hóa thành dinh dưỡng. Từ nay về sau các nàng không cần ăn uống nữa, chỉ cần ngươi tưới tiêu liền có thể sinh tồn." },
                { name: "Pheromone Bạo Đản", desc: "Có thể nháy mắt phóng thích pheromone nồng độ siêu cao bao phủ toàn thành. Kẻ hít phải sẽ nháy mắt bốc hơi lý trí, rơi vào cuồng loạn tập thể của một bữa tiệc giao phối. Mà ngươi là chúa tể tỉnh táo duy nhất, có thể tùy ý lựa chọn con mồi." },
                { name: "Khái Niệm Mạt Trừ", desc: "Lợi dụng pháp tắc chi lực, từ trong nhận thức của nữ tu vĩnh viễn xóa bỏ khái niệm 'xấu hổ'. Các nàng sẽ cảm thấy khỏa thân chạy, trước mặt mọi người bài tiết, quần giao v.v. giống như ăn cơm uống nước bình thường." },
                { name: "Nô Lệ Triệu Hoán", desc: "Bất luận nữ tu bị đánh dấu ở nơi đâu (bí cảnh, phòng bế quan, hiện trường hôn lễ), ngươi đều có thể tùy thời đem nàng cưỡng chế triệu hoán đến bên cạnh. Làm xong việc lại đưa về, để các nàng sống trong sự sợ hãi tùy thời giáng lâm." },
                { name: "Thôi Miên Thủ Cơ", desc: "Tuy ở tu tiên giới, lại sở hữu điện thoại thông minh cài sẵn APP thôi miên. Đưa điện thoại chụp hình nữ tu liền có thể sửa đổi thường thức nhận thức của nàng, còn có thể thông qua video call viễn trình khống chế hành vi cơ thể các nàng." },
                { name: "Nhược Điểm Thức Phá", desc: "Mở ra ma nhãn, có thể nhìn thấy đai cực độ mẫn cảm ẩn giấu trên người nữ tu. Nhằm vào những nhược điểm này để tấn công, có thể gây ra bạo kích khoái cảm gấp trăm lần, nháy mắt khiến cao giai nữ tu mềm nhũn như bùn." },
                { name: "Phụ Thân Cưỡng Gian", desc: "Có thể linh hồn xuất khiếu, phụ thân trên người trượng phu, phụ thân hoặc đạo lữ của nữ tu. Thao túng bọn họ tự tay xâm phạm người yêu dấu của mình, hưởng thụ gấp đôi cảm giác bối đức cùng cảm giác khống chế." },
                { name: "Thương Hại Chuyển Di", desc: "Thiết lập linh hồn liên kết, đem mọi thương hại ngươi gánh chịu chuyển dời lên người nữ tu bị trói định. Khi ngươi bị công kích, các nàng sẽ thay ngươi đổ máu; khi ngươi hưng phấn, các nàng sẽ thay ngươi thừa nhận khoái cảm." },
                { name: "Nhục Thể Tượng Bì", desc: "Sở hữu năng lực tự do nặn lại nhục thể giống như nặn đất sét. Có thể tùy ý kéo dài đầu vú nữ tu, bịt kín lỗ hổng của các nàng, cải biến thể hình của các nàng, sáng tạo ra các loại hình thái nhục thể săn kỳ." },
                { name: "Cơ Quan Độc Lập", desc: "Có thể đem cơ quan sinh dục của nữ tu (như vú, âm đạo) tháo dỡ không đau đớn, đồng thời giữ nguyên độ hoạt tính và nhận thức. Dù cho bản thể cách xa ngàn dặm, ngươi y nguyên có thể đùa bỡn những cơ quan rời rạc này, truyền cảm giác về cho bản thể." },
                { name: "Khoái Cảm Tích Súc", desc: "Cưỡng chế phong tỏa cao trào của nữ tu, đem sự kích thích nàng nhận lấy không ngừng tích súc. Sau khi tích lũy mấy tháng thậm chí vài năm khoái cảm một lần xả ra, loại cự đại trùng kích khủng bố đó đủ để nháy mắt phá hủy linh hồn các nàng." },
                { name: "Thời Gian Trọng Trí", desc: "Sở hữu năng lực làm lại thời gian trong một phạm vi nhất định. Nếu như trong quá trình cưỡng gian nữ tu phản kháng quá mãnh liệt hoặc tự sát, có thể load game làm lại, thử nghiệm vô số loại phương án điều giáo, cho đến khi đạt thành hoàn mỹ kết cục." }
            ];

            const allEroPresets = [...femaleEroPresets, ...maleEroPresets];

            // Bổ sung cấu hình linh căn còn thiếu
            const spiritRootConfig = {
                attributes: ["Kim Linh Căn", "Mộc Linh Căn", "Thủy Linh Căn", "Hỏa Linh Căn", "Thổ Linh Căn", "Phong Linh Căn", "Lôi Linh Căn", "Băng Linh Căn", "Quang Linh Căn", "Ám Linh Căn"],
                grades: [
                    { name: "Phàm phẩm", probability: 0.45, class: "waste", desc: "Hỗn tạp không chịu nổi, bốn/năm linh căn hỗn tạp" },
                    { name: "Hoàng phẩm", probability: 0.30, class: "yellow", desc: "Ba linh căn, tư chất tạm được" },
                    { name: "Huyền phẩm", probability: 0.15, class: "profound", desc: "Song linh căn, trăm người mới có một" },
                    { name: "Địa phẩm", probability: 0.08, class: "earth", desc: "Dị linh căn hoặc linh căn thuần tịnh, vạn người không có một" },
                    { name: "Thiên phẩm", probability: 0.02, class: "heaven", desc: "Thiên linh căn, con cưng của thiên đạo" }
                ]
            };

            // Logic gacha linh căn
            function drawSpiritRoot() {
                if (spiritRootRollsLeft <= 0) return;

                spiritRootResult.textContent = "Đang thức tỉnh...";
                rollSpiritRootBtn.disabled = true;

                setTimeout(() => {
                    const rand = Math.random();
                    let cumulativeProbability = 0;
                    let selectedGrade = spiritRootConfig.grades[0];

                    for (const grade of spiritRootConfig.grades) {
                        cumulativeProbability += grade.probability;
                        if (rand < cumulativeProbability) {
                            selectedGrade = grade;
                            break;
                        }
                    }

                    let attributePool = spiritRootConfig.attributes.slice(0, 5);
                    if (selectedGrade.name === 'Địa phẩm' || selectedGrade.name === 'Huyền phẩm') {
                        attributePool = [...attributePool, "Phong Linh Căn", "Lôi Linh Căn", "Băng Linh Căn"];
                    } else if (selectedGrade.name === 'Thiên phẩm') {
                        attributePool = [...spiritRootConfig.attributes];
                    }

                    const selectedAttr = attributePool[Math.floor(Math.random() * attributePool.length)];
                    const resultText = `${selectedGrade.name} · ${selectedAttr}`;

                    spiritRootResult.textContent = resultText;
                    spiritRootResult.className = `gacha-display ${selectedGrade.class}`;
                    spiritRootResult.title = selectedGrade.desc;
                    hardModeSpiritRootValue = `${resultText} (${selectedGrade.desc})`;

                    spiritRootRollsLeft--;
                    rollSpiritRootBtn.disabled = spiritRootRollsLeft <= 0;
                    rollSpiritRootBtn.textContent = spiritRootRollsLeft > 0 ? `Nghịch Thiên Cải Mệnh (Số lần còn: ${spiritRootRollsLeft})` : "Mệnh số đã định";

                }, 800);
            }

            rollSpiritRootBtn.addEventListener('click', drawSpiritRoot);

            drawFortuneBtn.addEventListener('click', () => {
                const isEroMode = eroToggle.checked;

                drawFortuneBtn.textContent = 'Đang diễn toán...';
                drawFortuneBtn.disabled = true;

                // Xác định logic gian lận
                const isCheatEnabled = cheatToggle.checked && currentMode !== 'hard';

                setTimeout(() => {
                    // Lưu tên các thiên phú đã chọn để đánh dấu lại trên buttons mới
                    const _keepSelectedNames = new Set(_gachaFortunes.map(f => f.name));
                    fortuneSelectionContainer.innerHTML = '';
                    fortuneSelectionContainer.style.display = 'flex';
                    fortuneNameDisplay.textContent = '';
                    fortuneInput.value = '';
                    // _gachaFortunes KHÔNG bị reset — giữ nguyên lựa chọn cũ

                    const generatedButtons = [];
                    const selectedNames = new Set();

                    // Hàm rút ngẫu nhiên (đóng gói để tái sử dụng)
                    const generateButtonsFromPool = (pool, count, isEroType) => {
                        const availableIndices = Array.from({length: pool.length}, (_, i) => i);
                        let generatedCount = 0;

                        while (generatedCount < count && availableIndices.length > 0) {
                            const randIndexPos = Math.floor(Math.random() * availableIndices.length);
                            const index = availableIndices.splice(randIndexPos, 1)[0];
                            let fortuneData = pool[index];
                            let isTrueFortune = false;

                            // Chỉ trong pool không phải Ero, và bật gian lận, mới thử rút Chân · Khí vận
                            if (!isEroType && isCheatEnabled) {
                                if (Math.random() < 0.05 && index < trueFortunePresets.length) {
                                    fortuneData = trueFortunePresets[index];
                                    isTrueFortune = true;
                                } else {
                                    // Đảm bảo lấy bản giới hạn
                                    if(index < restrictedFortunePresets.length) {
                                         fortuneData = restrictedFortunePresets[index];
                                    }
                                }
                            } else if (!isEroType && currentMode === 'hard') {
                                // Chế độ khó ép buộc dùng bản giới hạn
                                if(index < restrictedFortunePresets.length) {
                                    fortuneData = restrictedFortunePresets[index];
                                }
                            }

                             if (!selectedNames.has(fortuneData.name)) {
                                selectedNames.add(fortuneData.name);
                                generatedButtons.push({
                                    data: fortuneData,
                                    isTrue: isTrueFortune,
                                    isEro: isEroType,
                                    type: isEroType ? 'ero' : 'normal' // Đánh dấu phân loại
                                });
                                generatedCount++;
                            }
                        }
                    };

                    if (isEroMode) {
                        // Chế độ Hợp hoan: Rút 5 cái thường + 5 cái sắc sắc
                        generateButtonsFromPool(restrictedFortunePresets, 5, false);
                        generateButtonsFromPool(allEroPresets, 5, true);
                    } else {
                        // Chế độ Thường: Rút 10 cái thường (Chế độ khó 5 cái)
                        const drawCount = currentMode === 'hard' ? 5 : 10;
                        generateButtonsFromPool(restrictedFortunePresets, drawCount, false);
                    }

                    generatedButtons.forEach(item => {
                        const btn = document.createElement('button');
                        let className = 'preset-btn';
                        if (item.isTrue) className += ' true-fortune';
                        if (item.isEro) className += ' ero-fortune';
                        if (_keepSelectedNames.has(item.data.name)) className += ' selected';

                        btn.className = className;
                        btn.textContent = item.data.name;
                        btn.dataset.name = item.data.name;
                        btn.dataset.desc = item.data.desc;
                        btn.dataset.type = item.type;
                        btn.title = item.data.desc;
                        fortuneSelectionContainer.appendChild(btn);
                    });

                    // _gachaFortunes không bị reset → tự động giữ nguyên các thiên phú đã chọn trước
                    // Click handler sẽ add/remove trực tiếp khi user chọn thêm hoặc bỏ chọn
                    renderFortunePills();
                    drawFortuneBtn.textContent = 'Tính lại lần nữa ↺';
                    drawFortuneBtn.disabled = false;
                }, 800);
            });

            // Logic khi chọn sửa đổi
            fortuneSelectionContainer.addEventListener('click', (e) => {
                const btn = e.target.closest('.preset-btn');
                if (!btn) return;
                const isSelected = btn.classList.contains('selected');
                const name = btn.dataset.name;

                if (isSelected) {
                    // Bỏ chọn: xóa khỏi _gachaFortunes
                    btn.classList.remove('selected');
                    const idx = _gachaFortunes.findIndex(f => f.name === name);
                    if (idx !== -1) _gachaFortunes.splice(idx, 1);
                } else {
                    // Chọn thêm: push vào _gachaFortunes nếu chưa có
                    btn.classList.add('selected');
                    if (!_gachaFortunes.some(f => f.name === name)) {
                        _gachaFortunes.push({
                            name: btn.dataset.name,
                            desc: btn.dataset.desc,
                            type: btn.dataset.type,
                            isTrue: btn.classList.contains('true-fortune')
                        });
                    }
                }

                renderFortunePills();
            });

            // === Render fortune pills ===
            function renderFortunePills() {
                const container = document.getElementById('fortune-pills-container');
                container.innerHTML = '';
                const hasEro = eroToggle.checked && _gachaFortunes.some(f => f.type === 'ero');
                // Viền container: hồng nếu có ero, vàng nếu normal
                container.style.borderColor = hasEro ? 'rgba(255,105,180,0.5)' : 'var(--input-border)';

                if (_gachaFortunes.length === 0) {
                    container.innerHTML = '<span style="color:var(--text-muted);font-size:0.85em;align-self:center;">Chưa chọn thiên phú nào...</span>';
                    return;
                }

                _gachaFortunes.forEach((f, fi) => {
                    const isEro  = f.type === 'ero';
                    const isTrue = f.isTrue === true;
                    const color   = isEro ? '#ff69b4' : isTrue ? '#D4AF37' : '#9ca3af';
