<head>
    <style>
        @import url('https://fonts.googleapis.com/css2?family=Noto+Serif+SC:wght@400;700&family=JetBrains+Mono:wght@400;700&display=swap');
        :root {
            --bg-panel: rgba(26,24,29,0.75); --border-metal: #5a3d3d;
            --accent-blood: #ff4d4d; --accent-blood-glow: rgba(255,77,77,0.5);
