            --accent-gold: #ffd700; --accent-gold-glow: rgba(255,215,0,0.3);
            --accent-exp: #ff9f43; --accent-san: #2ed573;
            --text-main: #f1f2f6; --text-dim: #a4b0be; --rare-text: #d980fa;

            /* ĐÃ LÀM DỊU VÀ SÁNG CÁC MÀU TỐI */
            --g0: #b0bec5; /* Phàm/Hạ - Xám sáng */
            --g1: #81c784; /* Hoàng/Trung/Tam phẩm - Xanh lục */
            --g2: #64b5f6; /* Huyền/Thượng/Tứ phẩm - Xanh lam sáng */
            --g3: #ba68c8; /* Địa/Cực/Lục phẩm - Tím sáng */
            --g4: #ffb74d; /* Thiên/Thất phẩm - Cam sáng */
            --g5: #ef5350; /* Đế/Bát phẩm - Đỏ nhạt/Hồng nhạt */
            --g6: #ffd700; /* Tiên/Cửu phẩm - Vàng kim */
            --g7: #ffe57f; /* Thiên Vương - Vàng sáng rực, vượt trên Tiên */
            --g8: #80cbc4; /* Đạo Khí/Đạo Giáp - Thanh lam thần bí */
            --g9: #f48fb1; /* Hỗn Nguyên - Hồng phấn Thái Cổ, siêu vượt phân loại */
            /* Linh Thảo */
            --herb0: #81c784; /* Bách Niên  - Xanh lục tươi */
            --herb1: #4fc3f7; /* Thiên Niên - Xanh lam sáng */
            --herb2: #ffb74d; /* Vạn Niên   - Cam hổ phách */
            --herb3: #ce93d8; /* Thượng Cổ  - Tím mộng ảo */
        }
        * { margin:0; padding:0; box-sizing:border-box; }
        body { margin:0; padding:10px 0; background:transparent; font-family:'Noto Serif SC',serif; color:var(--text-main); font-size:14px; }

        .terminal-container { width:100%; max-width:800px; margin:auto; background:radial-gradient(circle at 50% 30%, rgba(30,40,50,0.95), rgba(10,15,20,0.98)); border:1px solid #333; border-top:2px solid var(--border-metal); border-bottom:2px solid var(--border-metal); border-radius:10px; box-shadow:0 0 30px rgba(0,0,0,0.8),inset 0 0 40px rgba(0,0,0,0.7); overflow:hidden; display:flex; flex-direction:column; position:relative;}
        .top-bar { height:3px; background:linear-gradient(90deg,transparent,var(--accent-blood),var(--accent-gold),var(--accent-mana),transparent); animation:shimmer 3s infinite linear; background-size:200% 100%; }
        .header { padding:8px 12px; display:flex; justify-content:space-between; align-items:center; border-bottom:1px solid rgba(255,255,255,0.05); background:linear-gradient(to bottom,rgba(0,0,0,0.6),rgba(0,0,0,0.2)); }
        .guild-badge { display:flex; align-items:center; gap:8px; }
        .guild-logo { width:26px; height:26px; border:2px solid var(--accent-gold); border-radius:50%; display:grid; place-items:center; font-weight:bold; color:var(--accent-gold); background:rgba(0,0,0,0.5); font-size:0.8em; }
        .guild-name { font-size:1.1em; letter-spacing:1px; font-weight:700; background:linear-gradient(to bottom,#fff,#bbb); -webkit-background-clip:text; -webkit-text-fill-color:transparent; }
        .time-display { font-size:0.85em; color:var(--accent-gold); font-family:'JetBrains Mono',monospace; border:1px solid rgba(255,215,0,0.3); padding:2px 6px; border-radius:4px; background:rgba(0,0,0,0.3); }
        .content-grid { display:grid; grid-template-columns:33% 1fr; flex-grow:1; }
        @media(max-width:560px){ .content-grid{grid-template-columns:1fr;} }

        /* PANEL TRÁI */
        .status-panel { background:rgba(20,18,22,0.6); border-right:1px solid rgba(255,255,255,0.05); padding:12px; display:flex; flex-direction:column; gap:8px; align-items:center; }
        .avatar-wrapper { display:flex; flex-direction:column; align-items:center; position:relative; margin-bottom: 5px; }
        .avatar-frame { width:90px; height:90px; border:2px solid var(--accent-gold); border-radius:6px; overflow:hidden; background:#000; box-shadow:0 0 10px var(--accent-gold-glow); }
        .user_avatar { width:100%; height:100%; background-size:cover; background-position:center; filter:sepia(10%) contrast(110%); transition:transform 0.5s; }
        .rank-tag { background:linear-gradient(135deg,#b8860b,#ffd700,#b8860b); color:#1a0f0f; padding:2px 8px; font-size:0.8em; border-radius:4px; font-weight:800; margin-top:-8px; z-index:3; box-shadow:0 4px 8px rgba(0,0,0,0.6); letter-spacing:1px; text-align:center; }

        .stat-group { width:100%; display:flex; flex-direction:column; gap:7px; }
        .stat-row { display:flex; flex-direction:column; gap:2px; }
        .stat-label { font-size:0.8em; color:var(--text-dim); display:flex; justify-content:space-between; align-items:flex-start; gap:4px; font-weight:700; letter-spacing:0.5px; }
        .stat-label > span:last-child { text-align:right; max-width:70%; word-wrap:break-word; white-space:normal; line-height:1.3; }
        .stat-val-btn { cursor:pointer; border:none; background:none; font-family:inherit; font-size:0.9em; font-weight:700; color:var(--text-dim); padding:0; text-align:right; max-width:70%; transition:color 0.2s; }
        .progress-bg { width:100%; height:6px; background:rgba(0,0,0,0.6); border:1px solid rgba(255,255,255,0.08); border-radius:3px; overflow:hidden; }
        .progress-fill { height:100%; width:0%; transition:width 0.8s; border-radius:3px; }
        .fill-hp { background:linear-gradient(90deg,#c0392b,#e74c3c); } .fill-mp { background:linear-gradient(90deg,#2980b9,#3498db); } .fill-san { background:linear-gradient(90deg,#27ae60,#2ecc71); } .fill-exp { background:linear-gradient(90deg,#d35400,#f39c12); }
        .grade-badge { display:inline-block; font-size:0.75em; padding:1px 4px; border-radius:3px; border:1px solid; font-weight:700; margin-left: 4px;}

        /* PANEL PHẢI & TABS GRID 4-4-3 */
        .main-panel { display:flex; flex-direction:column; }
        .nav-tabs { 
            display:grid; 
            grid-template-columns: repeat(12, 1fr); 
            background:rgba(0,0,0,0.4); 
            border-bottom:1px solid rgba(255,255,255,0.05); 
        }
        .tab-btn { 
            grid-column: span 3; 
            padding:9px 2px; text-align:center; background:none; border:none; color:var(--text-dim); cursor:pointer; font-family:inherit; font-size:0.85em; font-weight:bold; transition:all 0.3s; 
            border-right:1px solid rgba(255,255,255,0.03); 
            border-bottom:1px solid rgba(255,255,255,0.03); 
            position:relative;
        }
        .tab-btn:nth-child(4n) { border-right: none; }
        .tab-btn:nth-last-child(-n+3) { grid-column: span 4; border-bottom: none; }
        .tab-btn:last-child { border-right: none; }

        .tab-btn.active { color:var(--accent-gold); text-shadow:0 0 5px var(--accent-gold-glow); background:rgba(255,215,0,0.05); }
        .tab-btn.active::after { content:''; position:absolute; bottom:0; left:10%; right:10%; height:2px; background:var(--accent-gold); }
        .tab-content { padding:12px; flex-grow:1; overflow-y:auto; max-height:420px; }

        .empty-text { text-align:center; font-style:italic; color:var(--text-dim); font-size:0.9em; padding: 20px 0; }

        /* CARDS THÔNG DỤNG */
        .card { border:1px solid rgba(255,255,255,0.08); background:linear-gradient(145deg,rgba(30,30,35,0.6),rgba(20,20,25,0.8)); padding:10px; margin-bottom:8px; border-radius:6px; }
        .card-title { color:var(--accent-gold); font-size:0.95em; margin-bottom:6px; border-bottom:1px dashed rgba(255,255,255,0.12); padding-bottom:4px; display:flex; justify-content:space-between; font-weight:bold; }
        .card-text { font-size:0.85em; color:#dcdde1; line-height:1.4; }
        .stats-grid { display:grid; grid-template-columns:auto 1fr; align-items:center; gap:4px 8px; font-size:0.85em; margin-top:6px; background:rgba(0,0,0,0.2); padding:6px; border-radius:4px; }
        .stats-grid .lbl { color:var(--text-dim); }
        .section-div { display:flex; align-items:center; gap:8px; margin:10px 0 6px; }
        .section-div::before,.section-div::after { content:''; flex:1; height:1px; background:rgba(255,255,255,0.1); }
        .section-div span { font-size:0.8em; font-weight:bold; letter-spacing:1px; }

        /* TÚI ĐỒ */
        .inv-section { margin-bottom:8px; border:1px solid rgba(255,255,255,0.06); border-radius:6px; overflow:hidden; }
        .inv-header { display:flex; align-items:center; justify-content:space-between; padding:8px 10px; background:rgba(0,0,0,0.4); cursor:pointer; user-select:none; }
        .inv-header-left { font-size:0.9em; font-weight:bold; color:var(--text-main); display:flex; gap:8px; align-items:center;}
        .inv-count { font-size:0.85em; color:var(--text-dim); background:rgba(255,255,255,0.08); padding:1px 6px; border-radius:10px; }
        .inv-arrow { font-size: 0.8em; transition: transform 0.2s; }
        .inv-body { display:none; padding:8px; background:rgba(0,0,0,0.2); }
        .inv-body.open { display:block; }

        /* CSS FIX: Xếp hàng ngang cho Túi Đồ */
        .item-grid { display: grid; grid-template-columns: repeat(auto-fill, minmax(68px, 1fr)); gap: 6px; }
        .item-tile { position:relative; width:100%; cursor:pointer; transition: transform 0.1s; }

        .item-tile:hover { transform: translateY(-2px); }
        .item-box { border-radius:5px; border:1.5px solid; background:rgba(0,0,0,0.5); display:flex; flex-direction:column; align-items:center; padding:6px 2px; gap:3px; min-height:65px; }
        .item-icon { font-size:1.5em; line-height:1; }
        .item-name { font-size:0.7em; text-align:center; word-break:break-word; line-height:1.2; font-weight:bold; }
        .item-qty { position:absolute; bottom:2px; right:2px; font-size:0.7em; color:#fff; background:rgba(0,0,0,0.8); padding:1px 3px; border-radius:3px; font-family: 'JetBrains Mono', monospace;}

        /* TRANG BỊ */
        .equipped-grid { display:grid; grid-template-columns:1fr 1fr; gap:6px; }
        .equip-slot { border:1px solid rgba(255,255,255,0.1); border-radius:5px; padding:6px 8px; background:rgba(0,0,0,0.3); display:flex; flex-direction:column; gap:3px; cursor:pointer; }
        .equip-slot-label { font-size:0.75em; color:var(--text-dim); font-weight:bold; }
        .equip-slot-name { font-size:0.85em; font-weight:bold; }
        .equip-slot-grade { font-size:0.75em; color:var(--text-dim); }
        .equip-slot-mod { font-size:0.75em; color:var(--accent-exp); }

        /* DANH SÁCH 11 TAB CUSTOM */
        .quest-item { border-left:3px solid var(--text-dim); padding:6px 8px; margin-bottom:6px; background:rgba(255,255,255,0.02); border-radius:0 5px 5px 0; }
        .beauty-card { display:flex; gap:8px; border:1px solid rgba(255,215,0,0.2); background:linear-gradient(135deg,rgba(40,25,50,0.75),rgba(20,15,25,0.9)); padding:8px; margin-bottom:6px; border-radius:6px; }
        .beauty-rank { font-size:1.2em; font-weight:900; min-width:24px; text-align:center; }
        .event-card { border:1px solid rgba(255,77,77,0.25); background:linear-gradient(135deg,rgba(40,20,20,0.8),rgba(20,10,10,0.9)); padding:8px; margin-bottom:6px; border-radius:6px; }
        .msg-card { border:1px solid rgba(77,166,255,0.2); background:linear-gradient(135deg,rgba(20,30,45,0.85),rgba(10,15,25,0.9)); padding:8px; margin-bottom:6px; border-radius:6px; }

        /* TIÊN TỬ (FAIRY) */
        .fairy-container { position:absolute; bottom:15px; right:15px; display:flex; align-items:flex-end; gap:8px; z-index:10; animation:fairy-bob 4s infinite ease-in-out; pointer-events:none; }
        .fairy-avatar { width:40px; height:40px; background-size:cover; background-position:center; border-radius:50%; cursor:pointer; pointer-events:auto; box-shadow:0 0 15px var(--accent-gold),0 0 20px var(--accent-mana); border:2px solid #fff; transition:transform 0.3s; }
        .fairy-bubble { max-width:180px; background:rgba(10,8,18,0.97); border:1px solid rgba(255,215,0,0.3); border-radius:12px 12px 0 12px; padding:6px 8px; font-size:0.75em; color:var(--text-main); line-height:1.4; box-shadow:0 4px 10px rgba(0,0,0,0.8); transition:opacity 0.4s,transform 0.4s; pointer-events:none; }

        /* POPUP CHI TIẾT */
        .item-popup { display:none; position:fixed; z-index:99999; background:rgba(15,12,25,0.98); border:2px solid var(--accent-gold); border-radius:8px; padding:12px; max-width:250px; box-shadow:0 10px 30px rgba(0,0,0,0.9); pointer-events:none; }
        .item-popup.show { display:block; }
        .item-popup-name { font-weight:bold; font-size:1.05em; margin-bottom:4px; }
        .item-popup-grade { font-size:0.85em; margin-bottom:4px; display:flex; align-items:center;}
        .item-popup-mod { font-size:0.8em; color:var(--accent-exp); margin-bottom:4px; font-weight:bold;}
        .item-popup-desc { font-size:0.85em; color:#e0e0e0; line-height:1.4; border-top:1px dashed #555; padding-top:6px; margin-top:2px;}

        @keyframes shimmer { 0%{background-position:200% 0} 100%{background-position:-200% 0} }
        @keyframes rainbow-shift { 0%{filter:hue-rotate(0deg)} 100%{filter:hue-rotate(360deg)} }
        .rainbow-weapon { animation:rainbow-shift 3s linear infinite; color:var(--g9) !important; }
        @keyframes fairy-bob { 0%,100%{transform:translateY(0)} 50%{transform:translateY(-6px)} }
    </style>
