                    <button class="tab-btn" data-tab="database">Nhật Ký</button>

                    <!-- Dòng 3 (3 Tabs) -->
                    <button class="tab-btn" data-tab="beauties">Tuyệt Sắc</button>
                    <button class="tab-btn" data-tab="worldevents">Biến Động</button>
                    <button class="tab-btn" data-tab="messages">Ngọc Giản</button>
                </div>
                <div id="tab-dashboard" class="tab-content" style="display:block"></div>
                <div id="tab-inventory" class="tab-content" style="display:none"></div>
                <div id="tab-skills" class="tab-content" style="display:none"></div>
                <div id="tab-gifts" class="tab-content" style="display:none"></div>
                <div id="tab-partners" class="tab-content" style="display:none"></div>
                <div id="tab-npcs" class="tab-content" style="display:none"></div>
                <div id="tab-quests" class="tab-content" style="display:none"></div>
                <div id="tab-database" class="tab-content" style="display:none"></div>
                <div id="tab-beauties" class="tab-content" style="display:none"></div>
                <div id="tab-worldevents" class="tab-content" style="display:none"></div>
                <div id="tab-messages" class="tab-content" style="display:none"></div>
            </div>
        </div>
        <!-- TIÊN TỬ (FAIRY) -->
        <div class="fairy-container">
            <div class="fairy-bubble" style="opacity:0;transform:translateY(10px)"><span id="fairy-text">...</span></div>
            <div class="fairy-avatar" title="Nhấp để xem gợi ý"></div>
        </div>
    </div>

    <!-- POPUP DÙNG CHUNG -->
    <div id="st-mvu-global-popup" class="item-popup"></div>

    <script src="https://cdnjs.cloudflare.com/ajax/libs/lodash.js/4.17.21/lodash.min.js"></script>
    <script>
    (() => {
        // --- TÌM ĐÚNG VÙNG CHỨA CỦA TIN NHẮN HIỆN TẠI ---
        const containers = document.querySelectorAll('.terminal-container');
        const uiRoot = containers[containers.length - 1];
        if (!uiRoot) return;

        const itemStore = {};
        function saveItemData(item) {
            if(!item) return "";
            const id = 'item_' + Math.random().toString(36).substr(2, 9);
            itemStore[id] = item;
            return id;
        }

        // --- CẬP NHẬT MÀU SẮC ĐAN DƯỢC & VẬT PHẨM ---
        const GRADE_COLOR = {
            map: (g) => {
                if(!g) return 'var(--g0)'; const s = g.toString().toLowerCase();
                if(s.includes('tiên')||s.includes('siêu')||s.includes('cửu phẩm')||s.includes('thập phẩm')) return 'var(--g6)';
                if(s.includes('đế')||s.includes('bát phẩm')) return 'var(--g5)'; 
                if(s.includes('thiên')||s.includes('thất phẩm')) return 'var(--g4)';
                if(s.includes('địa')||s.includes('cực')||s.includes('ngũ phẩm')||s.includes('lục phẩm')) return 'var(--g3)';
                if(s.includes('huyền')||s.includes('thượng')||s.includes('tứ phẩm')) return 'var(--g2)';
                if(s.includes('hoàng')||s.includes('trung')||s.includes('tam phẩm')||s.includes('nhị phẩm')) return 'var(--g1)';
                return 'var(--g0)'; // Phàm/Hạ/Nhất phẩm
            },
            physique: (g) => {
                if(!g) return 'var(--g0)'; const s = g.toString().toLowerCase();
                if(s.includes('đạo')) return 'var(--g6)'; if(s.includes('thần')) return 'var(--g5)';
                if(s.includes('thánh')) return 'var(--g4)'; if(s.includes('hoàng')) return 'var(--g3)';
                if(s.includes('vương')) return 'var(--g2)'; if(s.includes('linh')) return 'var(--g1)';
                return 'var(--g0)';
            },
            root: (g) => {
                if(!g) return 'var(--g0)'; const s = g.toString().toLowerCase();
                if(s.includes('thiên')) return 'var(--g5)'; if(s.includes('địa')) return 'var(--g4)';
                if(s.includes('huyền')) return 'var(--g3)'; if(s.includes('hoàng')) return 'var(--g2)';
                if(s.includes('tạp')) return 'var(--g1)'; if(s.includes('phế')) return 'var(--g0)';
                return 'var(--g6)';
            },
            // Bảng màu riêng cho Vũ Khí / Pháp Bảo / Giáp — theo bậc chính
            weapon: (g) => {
                if(!g) return 'var(--g0)'; const s = g.toString().toLowerCase();
                // ── Bậc siêu vượt (trên Tiên Khí, không phân sub-grade) ──
                if(s.includes('hỗn nguyên'))                          return 'RAINBOW'; // animated
                if(s.includes('đạo khí') || s.includes('đạo giáp'))  return 'var(--g8)';
                if(s.includes('thiên vương'))                         return 'var(--g7)';
                // ── Bậc Tiên ──
                if(s.includes('tiên khí') || s.includes('tiên y') || s.includes('phôi tiên')) return 'var(--g6)';
                if(s.includes('tiên thiên linh bảo'))                 return 'var(--g5)';
                if(s.includes('thông thiên') || s.includes('linh bảo giáp'))                  return 'var(--g4)';
                // ── Bậc cao ──
                if(s.includes('bản mệnh'))                            return 'var(--g3)';
                if(s.includes('cổ bảo') || s.includes('cổ giáp'))    return 'var(--g2)';
                if(s.includes('pháp bảo') || s.includes('linh giáp'))return 'var(--g1)';
                if(s.includes('pháp khí') || s.includes('pháp y'))   return 'var(--g0)';
                // ── Fallback theo sub-grade nếu không nhận ra tên bậc chính ──
                if(s.includes('cực phẩm'))    return 'var(--g3)';
                if(s.includes('thượng phẩm')) return 'var(--g2)';
                if(s.includes('trung phẩm'))  return 'var(--g1)';
                return 'var(--g0)';
            },
            // Bảng màu riêng cho Linh Thảo — theo 4 bậc grade
            herb: (g) => {
                if(!g) return 'var(--herb0)'; const s = g.toString().toLowerCase();
                if(s.includes('thượng cổ'))  return 'var(--herb3)';
                if(s.includes('vạn niên'))   return 'var(--herb2)';
                if(s.includes('thiên niên')) return 'var(--herb1)';
                return 'var(--herb0)'; // Bách Niên hoặc mặc định
            },
            badge: function(g) { return `<span class="grade-badge" style="color:${this.map(g)};border-color:${this.map(g)}40;background:${this.map(g)}15">${g||'?'}</span>`; }
        };

        function itemIcon(type, name) {
            const t = (type||'').toLowerCase(); const n = (name||'').toLowerCase();
            if(t.includes('đan')||n.includes('đan')) return '💊';
            if(t.includes('thảo')||t.includes('dược')||n.includes('thảo')||n.includes('tinh')) return '🌿';
            if(t.includes('kiếm')||n.includes('kiếm')) return '⚔️';
            if(t.includes('y phục')||n.includes('giáp')) return '👘';
            if(t.includes('nhẫn')) return '💍'; if(t.includes('trâm')) return '📌';
            if(t.includes('pháp bảo')||t.includes('linh bảo')) return '🔮';
            if(t.includes('sách')||t.includes('quyết')) return '📖';
            return '📦';
        }

        // --- KHỞI TẠO DỮ LIỆU ---
        function renderUI() {
            if(typeof getAllVariables !== 'function') return;
            const data = _.get(getAllVariables(), 'stat_data', {});
            if(!data || !Object.keys(data).length) return;

            const $ = sel => uiRoot.querySelector(sel);
            const $txt = (sel, v) => { const el=$(sel); if(el) el.innerHTML = v; };
            const get = (p,d='') => _.get(data,p,d);

            // Avatar & Header
            const avatarUrl = document.querySelector('#user_avatar_image')?.src;
            if($('.user_avatar') && avatarUrl) $('.user_avatar').style.backgroundImage = `url('${avatarUrl}')`;
            $txt('#env-status', `⚜️ ${get('cultivator.identity.name','{{user}}')}`);
            $txt('.rank-tag', `${get('cultivator.realm.major','Phàm Nhân')} — Tầng ${get('cultivator.realm.tier',1)}`);

            // Thanh tiến trình
            const fillBar = (name, cur, max) => {
                const c=parseFloat(cur)||0; const m=parseFloat(max)||100;
                $txt(`#${name}-val`, `${Math.round(c)}/${Math.round(m)}`);
                if($(`#${name}-bar`)) $(`#${name}-bar`).style.width = (m>0 ? Math.min(100,(c/m)*100) : 0)+'%';
            };
            fillBar('hp', get('cultivator.stats.hp.current'), get('cultivator.stats.hp.max'));
            fillBar('blood', get('cultivator.stats.blood.current'), get('cultivator.stats.blood.max'));
            fillBar('mp', get('cultivator.stats.mp.current'), get('cultivator.stats.mp.max'));

            if(get('cultivator.realm.exp.max') === -1) {
                $txt('#exp-val', 'Viên Mãn'); if($('#exp-bar')) $('#exp-bar').style.width = '100%';
            } else {
                fillBar('exp', get('cultivator.realm.exp.current'), get('cultivator.realm.exp.max'));
            }

            // Text Info
            $txt('#san-val', get('cultivator.stats.san_status','Bình thường'));
            $txt('#luck-val', get('cultivator.stats.luck_status','Bình thường'));

            const btnSr = $('.detail-btn[data-type="spirit_root"]');
            if(btnSr) {
                const srVal = get('cultivator.roots.spirit_root','?');
                const srGrade = get('cultivator.roots.spirit_root_grade','');
                btnSr.style.color = GRADE_COLOR.root(srGrade);
                btnSr.innerHTML = `${srVal} ${srGrade && srGrade !== 'Chưa xác định' ? `<span style="font-size:0.75em;opacity:0.8">(${srGrade})</span>` : ''}`;
                btnSr.setAttribute('data-val', srVal); btnSr.setAttribute('data-grade', srGrade);
            }

            const btnPhy = $('.detail-btn[data-type="physique"]');
            if(btnPhy) {
                const phyVal = get('cultivator.roots.physique','Phàm Thể');
                const phyGrade = get('cultivator.roots.physique_grade','Phàm');
                btnPhy.style.color = GRADE_COLOR.physique(phyGrade);
                btnPhy.innerHTML = `${phyVal} ${phyGrade && phyGrade !== 'Phàm' ? `<span style="font-size:0.75em;opacity:0.8">(${phyGrade})</span>` : ''}`;
                btnPhy.setAttribute('data-val', phyVal); btnPhy.setAttribute('data-grade', phyGrade);
            }

            $txt('#race-val', get('cultivator.identity.race','Nhân Tộc'));
            $txt('#clan-val', get('relationships.current_sect','Tán Tu'));
            const efx = get('cultivator.stats.status_effects',[]);
            $txt('#efx-val', efx.length>0 ? efx.join(', ') : 'Vô sự');

            // Render Tất Cả Tabs
            renderDashboard(data, $);
            renderInventory(data, $);
            renderSkills(data, $);
            renderGifts(data, $);
            renderPartners(data, $);
            renderNPCs(data, $);
            renderQuests(data, $);
            renderLogs(data, $);
            renderBeauties(data, $);
            renderEvents(data, $);
            renderMessages(data, $);

            // Fairy Message
            $txt('#fairy-text', get('system.fairy_message','Đạo hữu cẩn trọng...'));
        }

        // --- RENDER FUNCTIONS ---
        function renderDashboard(data, $) {
            const loc = data.world?.location||{}; const time = data.world?.time||{}; const env = data.world?.environment||{};
            const inv = data.inventory||{}; const eq = inv.equipped||{};

            const renderSlot = (lbl, itm, icn, isMod, colorFn) => {
                if(!itm) return `<div class="equip-slot"><div class="equip-slot-label">${lbl}</div><div class="equip-slot-empty" style="font-size:0.85em;color:gray;font-style:italic">${icn} Không có</div></div>`;
                const rawC = colorFn ? colorFn(itm.grade) : GRADE_COLOR.map(itm.grade);
                const isRainbow = rawC === 'RAINBOW';
                const c = isRainbow ? 'var(--g9)' : rawC;
                const rainbowClass = isRainbow ? ' rainbow-weapon' : '';
                const itmTagged = colorFn === GRADE_COLOR.weapon ? {...itm, _slotType:'weapon'} : itm;
                const pid = saveItemData(itmTagged);
                const mod = isMod && itm.artifact_exp_mod ? `<div class="equip-slot-mod">⚡ ×${itm.artifact_exp_mod}</div>` : '';
                return `<div class="equip-slot popup-trigger" data-pid="${pid}"><div class="equip-slot-label">${lbl}</div><div class="equip-slot-name${rainbowClass}" style="color:${c}">${icn} ${itm.name}</div><div class="equip-slot-grade${rainbowClass}" style="color:${c}">${itm.grade||''}</div>${mod}</div>`;
            };

            const accHtml = (eq.accessories||[]).map(a => {
                const c = GRADE_COLOR.map(a.grade); const pid = saveItemData(a);
                return `<span class="item-tile popup-trigger" data-pid="${pid}"><div class="item-box" style="border-color:${c};width:auto;padding:3px 7px;min-height:auto"><span style="font-size:0.8em;color:${c};font-weight:bold">${a.name}${a.accessory_exp_mod>1?` <span style="color:var(--accent-exp)">×${a.accessory_exp_mod}</span>`:''}</span></div></span>`;
            }).join('') || '<span style="font-size:0.85em;color:gray;font-style:italic">Không có</span>';

            $('#tab-dashboard').innerHTML = `
                <div class="card"><div class="card-title"><span>Vị trí</span><span>📍</span></div><div class="card-text">${loc.realm||'?'} › ${loc.region||'?'} › ${loc.specific||'?'}</div></div>
                <div class="card"><div class="card-title" style="color:var(--accent-blood)"><span>Thiên Cơ</span><span>⚠️</span></div><div class="card-text">Năm ${time.year||1}, Tháng ${time.month||1}<br>Linh khí: <strong>${env.qi_density||'?'}</strong> | Nguy hiểm: <strong>${env.threat_level||'?'}</strong></div></div>
                <div class="card"><div class="card-title"><span>Tài Nguyên</span><span>💰</span></div><div class="card-text">Linh thạch: <span style="color:var(--accent-gold);font-weight:bold">${(inv.spirit_stones||0).toLocaleString()}</span></div></div>
                <div class="card"><div class="card-title"><span>Trang Bị</span><span>⚔️</span></div>
                    <div class="equipped-grid">
                        ${renderSlot('Vũ Khí/Pháp Bảo', eq.weapon, '⚔️', false, GRADE_COLOR.weapon)}
                        ${renderSlot('Giáp/Y Phục', eq.armor, '🛡️', false, GRADE_COLOR.weapon)}
                        ${renderSlot('Linh Khí Vật', eq.artifact, '🔮', true, GRADE_COLOR.weapon)}
                        <div class="equip-slot" style="grid-column:1/-1"><div class="equip-slot-label">Phụ kiện</div><div class="accessories-list" style="display:flex;gap:5px;flex-wrap:wrap;margin-top:2px;">${accHtml}</div></div>
                    </div>
                </div>`;
        }

        function renderInventory(data, $) {
            const inv = data.inventory||{};
            const renderSec = (id, icon, title, items, colorFn) => {
                const tiles = (items||[]).map(it => {
                    const c = colorFn ? colorFn(it.grade) : GRADE_COLOR.map(it.grade); const pid = saveItemData(it);
                    return `<div class="item-tile popup-trigger" data-pid="${pid}"><div class="item-box" style="border-color:${c};box-shadow:0 0 6px ${c}20"><div class="item-icon">${itemIcon(it.type,it.name)}</div><div class="item-name" style="color:${c}">${it.name}</div></div>${it.quantity?`<div class="item-qty">×${it.quantity}</div>`:''}</div>`;
                }).join('');
                return `<div class="inv-section"><div class="inv-header" data-toggle="${id}"><div class="inv-header-left"><span>${icon}</span>${title}<span class="inv-count">${(items||[]).length}</span></div><span class="inv-arrow">▼</span></div><div class="inv-body" id="inv-body-${id}"><div class="item-grid">${tiles||'<p class="empty-text">Trống rỗng</p>'}</div></div></div>`;
            };
            // Tag herbs để popup dùng đúng colorFn
            (inv.herbs||[]).forEach(h => h._slotType = 'herb');
            $('#tab-inventory').innerHTML = renderSec('pills','💊','Đan Dược',inv.pills) + renderSec('herbs','🌿','Linh Thảo',inv.herbs,GRADE_COLOR.herb) + renderSec('manuals','📖','Bí Tịch',inv.manuals) + renderSec('misc','📦','Khác',inv.misc);
        }

        function renderSkills(data, $) {
            // Hiển thị Công Pháp, phân biệt Chủ Tu / Phụ Tu / Thần Thông / Thuật Pháp
            function calcMethodMod(grade, level) {
                const g = (grade||'').toLowerCase(); const lv = parseInt(level)||1;
                const table = [
                    ['tiên',1,2.500,0.0625],['đế',1,1.900,0.0375],['thiên',1,1.550,0.025],
                    ['địa',1,1.350,0.01875],['huyền',1,1.200,0.0125],['hoàng',1,1.100,0.010],['phàm',1,1.000,0.010]
                ];
                for(const [key,,base,step] of table) {
                    if(g.includes(key)) return (base + (lv-1)*step).toFixed(3);
                }
                return null;
            }
            const renderSkill = (s, showLvl, defaultType) => {
                const c = GRADE_COLOR.map(s.grade);

                let typeText = s.type || defaultType;
                let typeColor = '#fff';
                const isChutU = typeText.toLowerCase().includes('chủ tu');
                if(isChutU) typeColor = 'var(--accent-gold)';

                const typeBadge = `<span style="font-size:0.75em; color:${typeColor}; margin-left:8px; font-weight:normal; letter-spacing:0.5px">${typeText}</span>`;

                // Method_Mod chỉ tính cho Chủ Tu có level
                const methodMod = (isChutU && showLvl) ? calcMethodMod(s.grade, s.level) : null;
                const modRow = methodMod ? `<span class="lbl">Tốc độ tu luyện</span><span style="color:var(--accent-exp);font-weight:bold">⚡ ×${methodMod}</span>` : '';

                return `<div class="card" style="border-left:2px solid ${c}"><div style="display:flex;justify-content:space-between;margin-bottom:6px;align-items:baseline"><span style="font-size:1.05em;font-weight:bold;color:${c}">${s.name}${typeBadge}</span>${GRADE_COLOR.badge(s.grade)}</div><div class="stats-grid">${showLvl?`<span class="lbl">Tầng</span><span>${s.level||1}</span>`:''}<span class="lbl">Thuần thục</span><div style="display:flex;align-items:center;gap:6px"><div class="progress-bg" style="width:100px"><div class="progress-fill" style="width:${s.mastery||0}%;background:${c}"></div></div><span style="font-size:0.8em;color:${c}">${s.mastery||0}%</span></div>${modRow}</div><div style="font-size:0.85em;color:#e0e0e0;margin-top:6px">${s.desc||''}</div></div>`;
            };
            let h = '';
            if(data.cultivation_methods?.length) h += `<div class="section-div"><span>⚡ CÔNG PHÁP</span></div>` + data.cultivation_methods.map(s=>renderSkill(s,true,'Công pháp')).join('');
            if(data.divine_arts?.length) h += `<div class="section-div"><span style="color:var(--rare-text)">✦ THẦN THÔNG</span></div>` + data.divine_arts.map(s=>renderSkill(s,false,'Thần thông')).join('');
            if(data.magic_arts?.length) h += `<div class="section-div"><span style="color:var(--accent-mana)">✨ THUẬT PHÁP</span></div>` + data.magic_arts.map(s=>renderSkill(s,false,'Thuật pháp')).join('');
            $('#tab-skills').innerHTML = h || '<p class="empty-text">Chưa tu luyện công pháp nào.</p>';
        }

        function renderGifts(data, $) {
            $('#tab-gifts').innerHTML = (data.gifts||[]).length ? data.gifts.map(g=>`<div class="card" style="border-left:2px solid var(--g6)"><div style="font-size:1em;font-weight:bold;color:var(--g6);margin-bottom:6px">✦ ${g.name}</div><div class="card-text">${g.desc}</div></div>`).join('') : '<p class="empty-text">Chưa có thiên phú nào thức tỉnh.</p>';
        }

        function renderPartners(data, $) {
            const p = data.partners||[];
            $('#tab-partners').innerHTML = p.length ? p.map(x=>`<div class="card"><div style="display:flex;justify-content:space-between;align-items:baseline;margin-bottom:6px"><span style="font-weight:bold;font-size:1.05em">${x.name} <span style="font-size:0.75em;color:var(--text-dim)">${x.species}</span></span><span style="font-size:0.75em;padding:2px 6px;border-radius:3px;background:rgba(77,166,255,0.15);border:1px solid rgba(77,166,255,0.3);color:var(--accent-mana)">${x.identity}</span></div><div class="stats-grid"><span class="lbl">Cảnh giới</span><span style="color:var(--rare-text);font-weight:bold">${x.realm}</span><span class="lbl">Sinh mệnh</span><div class="progress-bg"><div class="progress-fill fill-hp" style="width:${x.hp||0}%"></div></div><span class="lbl">Linh lực</span><div class="progress-bg"><div class="progress-fill fill-mp" style="width:${x.mp||0}%"></div></div><span class="lbl">Hảo cảm</span><div class="progress-bg"><div class="progress-fill fill-san" style="width:${x.loyalty||0}%"></div></div><span class="lbl">Tính cách</span><span>${x.personality}</span><span class="lbl">Ngoại hình</span><span>${x.appearance}</span><span class="lbl">Quan hệ</span><span>${x.relation_desc}</span><span class="lbl">Năng lực</span><span>${x.abilities}</span><span class="lbl">Tâm tư</span><em style="color:var(--text-dim)">${x.thoughts}</em></div></div>`).join('') : '<p class="empty-text">Chưa kết giao đạo lữ, cô độc một mình.</p>';
        }

        function renderNPCs(data, $) {
            const npcs = data.npcs||[];
            $('#tab-npcs').innerHTML = npcs.length ? npcs.map(n=>{
                const rc = n.relation>=50?'#2ed573':n.relation<30?'#ff4d4d':'#a4b0be';
                const relationVal = n.relation || 0;
                return `<div class="card"><div style="display:flex;justify-content:space-between;align-items:baseline;margin-bottom:6px"><span><strong style="font-size:1.05em">${n.name}</strong> <span style="font-size:0.75em;color:var(--text-dim)">${n.title}</span></span><span style="font-size:0.75em;font-weight:bold;color:${rc}">${n.relation>=50?'Thân thiện':n.relation<30?'Thù địch':'Trung lập'}</span></div><div class="stats-grid"><span class="lbl">Cảnh giới</span><span style="color:var(--rare-text)">${n.realm}</span><span class="lbl">Sinh mệnh</span><div class="progress-bg"><div class="progress-fill fill-hp" style="width:${n.hp||0}%"></div></div><span class="lbl">Quan hệ</span><div class="progress-bg"><div class="progress-fill" style="width:${Math.max(0, Math.min(100, relationVal))}%;background:${rc}"></div></div><span class="lbl">Tính cách</span><span>${n.personality}</span><span class="lbl">Ấn tượng</span><span>${n.desc}</span></div></div>`;
            }).join('') : '<p class="empty-text">Không có nhân vật nào xuất hiện.</p>';
        }

        function renderQuests(data, $) {
            const qs = data.system?.quest_log?.side_quests||[]; const mq = data.system?.quest_log?.current_quest||'';
            let html = `<div class="card" style="border-color:var(--accent-gold);margin-bottom:12px"><div class="card-title"><span>Mục Tiêu Chính</span><span>🎯</span></div><div class="card-text">${mq}</div></div>`;
            html += qs.length ? qs.map(q=>`<div class="quest-item"><div style="display:flex;justify-content:space-between;margin-bottom:4px"><strong>${q.title}</strong><span style="font-size:0.8em;color:var(--accent-gold)">${q.status||''}</span></div>${q.quote?`<div style="font-style:italic;font-size:0.8em;color:var(--text-dim);margin-bottom:4px">"${q.quote}"</div>`:''}<div style="font-size:0.85em">${q.desc||''}</div></div>`).join('') : '<p class="empty-text">Tạm thời không có cơ duyên nào.</p>';
            $('#tab-quests').innerHTML = html;
        }

        function renderLogs(data, $) {
            const logs = data.system?.quest_log?.history_log||[];
            $('#tab-database').innerHTML = logs.length ? logs.map(l=>`<p style="margin-bottom:6px;border-bottom:1px solid rgba(255,255,255,0.05);padding-bottom:6px;font-size:0.9em;">➤ ${l}</p>`).join('') : '<p class="empty-text">Nhật ký trống rỗng.</p>';
        }

        function renderBeauties(data, $) {
            const bs = [...(data.beauties||[])].sort((a,b)=>a.rank-b.rank);
            $('#tab-beauties').innerHTML = bs.length ? bs.map(b=>{
                const medal = b.rank===1?'👑':b.rank===2?'🥈':b.rank===3?'🥉':'#'+b.rank;
                const rc = b.rank===1?'#ffd700':b.rank===2?'#c0c0c0':b.rank===3?'#cd7f32':'var(--accent-gold)';
                return `<div class="beauty-card"><div class="beauty-rank" style="color:${rc}">${medal}</div><div style="flex-grow:1"><div style="display:flex;justify-content:space-between;align-items:baseline;margin-bottom:4px"><span style="font-size:1em;font-weight:bold">${b.name}</span>${b.title?`<span style="font-size:0.7em;color:var(--rare-text);border:1px solid rgba(217,128,250,0.3);padding:1px 5px;border-radius:3px">${b.title}</span>`:''}</div>${b.appearance?`<div style="font-size:0.85em;color:#dcdde1;border-left:2px solid rgba(255,215,0,0.3);padding-left:6px;margin-bottom:4px">${b.appearance}</div>`:''} ${b.rumor?`<div style="font-size:0.8em;color:var(--text-dim);font-style:italic">💬 ${b.rumor}</div>`:''}</div></div>`;
            }).join('') : '<p class="empty-text">Chưa có giai nhân nào lọt vào Tuyệt Sắc Bảng.</p>';
        }

        function renderEvents(data, $) {
            const evs = data.world_events||[];
            $('#tab-worldevents').innerHTML = evs.length ? evs.map(ev=>`<div class="event-card"><div style="display:flex;align-items:baseline;gap:8px;margin-bottom:6px"><span style="font-size:0.7em;color:var(--accent-blood);border:1px solid rgba(255,77,77,0.4);padding:1px 5px;border-radius:2px;background:rgba(255,77,77,0.08);font-weight:bold">${ev.type||'Sự Kiện'}</span><span style="font-size:1em;font-weight:bold">${ev.title}</span></div><div style="font-size:0.8em;color:var(--accent-gold);margin-bottom:4px">📍 ${ev.location}</div><div style="font-size:0.85em;color:#dcdde1;border-left:2px solid rgba(255,77,77,0.3);padding-left:6px">${ev.desc}</div></div>`).join('') : '<p class="empty-text">Thiên hạ thái bình.</p>';
        }

        function renderMessages(data, $) {
            const msgs = [...(data.messages||[])].reverse();
            $('#tab-messages').innerHTML = msgs.length ? msgs.map(m=>`<div class="msg-card"><div style="display:flex;justify-content:space-between;margin-bottom:6px"><span style="font-size:0.95em;font-weight:bold;color:var(--accent-mana)">✉ ${m.sender}</span><span style="font-size:0.75em;color:var(--text-dim);font-family:monospace;border:1px solid rgba(255,255,255,0.1);padding:1px 4px;border-radius:2px">${m.time}</span></div><div style="font-size:0.85em;color:#dcdde1;border-left:2px solid rgba(77,166,255,0.3);padding-left:6px">${m.content}</div></div>`).join('') : '<p class="empty-text">Ngọc Giản truyền âm trống rỗng.</p>';
        }

        // --- XỬ LÝ SỰ KIỆN DELEGATION (CHỈ ÁP DỤNG TRONG uiRoot) ---
        if (!uiRoot.dataset.eventsBound) {
            uiRoot.addEventListener('click', (e) => {
                // Chuyển Tab
                const tabBtn = e.target.closest('.tab-btn');
                if (tabBtn) {
                    uiRoot.querySelectorAll('.tab-btn').forEach(b => b.classList.remove('active'));
                    uiRoot.querySelectorAll('.tab-content').forEach(p => p.style.display = 'none');
                    tabBtn.classList.add('active');
                    const targetTab = uiRoot.querySelector('#tab-' + tabBtn.getAttribute('data-tab'));
                    if(targetTab) targetTab.style.display = 'block';
                    return;
                }

                // Đóng/Mở Túi Đồ
                const invHeader = e.target.closest('.inv-header');
                if (invHeader) {
                    const id = invHeader.getAttribute('data-toggle');
                    const body = uiRoot.querySelector('#inv-body-' + id);
                    if (body) {
                        body.classList.toggle('open');
                        const arrow = invHeader.querySelector('.inv-arrow');
                        if(arrow) arrow.style.transform = body.classList.contains('open') ? 'rotate(180deg)' : 'none';
                    }
                    return;
                }

                // Click vào Tiên Tử (Fairy)
                const fairyAvatar = e.target.closest('.fairy-avatar');
                if (fairyAvatar) {
                    const fairyImages = ['https://i.postimg.cc/rpz2PCrZ/Image-1765540443504.jpg','https://i.postimg.cc/B6bsPC8Q/Image-1765540442059.jpg'];
                    const currentBg = fairyAvatar.style.backgroundImage;
                    const nextImg = currentBg.includes(fairyImages[0]) ? fairyImages[1] : fairyImages[0];
                    fairyAvatar.style.backgroundImage = `url('${nextImg}')`;

                    const bubble = uiRoot.querySelector('.fairy-bubble');
                    if (bubble) {
                        bubble.style.opacity = bubble.style.opacity === '1' ? '0' : '1';
                        bubble.style.transform = bubble.style.opacity === '1' ? 'translateY(0)' : 'translateY(10px)';
                    }
                    return;
                }

                // Click Xem chi tiết (Linh căn, Thể chất)
                const detailBtn = e.target.closest('.detail-btn');
                if (detailBtn) {
                    const type = detailBtn.getAttribute('data-type');
                    const val = detailBtn.getAttribute('data-val');
                    const grade = detailBtn.getAttribute('data-grade');

                    let content = '';
                    if(type==='spirit_root') {
                        const c = GRADE_COLOR.root(grade);
                        let desc = '🔮 Linh căn đặc thù.';
                        const v = (grade||'').toLowerCase();
                        if(v.includes('thiên')) desc= '🌟 Thiên phẩm — Vạn người không có một. Tu luyện cực nhanh.<br><span style="color:var(--accent-exp)">⚡ Tăng tốc độ tu luyện: ×2.0</span>';
                        else if(v.includes('địa')) desc= '✨ Địa phẩm — Trăm năm khó gặp. Tốc độ tu luyện vượt xa người thường.<br><span style="color:var(--accent-exp)">⚡ Tăng tốc độ tu luyện: ×1.5</span>';
                        else if(v.includes('huyền')) desc= '💠 Huyền phẩm — Thiên phú ưu lương. Tu luyện suôn sẻ.<br><span style="color:var(--accent-exp)">⚡ Tăng tốc độ tu luyện: ×1.0</span>';
                        else if(v.includes('hoàng')) desc= '🟡 Hoàng phẩm — Tư chất bình dung.<br><span style="color:var(--accent-exp)">⚡ Tăng tốc độ tu luyện: ×0.8</span>';
                        else if(v.includes('tạp')) desc= '⚪ Tạp linh căn — Nhiều hành nhưng không thuần nhất.<br><span style="color:var(--accent-exp)">⚡ Tăng tốc độ tu luyện: ×0.5</span>';
                        else if(v.includes('phế')) desc= '🩶 Phế phẩm — Không cảm ứng được linh khí.<br><span style="color:var(--accent-exp)">⚡ Tăng tốc độ tu luyện: ×0.1</span>';
                        content = `<strong style="color:${c};font-size:1.1em">${val}</strong><br><span style="font-size:0.85em;color:${c};opacity:0.9">${grade}</span><hr style="border-color:rgba(255,255,255,0.1);margin:6px 0"><br>${desc}`;
                    } else if (type === 'physique') {
                        const c = GRADE_COLOR.physique(grade);
                        let desc = '⬜ Phàm Thể — Thể chất người thường.<br><b>EXP×1.0 | HP×1.0</b>';
                        const v = (grade||'').toLowerCase();
                        if(v.includes('đạo')) desc= '🌌 Đạo Thể — Nhục thân bản thân là Đạo. Tối thượng truyền thuyết.<br><b>EXP×4.0 | HP×12.0</b>';
                        else if(v.includes('thần')) desc= '⚡ Thần Thể — Thần tắc cổ đại ẩn trong nhục thân.<br><b>EXP×3.0 | HP×8.0</b>';
                        else if(v.includes('thánh')) desc= '✨ Thánh Thể — Nhục thân nửa Tiên.<br><b>EXP×2.5 | HP×5.0</b>';
                        else if(v.includes('hoàng')) desc= '🔥 Hoàng Thể — Tiềm năng vượt bậc.<br><b>EXP×2.0 | HP×3.0</b>';
                        else if(v.includes('vương')) desc= '💜 Vương Thể — Thể chất vượt trội.<br><b>EXP×1.6 | HP×2.0</b>';
                        else if(v.includes('linh')) desc= '💚 Linh Thể — Kinh mạch có linh tính.<br><b>EXP×1.3 | HP×1.5</b>';
                        else if(v.includes('phế')) desc= '🩶 Phế Thể — Kinh mạch thiếu khuyết.<br><b>EXP×0.5 | HP×0.5</b>';
                        content = `<strong style="color:${c};font-size:1.1em">${val}</strong><br><span style="font-size:0.85em;color:${c};opacity:0.9">${grade}</span><hr style="border-color:rgba(255,255,255,0.1);margin:6px 0"><br>${desc}`;
                    }

                    let modal = document.getElementById('st-detail-modal-global');
                    if(!modal) {
                        modal = document.createElement('div');
                        modal.id = 'st-detail-modal-global';
                        modal.style.cssText = 'display:none;position:fixed;top:0;left:0;width:100%;height:100%;background:rgba(0,0,0,0.85);z-index:99999;justify-content:center;align-items:center;';
                        modal.innerHTML = '<div style="background:rgba(15,12,25,0.98);border:2px solid rgba(255,215,0,0.4);border-radius:10px;padding:16px;max-width:320px;width:90%;font-size:0.9em;line-height:1.5;color:#dcdde1;position:relative;box-shadow: 0 10px 30px rgba(0,0,0,0.9)"><button onclick="document.getElementById(\'st-detail-modal-global\').style.display=\'none\'" style="position:absolute;top:8px;right:12px;background:none;border:none;color:#fff;font-size:1.2em;cursor:pointer;">✕</button><div id="st-detail-modal-content"></div></div>';
                        document.body.appendChild(modal);
                        modal.onclick = e => { if(e.target===modal) modal.style.display='none'; };
                    }
                    document.getElementById('st-detail-modal-content').innerHTML = content;
                    modal.style.display = 'flex';
                    return;
                }

                // Click vào Item hiện Popup (Dùng chung cho toàn trang)
                const popupTrigger = e.target.closest('.popup-trigger');
                if (popupTrigger) {
                    const pid = popupTrigger.getAttribute('data-pid');
                    const item = itemStore[pid];
                    if(item) {
                        let popup = document.getElementById('st-mvu-global-popup');
                        if(!popup) {
                            popup = document.createElement('div');
                            popup.id = 'st-mvu-global-popup';
                            popup.className = 'item-popup';
                            document.body.appendChild(popup);
                        }
                        // Tính màu trước — dùng cho badge, border, glow
                        const isWpn = item._slotType === 'weapon' || item._slotType === 'armor';
                        const isHerb = item._slotType === 'herb';
                        const rawPopupC = isWpn ? GRADE_COLOR.weapon(item.grade) : isHerb ? GRADE_COLOR.herb(item.grade) : GRADE_COLOR.map(item.grade);
                        const isRainbowPopup = rawPopupC === 'RAINBOW';
                        const popupC = isRainbowPopup ? 'var(--g9)' : rawPopupC;
                        const c = popupC;

                        let modHtml = '';
                        if(item.pill_base_exp) modHtml += `<div class="item-popup-mod">💠 EXP cơ bản: ${item.pill_base_exp}</div>`;
                        if(item.artifact_exp_mod) modHtml += `<div class="item-popup-mod">⚡ Tăng tốc độ tu luyện: ×${item.artifact_exp_mod}</div>`;
                        if(item.accessory_exp_mod && item.accessory_exp_mod > 1) modHtml += `<div class="item-popup-mod">✨ Tăng tốc độ tu luyện: ×${item.accessory_exp_mod}</div>`;

                        const herbC = isHerb ? GRADE_COLOR.herb(item.grade) : '#81c784';
                        let ageHtml = item.age_years ? `<span style="margin-left:8px; color:${herbC}; font-size:0.95em; font-family:'JetBrains Mono', monospace;">🌱 ${item.age_years.toLocaleString()} năm</span>` : '';

                        const gradeBadgeHtml = `<span class="grade-badge" style="color:${popupC};border-color:${popupC}40;background:${popupC}15">${item.grade||'?'}</span>`;
                        popup.innerHTML = `
                            <div class="item-popup-name" style="color:${popupC}">${item.name||'?'}</div>
                            <div class="item-popup-grade" style="display:flex; align-items:center; margin-bottom:6px;">
                                ${gradeBadgeHtml} ${ageHtml}
                            </div>
                            ${modHtml}
                            <div class="item-popup-desc">${item.desc||''}</div>
                        `;
                        popup.classList.add('show');
                        popup.style.borderColor = popupC;
                        popup.style.boxShadow = `0 10px 30px rgba(0,0,0,0.9), 0 0 12px ${popupC}55`;
                        popup.style.animation = isRainbowPopup ? 'rainbow-shift 3s linear infinite' : '';

                        const rect = popupTrigger.getBoundingClientRect();
                        popup.style.left = Math.max(10, Math.min(rect.left, window.innerWidth - 260)) + 'px';
                        popup.style.top = Math.max(10, rect.top - popup.offsetHeight - 10) + 'px';
                    }
                    e.stopPropagation();
                    return;
                }

                // Click ra ngoài đóng Item Popup
                const globalPopup = document.getElementById('st-mvu-global-popup');
                if (globalPopup && globalPopup.classList.contains('show')) {
                    globalPopup.classList.remove('show');
                }
            });
            uiRoot.dataset.eventsBound = "true"; // Đánh dấu đã gắn sự kiện để không gắn trùng lặp
        }

        // Gắn ảnh Tiên Tử lúc khởi tạo
        const fa = uiRoot.querySelector('.fairy-avatar');
        if(fa) fa.style.backgroundImage = `url('https://i.postimg.cc/rpz2PCrZ/Image-1765540443504.jpg')`;

        // Khởi chạy Render
        setTimeout(() => {
            if(typeof window.Mvu !== 'undefined') renderUI();
            if(typeof eventOn === 'function' && typeof Mvu !== 'undefined') {
                eventOn(Mvu.events.VARIABLE_UPDATE_ENDED, renderUI);
            }
        }, 100);
    })();
    </script>
</body>
