scripts.content:
import { registerMvuSchema } from 'https://testingcf.jsdelivr.net/gh/StageDog/tavern_resource/dist/util/mvu_zod.js';

// --- HELPER ---
const z = window.z || window.Zod?.z;
const ValueWithMax = z.union([
  z.object({ 'current': z.coerce.number(), 'max': z.coerce.number() }),
  z.string().regex(/^\d+\s*\/\s*\d+$/)
]).transform((val) => {
  if (typeof val === 'string') {
    const [curr, max] = val.split('/').map(s => Number(s.trim()));
    return { 'current': curr, 'max': max };
  }
  return val;
});

// Nullable object: null hoặc object trang bị
const EquipItemSchema = z.union([
  z.null(),
  z.object({
    name: z.string(),
    grade: z.string().prefault(''),
    desc: z.string().prefault(''),
    artifact_exp_mod: z.coerce.number().optional(),
    accessory_exp_mod: z.coerce.number().optional(),
  })
]).prefault(null);

// --- SCHEMAS ---

const CultivatorSchema = z.object({
  identity: z.object({
    name: z.string().prefault('{{user}}'),
    taoist_name: z.string().prefault('Vô Danh'),
    race: z.string().prefault('Nhân Tộc'),
    gender: z.string().prefault('Nam'),
    age: z.coerce.number().prefault(16),
    lifespan: z.coerce.number().prefault(100),
    alignment: z.string().prefault('Trung Lập'),
  }),
  roots: z.object({
    spirit_root: z.string().prefault('Chưa xác định'),
    spirit_root_grade: z.string().prefault('Chưa xác định'),
    physique: z.string().prefault('Phàm Thể'),
    physique_grade: z.string().prefault('Phàm'),
    fortune: z.string().prefault(''),
  }),
  realm: z.object({
    major: z.string().prefault('Chưa xác định'),
    stage: z.string().prefault('Sơ Kỳ'),
    tier: z.coerce.number().prefault(1),
    exp: ValueWithMax.prefault({ current: 0, max: 100 }),
    breakthrough_chance: z.coerce.number().prefault(0),
    bottleneck: z.boolean().prefault(false),
  }),
  stats: z.object({
    hp: ValueWithMax.prefault({ current: 100, max: 100 }),
    mp: ValueWithMax.prefault({ current: 50, max: 50 }),
    blood: ValueWithMax.prefault({ current: 10, max: 10 }),
    san: ValueWithMax.prefault({ current: 100, max: 100 }),
    san_status: z.string().prefault('Bình thường'),
    luck_status: z.string().prefault('Bình thường'),
    status_effects: z.array(z.string()).prefault([]),
  }),
});

const InventorySchema = z.object({
  spirit_stones: z.coerce.number().prefault(0),
  sect_points: z.coerce.number().prefault(0),
  capacity: z.object({
    pills: z.coerce.number().prefault(50),
    herbs: z.coerce.number().prefault(50),
    manuals: z.coerce.number().prefault(20),
    misc: z.coerce.number().prefault(30),
  }).prefault({ pills: 50, herbs: 50, manuals: 20, misc: 30 }),
  pills: z.array(z.object({
    name: z.string(),
    grade: z.string().prefault(''),
    quantity: z.coerce.number().prefault(1),
    pill_base_exp: z.coerce.number().prefault(0),
    desc: z.string().prefault(''),
  })).prefault([]),
  herbs: z.array(z.object({
    name: z.string(),
    grade: z.string().prefault(''),
    quantity: z.coerce.number().prefault(1),
    age_years: z.coerce.number().prefault(0),
    desc: z.string().prefault(''),
  })).prefault([]),
  manuals: z.array(z.object({
    name: z.string(),
    type: z.string().prefault(''),
    grade: z.string().prefault(''),
    desc: z.string().prefault(''),
  })).prefault([]),
  misc: z.array(z.object({
    name: z.string(),
    type: z.string().prefault('Tạp Vật'),
    grade: z.string().prefault(''),
    quantity: z.coerce.number().prefault(1),
    desc: z.string().prefault(''),
  })).prefault([]),
  equipped: z.object({
    weapon: EquipItemSchema,
    armor: EquipItemSchema,
    artifact: EquipItemSchema,
    accessories: z.array(z.object({
      name: z.string(),
      grade: z.string().prefault(''),
      accessory_exp_mod: z.coerce.number().prefault(1.0),
      desc: z.string().prefault(''),
    })).prefault([]),
  }).prefault({ weapon: null, armor: null, artifact: null, accessories: [] }),
});

const CultivationMethodSchema = z.object({
  name: z.string(),
  type: z.string().prefault('Chủ Tu'),
  grade: z.string().prefault('Phàm cấp'),
  level: z.coerce.number().prefault(1),
  mastery: z.coerce.number().prefault(0),
  desc: z.string().prefault(''),
});

const DivineArtSchema = z.object({
  name: z.string(),
  grade: z.string().prefault('Phàm cấp'),
  mastery: z.coerce.number().prefault(0),
  desc: z.string().prefault(''),
});

const MagicArtSchema = z.object({
  name: z.string(),
  grade: z.string().prefault('Phàm cấp'),
  mastery: z.coerce.number().prefault(0),
  desc: z.string().prefault(''),
});

const GiftSchema = z.object({
  name: z.string(),
  desc: z.string().prefault(''),
});

const BeautySchema = z.object({
  rank: z.coerce.number().prefault(1),
  name: z.string(),
  title: z.string().prefault(''),
  appearance: z.string().prefault(''),
  rumor: z.string().prefault(''),
});

const WorldEventSchema = z.object({
  type: z.string().prefault('Sự kiện'),
  title: z.string(),
  location: z.string().prefault(''),
  desc: z.string().prefault(''),
});

const MessageSchema = z.object({
  sender: z.string(),
  time: z.string().prefault(''),
  content: z.string().prefault(''),
});

const PartnerSchema = z.object({
  name: z.string(),
  species: z.string().prefault('Nhân Tộc'),
  realm: z.string().prefault('Chưa xác định'),
  identity: z.string().prefault('Thân phận không rõ'),
  loyalty: z.coerce.number().prefault(0),
  hp: z.coerce.number().prefault(100),
  mp: z.coerce.number().prefault(100),
  personality: z.string().prefault(''),
  appearance: z.string().prefault(''),
  relation_desc: z.string().prefault(''),
  abilities: z.union([z.string(), z.array(z.string())]).prefault(''),
  thoughts: z.string().prefault(''),
});

const NpcSchema = z.object({
  name: z.string(),
  title: z.string().prefault(''),
  realm: z.string().prefault('?'),
  relation: z.coerce.number().prefault(0),
  hp: z.coerce.number().prefault(100),
  mp: z.coerce.number().prefault(100),
  personality: z.string().prefault(''),
  desc: z.string().prefault(''),
});

const QuestSchema = z.object({
  title: z.string(),
  difficulty: z.string().prefault('Dễ'),
  goal: z.string().prefault(''),
  reward: z.string().prefault(''),
  quote: z.string().prefault(''),
  status: z.string().prefault('Đang làm'),
});

const WorldSchema = z.object({
  location: z.object({
    realm: z.string().prefault('Huyền Thiên Giới'),
    region: z.string().prefault('Chưa xác định'),
    specific: z.string().prefault('Chưa xác định'),
  }),
  time: z.object({
    year: z.coerce.number().prefault(1),
    month: z.coerce.number().prefault(1),
    day: z.coerce.number().prefault(1),
    cycle: z.string().prefault('Ban ngày'),
  }),
  environment: z.object({
    qi_density: z.string().prefault('Trung bình'),
    threat_level: z.string().prefault('An toàn'),
  }),
});

const SystemSchema = z.object({
  quest_log: z.object({
    current_quest: z.string().prefault('Chưa xác định'),
    side_quests: z.array(QuestSchema).prefault([]),
    history_log: z.array(z.string()).prefault([]),
  }),
  fairy_message: z.string().prefault('Đạo hữu cẩn trọng...'),
  mode: z.string().prefault('Thường'),
  initialized: z.boolean().prefault(false),
});

export const Schema = z.object({
  'cultivator': CultivatorSchema,
  'inventory': InventorySchema,
  'cultivation_methods': z.array(CultivationMethodSchema).prefault([]),
  'divine_arts': z.array(DivineArtSchema).prefault([]),
  'magic_arts': z.array(MagicArtSchema).prefault([]),
  'gifts': z.array(GiftSchema).prefault([]),
  'partners': z.array(PartnerSchema).prefault([]),
  'npcs': z.array(NpcSchema).prefault([]),
  'relationships': z.object({
     current_sect: z.string().prefault('Tán Tu'),
     sect_rank: z.string().prefault('Không'),
     enemies: z.array(z.any()).prefault([]),
  }),
  'world': WorldSchema,
  'system': SystemSchema,
  'beauties': z.array(BeautySchema).prefault([]),
  'world_events': z.array(WorldEventSchema).prefault([]),
  'messages': z.array(MessageSchema).prefault([]),
});

$(() => {
  registerMvuSchema(Schema);
});

